 *
 * Uses the AI SDK (`@ai-sdk/react`) with the `/chat` endpoint.
 *
 * IMPORTANT: `useChat` requires a real `Chat` instance — it crashes if passed undefined.
 * Always guard with a conditional render so `useChat` is only called after `chat` is created.
 *
 * @example
 * ```typescript
 * import { useChat } from '@ai-sdk/react';
 * import { createConversation, createAgentChat } from '@/lib/agent-chat/v2';
 * import { useState } from 'react';
 * import { ulid } from 'ulidx';
 *
 * function ChatComponent() {
 *   const [chat, setChat] = useState<ReturnType<typeof createAgentChat> | null>(null);
 *
 *   const handleStartChat = async () => {
 *     const { conversationId } = await createConversation(agentId);
 *     setChat(createAgentChat(agentId, conversationId));
 *   };
 *
 *   if (!chat) return <button onClick={handleStartChat}>Start Chat</button>;
 *   return <ActiveChat chat={chat} />;
 * }
 *
 * function ActiveChat({ chat }: { chat: ReturnType<typeof createAgentChat> }) {
 *   const { messages, status } = useChat({ chat, id: chat.id });
 *
 *   const handleSend = async (text: string) => {
 *     await chat.sendMessage({
 *       id: ulid(),
 *       role: 'user',
 *       parts: [{ type: 'text', text }],
 *     });
 *   };
 *
 *   return (
 *     <div>
 *       {messages.map(msg => (
 *         <div key={msg.id}>
 *           {msg.role === 'user' ? 'You: ' : 'Agent: '}
 *           {msg.parts.filter(p => p.type === 'text').map(p => p.text).join('')}
 *         </div>
 *       ))}
 *       <button onClick={() => handleSend('Hello!')}>Send</button>
 *     </div>
 *   );
 * }
 * ```
 */

export type { ClientOptions, CreateConversationResponse } from './client';
export { createConversation } from './client';
export { createAgentChat } from './createAgentChat';

# Agent Chat SDK v2

SDK for building AI Agent Chat interfaces in Taskade Genesis apps.
Built on the AI SDK (`@ai-sdk/react`), using the `/chat` endpoint.

## Quick Start

```typescript
import { useChat } from '@ai-sdk/react';
import { createConversation, createAgentChat } from '@/lib/agent-chat/v2';
import { isToolUIPart } from 'ai';
import type { UIMessage } from 'ai';
import { useState } from 'react';
import { ulid } from 'ulidx';

// IMPORTANT: useChat requires a real Chat instance — it crashes if passed undefined.
// Split into two components so useChat is only called after chat is created.

function ChatComponent() {
  const [chat, setChat] = useState<ReturnType<typeof createAgentChat> | null>(null);

  const handleStartChat = async () => {
    const { conversationId } = await createConversation(agentId);
    setChat(createAgentChat(agentId, conversationId));
  };

  if (!chat) return <button onClick={handleStartChat}>Start Chat</button>;
  return <ActiveChat chat={chat} />;
}

function ActiveChat({ chat }: { chat: ReturnType<typeof createAgentChat> }) {
  const { messages, status, addToolApprovalResponse } = useChat({ chat, id: chat.id });
  const isSending = status === 'submitted' || status === 'streaming';

  const handleSend = async (text: string) => {
    await chat.sendMessage({
      id: ulid(),
      role: 'user',
      parts: [{ type: 'text', text }],
    });
  };

  return (
    <div>
      {messages.map(msg => (
        <div key={msg.id}>
          <strong>{msg.role === 'user' ? 'You' : 'Agent'}:</strong>
          {msg.parts.map((part, i) => {
            // Always render all part types — the agent may use tools even if none
            // are configured yet. Omitting this causes tool calls to be silently dropped.
            if (part.type === 'text') {
              return <span key={i}>{part.text}</span>;
            }
            if (isToolUIPart(part)) {
              return (
                <div key={i}>
                  <em>Tool: {part.toolName} [{part.state}]</em>
                  {part.state === 'approval-requested' && part.approval != null && (
                    <>
                      <button onClick={() => addToolApprovalResponse({ id: part.approval.id, approved: true })}>
                        Approve
                      </button>
                      <button onClick={() => addToolApprovalResponse({ id: part.approval.id, approved: false })}>
                        Deny
                      </button>
                    </>
                  )}
                </div>
              );
            }
            return null;
          })}
        </div>
      ))}
      <button onClick={() => handleSend('Hello!')} disabled={isSending}>Send</button>
    </div>
  );
}
```

## Pre-built AI Elements UI (`@/components/ai-elements/`)

Pre-built, styled React components for chat interfaces are available via AI Elements.
Use these instead of building chat UI from scratch:

| Component | Import | Purpose |
|-----------|--------|---------|
| `Conversation` | `@/components/ai-elements/conversation` | Scrollable chat container with auto-stick-to-bottom |
| `Message` | `@/components/ai-elements/message` | Message bubble with role-based styling + markdown |
| `PromptInput` | `@/components/ai-elements/prompt-input` | Chat input form with file attachments + submit |
| `Suggestion` | `@/components/ai-elements/suggestion` | Quick-reply suggestion pills |
| `Reasoning` | `@/components/ai-elements/reasoning` | Collapsible thinking/reasoning display |
| `CodeBlock` | `@/components/ai-elements/code-block` | Syntax-highlighted code with copy button |
| `Tool` | `@/components/ai-elements/tool` | Collapsible tool call display with status |
| `Confirmation` | `@/components/ai-elements/confirmation` | Tool call approval UI with approve/reject slots |
| `Shimmer` | `@/components/ai-elements/shimmer` | Animated shimmer text — usage: `<Shimmer>Loading...</Shimmer>` (children must be a string) |

See `@/components/ai-elements` for the full list of available components that you may use to build your chat UI.


### Full Example with AI Elements

```typescript
import { useChat } from '@ai-sdk/react';
import { createConversation, createAgentChat } from '@/lib/agent-chat/v2';
import { Conversation, ConversationContent, ConversationScrollButton } from '@/components/ai-elements/conversation';
import { Message, MessageContent, MessageResponse } from '@/components/ai-elements/message';
import { Tool, ToolHeader, ToolContent, ToolInput, ToolOutput } from '@/components/ai-elements/tool';
import {
  Confirmation,
  ConfirmationTitle,
  ConfirmationRequest,
  ConfirmationAccepted,
  ConfirmationRejected,
  ConfirmationActions,
  ConfirmationAction,
} from '@/components/ai-elements/confirmation';
import { PromptInput, PromptInputTextarea, PromptInputFooter, PromptInputSubmit } from '@/components/ai-elements/prompt-input';
import { Suggestions, Suggestion } from '@/components/ai-elements/suggestion';
import { isToolUIPart } from 'ai';
import type { UIMessage } from 'ai';
import { useState } from 'react';
import { ulid } from 'ulidx';

function ChatPage() {
  const [chat, setChat] = useState<ReturnType<typeof createAgentChat> | null>(null);

  const handleStartChat = async () => {
    const { conversationId } = await createConversation(agentId);
    setChat(createAgentChat(agentId, conversationId));
  };

  if (!chat) return <button onClick={handleStartChat}>Start Chat</button>;
  return <ActiveChat chat={chat} />;
}

function ActiveChat({ chat }: { chat: ReturnType<typeof createAgentChat> }) {
  const { messages, status, addToolApprovalResponse } = useChat({ chat, id: chat.id });

  const handleSend = async (text: string) => {
    await chat.sendMessage({
      id: ulid(),
      role: 'user',
      parts: [{ type: 'text', text }],
    });
  };

  const hasMessages = messages.length > 0;

  return (
    <div className="flex h-screen flex-col">
      <Conversation>
        <ConversationContent>
          {messages.map((msg) => (
            <Message key={msg.id} from={msg.role}>
              <MessageContent>
                <MessageParts message={msg} onApprove={addToolApprovalResponse} />
              </MessageContent>
            </Message>
          ))}
        </ConversationContent>
        <ConversationScrollButton />
      </Conversation>

      {!hasMessages && (
        <Suggestions>
          <Suggestion suggestion="What can you help me with?" onClick={handleSend} />
          <Suggestion suggestion="Tell me about this app" onClick={handleSend} />
        </Suggestions>
      )}

      <PromptInput onSubmit={({ text }) => handleSend(text)}>
        <PromptInputTextarea />
        <PromptInputFooter>
          <PromptInputSubmit status={status} />
        </PromptInputFooter>
      </PromptInput>
    </div>
  );
}

// Always handle all part types — the agent may call tools even if none are configured
// yet. Omitting isToolUIPart handling causes tool calls to be silently dropped.
function MessageParts({
  message,
  onApprove,
}: {
  message: UIMessage;
  onApprove: ReturnType<typeof useChat>['addToolApprovalResponse'];
}) {
  return (
    <>
      {message.parts.map((part, i) => {
        const key = `${message.id}-${i}`;

        if (part.type === 'text') {
          return message.role === 'user' ? (
            <p key={key}>{part.text}</p>
          ) : (
            <MessageResponse key={key}>{part.text}</MessageResponse>
          );
        }

        if (isToolUIPart(part)) {
          return (
            <Tool key={key}>
              <ToolHeader type={part.type} state={part.state} />
              <ToolContent>
                <ToolInput input={part.input} />
                <Confirmation approval={part.approval} state={part.state}>
                  <ConfirmationRequest>
                    <ConfirmationTitle>Allow this tool to run?</ConfirmationTitle>
                  </ConfirmationRequest>
                  <ConfirmationAccepted>Approved</ConfirmationAccepted>
                  <ConfirmationRejected>Rejected</ConfirmationRejected>
                  <ConfirmationActions>
                    <ConfirmationAction
                      variant="outline"
                      onClick={() =>
                        part.approval != null && onApprove({ id: part.approval.id, approved: false })
                      }
                    >
                      Deny
                    </ConfirmationAction>
                    <ConfirmationAction
                      onClick={() =>
                        part.approval != null && onApprove({ id: part.approval.id, approved: true })
                      }
                    >
                      Approve
                    </ConfirmationAction>
                  </ConfirmationActions>
                </Confirmation>
                <ToolOutput output={part.output} errorText={part.errorText} />
              </ToolContent>
            </Tool>
          );
        }

        return null;
      })}
    </>
  );
}
```

## Tool Call Approval

Both examples above already include full approval handling — it is part of the standard
`MessageParts` pattern and should always be present, even if the agent has no tools
configured today. Tool call parts will simply never appear in that case; the code is inert.

The approval flow is managed by two pieces:

- **`Confirmation` + sub-components** (`@/components/ai-elements/confirmation`) — conditional
  rendering driven by `part.state` and `part.approval`. No handler logic lives inside them.
- **`addToolApprovalResponse`** (from `useChat`) — call with `{ id: part.approval.id, approved }`.
  The `id` must be the tool part’s **`approval.id`**, not `toolCallId`; wrong `id` updates nothing.
  `createAgentChat` then automatically sends the next request to the server.

### Approval state lifecycle

| State | What's visible |
|---|---|
| `approval-requested` | `<ConfirmationRequest>` + `<ConfirmationActions>` (approve/deny buttons) |
| `approval-responded` | `<ConfirmationAccepted>` or `<ConfirmationRejected>` based on decision |
| `output-available` | Tool completed — `<ToolOutput>` shows result |
| `output-denied` | Tool was denied — `<ConfirmationRejected>` stays visible |

Once `addToolApprovalResponse` is called, `createAgentChat` automatically sends the next
request to the server — no manual trigger required.

## API

**`createConversation(agentId, options?)`**
Creates a new public conversation. Returns `{ ok, conversationId }`.

**`createAgentChat(agentId, conversationId, options?)`**
Creates a `Chat` instance configured for the agent. Use with `useChat` from `@ai-sdk/react`.

**`useChat({ chat, id })`** (from `@ai-sdk/react`)
Standard AI SDK hook. Returns `{ messages, status, error, addToolApprovalResponse }`.

**`addToolApprovalResponse({ id, approved, reason? })`** (from `useChat`)
Submits an approve (`true`) or deny (`false`) decision. **`id` is `toolUIPart.approval.id`**, not `toolCallId`.
The conversation automatically resumes after the response is submitted.

## Sending Messages

```typescript
import { ulid } from 'ulidx';

await chat.sendMessage({
  id: ulid(),
  role: 'user',
  parts: [{ type: 'text', text: 'Hello!' }],
});
```

## Message Format

Messages use the AI SDK `UIMessage` type:

```typescript
import { isToolUIPart } from 'ai';

msg.parts.filter(p => p.type === 'text').map(p => p.text)   // Text
msg.parts.filter(isToolUIPart)                               // Tool calls
```

## Requirements

- Agent must have **public visibility** enabled before creating a conversation
- `useChat` must receive a real `Chat` instance, never `undefined`

/**
 * API Response types
 */
export interface CreateConversationResponse {
  ok: boolean;
  conversationId: string;
}

/**
 * Configuration for API client
 */
export interface ClientOptions {
  /** Base URL for API requests (defaults to relative paths) */
  baseUrl?: string;
}

function isEmptyString(value: string | null | undefined): boolean {
  return value == null || value.trim().length === 0;
}

/**
 * Creates a new public agent conversation
 *
 * @param agentId - The agent ID
 * @param options - Optional client configuration
 * @returns Promise resolving to conversation ID
 * @throws Error if conversation creation fails
 *
 * @example
 * ```typescript
 * const { conversationId } = await createConversation('agent-456');
 * ```
 */
export async function createConversation(
  agentId: string,
  options?: ClientOptions,
): Promise<CreateConversationResponse> {
  if (isEmptyString(agentId)) {
    throw new Error('Agent ID cannot be empty');
  }

  const baseUrl = options?.baseUrl ?? '';
  const url = `${baseUrl}/api/taskade/agents/${encodeURIComponent(agentId)}/public-conversations`;

  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
  });

  const contentType = response.headers.get('content-type') || '';
  const responseText = await response.text().catch(() => '');

  if (!response.ok) {
    throw new Error(
      `Failed to create conversation: ${response.status} ${responseText || 'Unknown error'}`,
    );
  }

  if (!contentType.includes('application/json')) {
    throw new Error(
      `Invalid response format: expected JSON, got ${contentType}. Response: ${responseText.substring(0, 100)}`,
    );
  }

  try {
    const data = JSON.parse(responseText);
    return data as CreateConversationResponse;
  } catch (err) {
    throw new Error(
      `Failed to parse JSON response: ${err instanceof Error ? err.message : 'Unknown error'}. Response: ${responseText.substring(0, 200)}`,
    );
  }
}

import { Chat } from '@ai-sdk/react';
import {
  DefaultChatTransport,
  lastAssistantMessageIsCompleteWithApprovalResponses,
  lastAssistantMessageIsCompleteWithToolCalls,
  UIMessage,
  isToolUIPart,
} from 'ai';
import { ulid } from 'ulidx';

import type { ClientOptions } from './client';

export type ExtractInputMessagesResult = {
  history: UIMessage[];
  messages: UIMessage[];
};

/**
 * Strips text parts with empty content from a message's parts array.
 * The API rejects messages where any text content block is an empty string.
 */
function sanitizeMessage(message: UIMessage): UIMessage {
  if (!Array.isArray(message.parts)) return message;
  const sanitizedParts = message.parts.map((part) => {
    if (part.type === 'text' && typeof part.text === 'string' && part.text.trim() === '') {
      return { ...part, text: ' ' }; // replace empty with a single space — never an empty string
    }
    return part;
  });
  return { ...message, parts: sanitizedParts };
}

/**
 * Generic version of the TAA helper:
 * - Separates "history" from the latest actionable message(s) to send to the server.
 * - Handles agentic tool-call loops where the last assistant message contains tool parts.
 */
function extractInputMessages(messages: UIMessage[]): ExtractInputMessagesResult {
  if (messages.length === 0) {
    return { history: messages, messages: [] };
  }

  const lastMessageIndex = messages.length - 1;
  const lastMessage = messages[lastMessageIndex];
  if (lastMessage == null) {
    return { history: messages, messages: [] };
  }

  if (lastMessage.role === 'user') {
    const history = messages.slice(0, lastMessageIndex);
    return { history, messages: [lastMessage] };
  }

  if (lastMessage.role === 'assistant') {
    const parts = lastMessage.parts;
    if (parts != null && parts.length > 0) {
      const lastPart = parts[parts.length - 1];
      if (lastPart != null && isToolUIPart(lastPart)) {
        if (lastPart.state === 'output-available' || lastPart.state === 'output-error') {
          const history = messages.slice(0, lastMessageIndex);
          return { history, messages: [lastMessage] };
        }
      }
    }
  }

  const history = messages.slice(0, lastMessageIndex);
  return { history, messages: [lastMessage] };
}

const MAX_HISTORY_MESSAGES = 6;

/**
 * Creates a Chat instance configured for a Taskade agent public conversation.
 *
 * Use with `useChat` from `@ai-sdk/react` to build chat interfaces.
 *
 * IMPORTANT: `useChat` requires a real `Chat` instance — it crashes if passed undefined.
 * Always guard with a conditional render so `useChat` is only called after `chat` is created.
 *
 * @param agentId - The agent ID
 * @param conversationId - The conversation ID (from createConversation)
 * @param options - Optional client configuration
 * @returns A Chat instance ready to use with useChat
 *
 * Tool approval: `useChat`'s `addToolApprovalResponse` expects `{ id, approved }` where `id` is
 * `toolUIPart.approval.id` — **not** `toolCallId`. Passing `toolCallId` will not update any part.
 *
 * @example
 * ```typescript
 * import { useChat } from '@ai-sdk/react';
 * import { createConversation, createAgentChat } from '@/lib/agent-chat/v2';
 *
 * function ChatComponent() {
 *   const [chat, setChat] = useState<ReturnType<typeof createAgentChat> | null>(null);
 *
 *   const handleStartChat = async () => {
 *     const { conversationId } = await createConversation(agentId);
 *     setChat(createAgentChat(agentId, conversationId));
 *   };
 *
 *   if (!chat) return <button onClick={handleStartChat}>Start Chat</button>;
 *   return <ActiveChat chat={chat} />;
 * }
 *
 * function ActiveChat({ chat }: { chat: ReturnType<typeof createAgentChat> }) {
 *   const { messages, status } = useChat({ chat, id: chat.id });
 *   // ...
 * }
 * ```
 */
export function createAgentChat(
  agentId: string,
  conversationId: string,
  options?: ClientOptions,
): Chat<UIMessage> {
  const baseUrl = options?.baseUrl ?? '';
  const api = `${baseUrl}/api/taskade/agents/${encodeURIComponent(agentId)}/public-conversations/${encodeURIComponent(conversationId)}/chat`;

  const chatState = new Chat<UIMessage>({
    messages: [],
    transport: new DefaultChatTransport({
      api,
      prepareSendMessagesRequest: (opts) => {
        const { history, messages } = extractInputMessages(opts.messages);

        const maxHistory = Math.max(0, MAX_HISTORY_MESSAGES - messages.length);
        const trimmedHistory = maxHistory === 0 ? [] : history.slice(-maxHistory);

        return {
          body: {
            messages: messages.map(sanitizeMessage),
            history: trimmedHistory.map(sanitizeMessage),
          },
        };
      },
    }),
    id: conversationId,
    generateId: ulid,
    sendAutomaticallyWhen: (options) => {
      const shouldSendAutomatically =
        lastAssistantMessageIsCompleteWithToolCalls(options) ||
        lastAssistantMessageIsCompleteWithApprovalResponses(options);
      if (!shouldSendAutomatically) {
        return false;
      }
      if (chatState.error != null) {
        return false;
      }
      return true;
    },
  });

  return chatState;
}

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import {
  type ClientOptions,
  createConversation as createConversationApi,
  sendMessage as sendMessageApi,
} from './client';
import { AgentChatStream } from './stream';
import type { ErrorEvent, MessageState, StreamOptions } from './types';

/**
 * Options for useAgentChat hook
 */
export interface UseAgentChatOptions extends StreamOptions {
  /** Auto-connect stream on mount (default: true) */
  autoConnect?: boolean;
}

/**
 * Return type for useAgentChat hook
 */
export interface UseAgentChatReturn {
  /** Send a message to the conversation */
  sendMessage: (text: string) => Promise<void>;
  /** Array of messages (sorted by creation order) */
  messages: MessageState[];
  /** Whether stream is currently connected */
  isConnected: boolean;
  /** Current error, if any */
  error: Error | null;
  /** Current conversation ID */
  conversationId: string | null;
  /** Create a new conversation (stream stays open, switches to new conversation) */
  createConversation: () => Promise<string>;
  /** Switch to a different conversation (stream stays open) */
  switchConversation: (conversationId: string) => void;
  /** Manually connect the stream (useful when autoConnect is false) */
  connect: () => void;
}

/**
 * React hook for managing agent chat conversation
 *
 * Requires a conversationId to be provided. The stream is opened when conversationId is available
 * and stays open throughout the conversation lifecycle.
 *
 * @param agentId - The agent ID
 * @param conversationId - The conversation ID (required - must be created manually)
 * @param options - Configuration options
 * @returns Chat state and methods
 *
 * @example
 * ```typescript
 * function ChatComponent() {
 *   const [conversationId, setConversationId] = useState<string | null>(null);
 *   const { sendMessage, messages, isConnected } = useAgentChat('agent-456', conversationId);
 *
 *   // Create conversation manually
 *   const handleStartChat = async () => {
 *     const { conversationId: newId } = await createConversation('agent-456');
 *     setConversationId(newId);
 *   };
 *
 *   return (
 *     <div>
 *       {!conversationId && <button onClick={handleStartChat}>Start Chat</button>}
 *       {messages.map(msg => (
 *         <div key={msg.id}>{msg.content}</div>
 *       ))}
 *       <button onClick={() => sendMessage('Hello!')}>Send</button>
 *     </div>
 *   );
 * }
 * ```
 */
export function useAgentChat(
  agentId: string,
  conversationId: string | null,
  options?: UseAgentChatOptions,
): UseAgentChatReturn {
  const [messagesMap, setMessagesMap] = useState<Map<string, MessageState>>(new Map());
  const [isConnected, setIsConnected] = useState(false);
  const [error, setError] = useState<Error | null>(null);
  const [currentConversationId, setCurrentConversationId] = useState<string | null>(conversationId);
  const streamRef = useRef<AgentChatStream | null>(null);
  const listenersRef = useRef<Array<() => void>>([]);
  const streamAgentIdRef = useRef<string | null>(null);
  const currentConversationIdRef = useRef<string | null>(conversationId);
  const previousConversationIdRef = useRef<string | null>(conversationId);

  // Sync currentConversationId with prop when prop changes externally
  // This ensures the hook's internal state stays in sync with external prop updates
  useEffect(() => {
    const previousId = previousConversationIdRef.current;
    const newId = conversationId;

    // Clear messages when conversationId changes to a different non-null value
    // This handles the case where the prop changes externally (not via createConversation/switchConversation)
    if (previousId !== newId && newId != null && previousId != null) {
      setMessagesMap(new Map());
      // Also clear stream's message states if stream exists
      if (streamRef.current) {
        streamRef.current.clearMessages();
      }
    }

    setCurrentConversationId(newId);
    currentConversationIdRef.current = newId;
    previousConversationIdRef.current = newId;
  }, [conversationId]);

  // Cleanup on component unmount
  useEffect(() => {
    return () => {
      if (streamRef.current) {
        streamRef.current.disconnect();
        streamRef.current = null;
        streamAgentIdRef.current = null;
      }
    };
  }, []);

  // Convert messages map to sorted array
  const messages = useMemo(() => {
    const allMessages = Array.from(messagesMap.values());
    // Sort by message ID (ULID) - ULIDs are lexicographically sortable and encode timestamp
    // This ensures chronological order regardless of message role
    allMessages.sort((a, b) => {
      return a.id.localeCompare(b.id);
    });
    return allMessages;
  }, [messagesMap]);

  // Initialize stream when conversationId is available
  // Uses currentConversationId to ensure we're working with the latest state
  // (which may have been updated by createConversation/switchConversation)
  useEffect(() => {
    // Don't initialize if no conversationId
    if (!currentConversationId) {
      // Clean up existing stream if conversationId is removed
      if (streamRef.current) {
        streamRef.current.clearMessages(); // Clear stream's message states
        streamRef.current.disconnect();
        streamRef.current = null;
        streamAgentIdRef.current = null;
        setIsConnected(false);
      }
      // Clear messages when conversation is removed
      setMessagesMap(new Map());
      currentConversationIdRef.current = null;
      return;
    }

    // Update ref to track current conversation ID
    currentConversationIdRef.current = currentConversationId;

    // Clean up previous listeners before setting up new ones
    // This ensures we don't accumulate duplicate listeners when reusing the stream
    listenersRef.current.forEach((unsub) => unsub());
    listenersRef.current = [];

    const unsubscribeFunctions: Array<() => void> = [];
    let isMounted = true;

    // Register cleanup function first to ensure it's available immediately
    // This prevents race conditions where component unmounts before cleanup is registered
    const cleanup = () => {
      isMounted = false;
      unsubscribeFunctions.forEach((unsub) => unsub());
      // Note: We don't disconnect the stream here because:
      // 1. The stream may be reused in the next effect run (when switching conversations)
      // 2. Disconnection is handled when conversationId becomes null (early return above)
      // 3. On component unmount, React will call cleanup, but the stream will be garbage collected
      //    when the ref is cleared by the early return path if conversationId becomes null
    };

    try {
      // Ensure we have valid agentId before creating stream
      // Note: currentConversationId is already validated above (early return if falsy)
      if (!agentId) {
        throw new Error(`Invalid parameters: agentId is required`);
      }

      // Helper function to update messages from stream state
      // Defined inline here since it only uses refs and setState (both stable)
      const updateMessages = () => {
        const currentStream = streamRef.current;
        if (currentStream) {
          setMessagesMap((prev) => {
            const next = new Map(prev);
            // Add/update stream messages (assistant responses)
            for (const [id, streamMsg] of currentStream.messages) {
              // Only update if this is an assistant message (or doesn't exist yet)
              // Preserve user messages - they should never be overwritten by stream
              const existing = prev.get(id);
              if (!existing || existing.role === 'assistant') {
                // Merge with existing to preserve content if stream message is missing it
                // Stream message should have latest content, but fallback to existing as safety
                const mergedMsg: MessageState = {
                  ...existing,
                  ...streamMsg,
                  id, // Ensure ID is preserved
                  role: 'assistant' as const,
                  // Prefer stream message content if it exists and is non-empty, otherwise preserve existing
                  content:
                    typeof streamMsg.content === 'string' && streamMsg.content.length > 0
                      ? streamMsg.content
                      : existing?.content || '',
                };
                next.set(id, mergedMsg);
              }
            }
            return next;
          });
        }
      };

      let stream: AgentChatStream;

      // Check if we need to recreate the stream (agentId changed or stream doesn't exist)
      const existingStream = streamRef.current;
      const agentIdChanged = existingStream && streamAgentIdRef.current !== agentId;

      if (agentIdChanged && existingStream) {
        // AgentId changed - preserve messages from old stream before disconnecting
        // The hook's messagesMap should already have all messages, but we ensure
        // any messages in the stream's state are preserved in the hook's state
        setMessagesMap((prev) => {
          const next = new Map(prev);
          // Preserve any messages from the old stream that aren't already in the map
          for (const [id, streamMsg] of existingStream.messages) {
            if (!next.has(id)) {
              next.set(id, streamMsg);
            } else {
              // If message exists, preserve user messages and merge assistant messages
              const existing = prev.get(id);
              if (existing?.role === 'user') {
                // Keep user message as-is
                continue;
              }
              // Merge assistant messages
              if (existing?.role === 'assistant' || !existing) {
                next.set(id, {
                  ...existing,
                  ...streamMsg,
                  id,
                  role: 'assistant' as const,
                });
              }
            }
          }
          return next;
        });
        // Now disconnect the old stream
        existingStream.disconnect();
        streamRef.current = null;
        streamAgentIdRef.current = null;
      }

      // If stream exists and agentId hasn't changed, update its conversation ID and reuse it
      // We still need to re-register event listeners to ensure fresh closures
      if (streamRef.current && !agentIdChanged) {
        stream = streamRef.current;
        // Update conversation ID if needed - this handles disconnection/reconnection
        stream.setConversationId(currentConversationId);
      } else {
        // Create new stream
        const streamOptions: StreamOptions = {
          baseUrl: options?.baseUrl,
          autoReconnect: options?.autoReconnect ?? true,
          reconnectDelay: options?.reconnectDelay,
          onError: (err) => {
            if (isMounted) {
              setError(err);
            }
            options?.onError?.(err);
          },
        };
        stream = new AgentChatStream(agentId, currentConversationId, streamOptions);
        streamRef.current = stream;
        streamAgentIdRef.current = agentId;
      }

      // Always set up event listeners to ensure fresh closures
      // Even if stream exists, we need to re-register listeners with current closures
      // (isMounted, updateMessages, etc.)

      // Subscribe to events
      // Note: We always re-register listeners even if stream exists to ensure fresh closures
      const unsubscribeOpen = stream.on('open', () => {
        if (isMounted) {
          setIsConnected(true);
          setError(null);
        }
      });
      unsubscribeFunctions.push(unsubscribeOpen);

      const unsubscribeClose = stream.on('close', () => {
        if (isMounted) {
          setIsConnected(false);
        }
      });
      unsubscribeFunctions.push(unsubscribeClose);

      const unsubscribeTextDelta = stream.on('text-delta', () => {
        if (isMounted) {
          updateMessages();
        }
      });
      unsubscribeFunctions.push(unsubscribeTextDelta);

      const unsubscribeFinish = stream.on('finish', () => {
        if (isMounted) {
          updateMessages();
        }
      });
      unsubscribeFunctions.push(unsubscribeFinish);

      const unsubscribeError = stream.on('error', (event: ErrorEvent) => {
        if (isMounted) {
          setError(new Error(event.errorText));
        }
      });
      unsubscribeFunctions.push(unsubscribeError);

      // Store unsubscribe functions for cleanup on next effect run
      listenersRef.current = unsubscribeFunctions;

      // Connect stream if autoConnect is enabled (default: true)
      if (options?.autoConnect !== false) {
        stream.connect();
      }
    } catch (err) {
      if (isMounted) {
        const initError = err instanceof Error ? err : new Error('Failed to initialize chat');
        setError(initError);
        console.error('[useAgentChat] Initialization error:', initError);
      }
    }

    // Return cleanup function
    return cleanup;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [
    agentId,
    currentConversationId, // Use currentConversationId instead of prop to react to internal updates
    options?.baseUrl,
    options?.autoReconnect,
    options?.reconnectDelay,
    options?.autoConnect,
    options?.onError,
    // Note: updateMessages is defined inline in the effect and only uses refs/setState (stable)
  ]);

  // Send message function
  const sendMessage = useCallback(
    async (text: string) => {
      // Use currentConversationId to ensure we're using the latest state
      const convoId = currentConversationId;
      if (!convoId) {
        throw new Error('No conversation available. Create a conversation first.');
      }

      const clientOptions: ClientOptions = {
        baseUrl: options?.baseUrl,
      };

      try {
        setError(null);
        const response = await sendMessageApi(agentId, convoId, text, clientOptions);

        // Check if conversation is still active before adding message
        // This prevents race condition where conversation switches while API call is pending
        // Use ref to check latest conversation ID (closure value might be stale)
        if (currentConversationIdRef.current !== convoId) {
          // Conversation changed during API call, don't add message (it belongs to old conversation)
          return;
        }

        // Add user message with the messageId from the API response
        const userMessage: MessageState = {
          id: response.messageId,
          content: text,
          isComplete: true,
          role: 'user',
        };
        // Add user message to messages map
        setMessagesMap((prev) => {
          const next = new Map(prev);
          next.set(response.messageId, userMessage);
          return next;
        });
      } catch (err) {
        const sendError = err instanceof Error ? err : new Error('Failed to send message');
        setError(sendError);
        throw sendError;
      }
    },
    [agentId, currentConversationId, options?.baseUrl],
  );

  /**
   * Create a new conversation
   *
   * Creates a new conversation and switches the stream to it. The hook's internal state
   * is updated automatically. If you're managing conversationId as a prop, you should
   * also update it to keep it in sync:
   *
   * @example
   * ```typescript
   * const [conversationId, setConversationId] = useState<string | null>(null);
   * const { createConversation } = useAgentChat(agentId, conversationId);
   *
   * const handleNewChat = async () => {
   *   const newId = await createConversation();
   *   setConversationId(newId); // Update prop to keep it in sync
   * };
   * ```
   *
   * @returns The new conversation ID
   */
  const createConversation = useCallback(async (): Promise<string> => {
    const clientOptions: ClientOptions = {
      baseUrl: options?.baseUrl,
    };
    const { conversationId: newConvoId } = await createConversationApi(agentId, clientOptions);

    // Update internal state first - this will trigger useEffect to reinitialize stream
    setCurrentConversationId(newConvoId);
    currentConversationIdRef.current = newConvoId;
    // Clear messages when switching to new conversation
    setMessagesMap(new Map());

    // If stream exists, update it to the new conversation ID
    // This handles the case where stream was already initialized
    if (streamRef.current) {
      streamRef.current.setConversationId(newConvoId);
    }

    return newConvoId;
  }, [agentId, options?.baseUrl]);

  /**
   * Switch to a different conversation
   *
   * Switches the stream to an existing conversation. The hook's internal state
   * is updated automatically. If you're managing conversationId as a prop, you should
   * also update it to keep it in sync:
   *
   * @example
   * ```typescript
   * const [conversationId, setConversationId] = useState<string | null>(null);
   * const { switchConversation } = useAgentChat(agentId, conversationId);
   *
   * const handleSwitchChat = (existingConvoId: string) => {
   *   switchConversation(existingConvoId);
   *   setConversationId(existingConvoId); // Update prop to keep it in sync
   * };
   * ```
   *
   * @param convoId - The conversation ID to switch to
   */
  const switchConversation = useCallback((convoId: string) => {
    // Update internal state first - this will trigger useEffect to reinitialize stream
    setCurrentConversationId(convoId);
    currentConversationIdRef.current = convoId;
    // Clear messages when switching conversations
    setMessagesMap(new Map());

    // If stream exists, update it to the new conversation ID
    // This handles the case where stream was already initialized
    if (streamRef.current) {
      streamRef.current.setConversationId(convoId);
    }
  }, []);

  /**
   * Manually connect the stream
   *
   * Useful when `autoConnect` is set to `false`. The stream must have a valid
   * conversationId before connecting.
   *
   * @example
   * ```typescript
   * const { connect, conversationId } = useAgentChat(agentId, conversationId, {
   *   autoConnect: false,
   * });
   *
   * // Connect manually after conversation is created
   * const handleStartChat = async () => {
   *   const { conversationId: newId } = await createConversation(agentId);
   *   setConversationId(newId);
   *   // Stream will be initialized but not connected due to autoConnect: false
   *   // Manually connect it
   *   connect();
   * };
   * ```
   */
  const connect = useCallback(() => {
    if (!currentConversationId) {
      throw new Error('Cannot connect: no conversation available. Create a conversation first.');
    }

    if (!streamRef.current) {
      throw new Error('Cannot connect: stream not initialized. Ensure conversationId is provided.');
    }

    streamRef.current.connect();
  }, [currentConversationId]);

  return {
    sendMessage,
    messages,
    isConnected,
    error,
    conversationId: currentConversationId,
    createConversation,
    switchConversation,
    connect,
  };
}

/**
 * Agent Chat SDK for Taskade Genesis (Legacy)
