// ─── Number Line Rail ──────────────────────────────────────────────────────

function NumberRail({ cards, correctOrder, showSolution, tieCardIds }: {
  cards: RecipeCard[];
  correctOrder: string[];
  showSolution: boolean;
  tieCardIds?: string[];
}) {
  const RAIL_MIN = 0;
  const RAIL_MAX = 1;

  const sorted = [...cards].sort((a, b) => a.decimalValue - b.decimalValue);
  const uniqueValues = Array.from(new Set(sorted.map(c => c.decimalValue))).sort((a, b) => a - b);

  // Notch positions
  const notches = [0, 0.25, 0.5, 0.75, 1.0];

  return (
    <div className="relative w-full px-8 py-6">
      {/* Rail background */}
      <div className="relative h-2 bg-white/8 rounded-full border border-white/10 mx-4">
        {/* Gradient fill */}
        <div className="absolute inset-0 rounded-full bg-gradient-to-r from-indigo-500/30 via-purple-500/20 to-pink-500/30" />

        {/* Notch marks */}
        {notches.map(n => (
          <div
            key={n}
            className="absolute top-1/2 -translate-y-1/2 flex flex-col items-center"
            style={{ left: `${n * 100}%`, transform: 'translate(-50%, -50%)' }}
          >
            <div className="w-0.5 h-3 bg-white/20 rounded-full" />
          </div>
        ))}

        {/* Card markers on rail */}
        {showSolution && sorted.map((card, idx) => {
          const pct = ((card.decimalValue - RAIL_MIN) / (RAIL_MAX - RAIL_MIN)) * 100;
          const isTied = tieCardIds?.includes(card.id);
          const mc = REP_META[card.repType];
          // Offset tied cards slightly so both are visible
          const tieOffset = isTied
            ? (tieCardIds!.indexOf(card.id) === 0 ? -14 : 14)
            : 0;

          return (
            <motion.div
              key={card.id}
              initial={{ opacity: 0, y: -20, scale: 0.7 }}
              animate={{ opacity: 1, y: tieOffset, scale: 1 }}
              transition={{ delay: idx * 0.08, type: 'spring', stiffness: 260, damping: 22 }}
              className="absolute top-1/2 -translate-y-1/2 flex flex-col items-center pointer-events-none"
              style={{ left: `${pct}%`, transform: `translate(-50%, calc(-50% + ${tieOffset}px))` }}
            >
              {/* Connector line */}
              <div className={cn('w-0.5 h-3 mb-0.5', isTied ? 'bg-yellow-400/60' : 'bg-white/20')} />
              {/* Card chip */}
              <div className={cn(
                'px-2 py-1 rounded-md border text-[10px] font-bold whitespace-nowrap shadow-lg',
                mc.color,
                isTied && 'ring-1 ring-yellow-400/50'
              )}>
                {card.display}
                {isTied && <span className="ml-1 text-yellow-300 text-[8px]">≈</span>}
              </div>
            </motion.div>
          );
        })}
      </div>

      {/* Notch labels */}
      <div className="flex justify-between px-4 mt-3">
        {notches.map(n => (
          <span key={n} className="text-[9px] text-white/25 font-mono">{n}</span>
        ))}
      </div>
    </div>
  );
}

// ─── Recipe Card ──────────────────────────────────────────────────────────

function CardChip({ card, rank, showSolution, isTied, isCorrect }: {
  card: RecipeCard;
  rank: number;
  showSolution: boolean;
  isTied: boolean;
  isCorrect: boolean;
}) {
  const mc = REP_META[card.repType];

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: rank * 0.05 }}
      className={cn(
        'relative flex flex-col items-center gap-1.5 p-3 rounded-xl border transition-all duration-300 select-none',
        'bg-white/4 hover:bg-white/6',
        isTied && showSolution ? 'border-yellow-400/40 bg-yellow-400/5' : 'border-white/8',
        showSolution && isCorrect ? 'border-indigo-400/40' : '',
      )}
      style={{ minWidth: 80 }}
    >
      {/* Rank badge */}
      {showSolution && (
        <div className="absolute -top-2 -right-2 w-5 h-5 rounded-full bg-indigo-600 text-white text-[9px] font-bold flex items-center justify-center shadow-lg">
          {rank + 1}
        </div>
      )}

      {/* Ingredient emoji */}
      <span className="text-xl leading-none">{card.ingredient.split(' ')[0]}</span>

      {/* Value display */}
      <div className={cn('px-2 py-0.5 rounded-md border text-sm font-bold font-mono', mc.color)}>
        {card.display}
      </div>

      {/* Rep type badge */}
      <span className={cn('text-[8px] px-1.5 py-0.5 rounded border uppercase tracking-wider font-medium', mc.color)}>
        {mc.label}
      </span>

      {/* Ingredient label */}
      <span className="text-[9px] text-white/30 text-center leading-tight">{card.label}</span>

      {/* Tie indicator */}
      {isTied && showSolution && (
        <div className="text-[8px] text-yellow-300/80 font-mono">= tie</div>
      )}

      {/* Decimal value (shown in solution) */}
      {showSolution && (
        <div className="text-[9px] text-white/20 font-mono">≈ {card.decimalValue.toFixed(3)}</div>
      )}

      {/* Drag handle */}
      <GripVertical size={10} className="text-white/15 mt-0.5" />
    </motion.div>
  );
}

