  {tag:'Law of Sines',difficulty:'D3',
   question:'In a triangle, angle A = 45°, side a = 10 m, angle B = 60°. Find side b using the Law of Sines.',
   choices:['b ≈ 12.2 m','b ≈ 8.7 m','b ≈ 14.1 m','b ≈ 10 m'],answer:0,
   hint:'a/sin(A) = b/sin(B) → b = a·sin(B)/sin(A) = 10·sin60°/sin45° = 10·(√3/2)/(√2/2) ≈ 12.2.',
   angle:52,skill:'HSG.SRT.D.10'},
  // R9 – Law of Cosines
  {tag:'Law of Cosines',difficulty:'D3',
   question:'Two cannon towers are 8 m and 6 m from a central point, with 120° between them. How far apart are the towers?',
   choices:['10 m','12.2 m','√148 ≈ 12.2 m','14 m'],answer:2,
   hint:'c² = a² + b² – 2ab·cos(C) = 64 + 36 – 2(8)(6)cos(120°) = 100 + 48 = 148. c = √148 ≈ 12.2.',
   angle:42,skill:'HSG.SRT.D.11'},
  // R10 – Trig identity
  {tag:'Identities',difficulty:'D3',
   question:'Which identity helps simplify sin²(θ) + cos²(θ) − 1?',
   choices:['Double-angle formula','Pythagorean identity (= 0)','Sum-to-product','Law of Sines'],answer:1,
   hint:'The Pythagorean Identity: sin²θ + cos²θ = 1, so sin²θ + cos²θ – 1 = 0.',
   angle:55,skill:'HSF.TF.C.8'},
  // R11 – Graphing amplitude
  {tag:'Graphing',difficulty:'D3',
   question:'The siege catapult follows y = 3·sin(2x). What is its amplitude and period?',
   choices:['Amplitude 2, Period 3π','Amplitude 3, Period π','Amplitude 6, Period 2π','Amplitude 3, Period 2π'],answer:1,
   hint:'For y = A·sin(Bx): Amplitude = |A| = 3. Period = 2π/B = 2π/2 = π.',
   angle:50,skill:'HSF.TF.B.5'},
];

// ── STATE ─────────────────────────────────────────────────────────────────────
let round = 0, score = 0, streak = 0;
let animFrame = null;
let projectiles = [];
let particles = [];
let castles = [];
let answered = false;
let gameStarted = false;
let gameOver = false;

// ── CANVAS SETUP ──────────────────────────────────────────────────────────────
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');

function resize() {
  const scene = document.getElementById('scene');
  canvas.width = scene.clientWidth * devicePixelRatio;
  canvas.height = scene.clientHeight * devicePixelRatio;
  canvas.style.width = scene.clientWidth + 'px';
  canvas.style.height = scene.clientHeight + 'px';
  ctx.scale(devicePixelRatio, devicePixelRatio);
  drawStatic();
}
window.addEventListener('resize', resize);

// ── DRAWING ───────────────────────────────────────────────────────────────────
function W() { return canvas.width / devicePixelRatio; }
function H() { return canvas.height / devicePixelRatio; }

function drawStatic() {
  const w = W(), h = H();
  // Sky gradient
  const sky = ctx.createLinearGradient(0, 0, 0, h);
  sky.addColorStop(0, '#0a0a1a');
  sky.addColorStop(0.6, '#0f0f2a');
  sky.addColorStop(1, '#1a1a40');
  ctx.fillStyle = sky;
  ctx.fillRect(0, 0, w, h);

  // Stars
  ctx.fillStyle = 'rgba(255,255,255,0.6)';
  const stars = [[50,40],[100,20],[180,60],[250,15],[300,50],[380,25],[440,70],[510,30],[580,55],[620,20]];
  stars.forEach(([x,y]) => {
    ctx.beginPath(); ctx.arc(x % w, y, 1, 0, Math.PI*2); ctx.fill();
  });

  // Ground
  const ground = ctx.createLinearGradient(0, h-60, 0, h);
  ground.addColorStop(0, '#1e1b4b');
  ground.addColorStop(1, '#0f0e2a');
  ctx.fillStyle = ground;
  ctx.fillRect(0, h - 60, w, 60);

  // Ground line glow
  ctx.strokeStyle = 'rgba(99,102,241,0.4)';
  ctx.lineWidth = 1.5;
  ctx.beginPath(); ctx.moveTo(0, h-60); ctx.lineTo(w, h-60); ctx.stroke();
}

function drawCannon(angleRad) {
  const w = W(), h = H();
  const bx = 80, by = h - 60;

  // Cannon base
  ctx.fillStyle = 'rgba(99,102,241,0.25)';
  ctx.beginPath();
  ctx.arc(bx, by, 22, Math.PI, 0);
  ctx.fill();
  ctx.strokeStyle = 'rgba(99,102,241,0.6)';
  ctx.lineWidth = 2;
  ctx.stroke();

  // Cannon wheel
  ctx.beginPath();
  ctx.arc(bx, by, 14, 0, Math.PI*2);
  ctx.fillStyle = '#312e81';
  ctx.fill();
  ctx.strokeStyle = '#6366f1';
  ctx.lineWidth = 2;
  ctx.stroke();

  // Spokes
  for (let i = 0; i < 6; i++) {
    const a = (i / 6) * Math.PI * 2;
    ctx.beginPath();
    ctx.moveTo(bx, by);
    ctx.lineTo(bx + Math.cos(a)*12, by + Math.sin(a)*12);
    ctx.strokeStyle = '#4f46e5';
    ctx.lineWidth = 1.5;
    ctx.stroke();
  }

  // Barrel
  ctx.save();
  ctx.translate(bx, by);
  ctx.rotate(-angleRad);
  const barrelGrad = ctx.createLinearGradient(0, -7, 0, 7);
  barrelGrad.addColorStop(0, '#818cf8');
  barrelGrad.addColorStop(0.5, '#6366f1');
  barrelGrad.addColorStop(1, '#3730a3');
  ctx.fillStyle = barrelGrad;
  ctx.beginPath();
  ctx.roundRect(0, -7, 46, 14, [4,12,12,4]);
  ctx.fill();
  ctx.strokeStyle = '#a5b4fc';
  ctx.lineWidth = 1;
  ctx.stroke();

  // Angle arc indicator
  ctx.strokeStyle = 'rgba(165,180,252,0.35)';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.arc(0, 0, 55, -angleRad - 0.25, -angleRad + 0.25);
  ctx.stroke();
  ctx.restore();

  // Angle label
  const deg = Math.round(angleRad * 180 / Math.PI);
  ctx.fillStyle = '#a5b4fc';
  ctx.font = 'bold 11px system-ui';
  ctx.fillText(deg + '°', bx + 50, by - 14);
}

function drawCastles() {
  castles.forEach(c => {
    if (c.destroyed) return;
    const w = W(), h = H();
    const hp = c.hp / c.maxHp;
    const baseY = h - 60;

    // Tower body
    const grad = ctx.createLinearGradient(c.x - 20, 0, c.x + 20, 0);
    grad.addColorStop(0, c.hp > 0 ? '#7c3aed' : '#374151');
    grad.addColorStop(1, c.hp > 0 ? '#6d28d9' : '#1f2937');
    ctx.fillStyle = grad;
    ctx.fillRect(c.x - 20, baseY - c.height, 40, c.height);

    // Battlements
    if (c.hp > 0) {
      ctx.fillStyle = '#6d28d9';
      for (let i = 0; i < 3; i++) {
        ctx.fillRect(c.x - 18 + i*14, baseY - c.height - 12, 10, 12);
      }
    }

    // HP bar
    ctx.fillStyle = 'rgba(0,0,0,0.4)';
    ctx.fillRect(c.x - 18, baseY - c.height - 22, 36, 5);
    const hpColor = hp > 0.5 ? '#4ade80' : hp > 0.25 ? '#fbbf24' : '#f87171';
    ctx.fillStyle = hpColor;
    ctx.fillRect(c.x - 18, baseY - c.height - 22, 36 * hp, 5);

    // Flag
    if (c.hp > 0) {
      ctx.fillStyle = '#f472b6';
      ctx.beginPath();
      ctx.moveTo(c.x + 20, baseY - c.height - 10);
      ctx.lineTo(c.x + 36, baseY - c.height - 4);
      ctx.lineTo(c.x + 20, baseY - c.height + 2);
      ctx.fill();
      ctx.strokeStyle = '#a5b4fc';
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(c.x + 20, baseY - c.height - 14);
      ctx.lineTo(c.x + 20, baseY - c.height + 8);
      ctx.stroke();
    }

    // X on destroyed
    if (c.hp <= 0) {
      ctx.strokeStyle = '#f87171';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(c.x - 14, baseY - c.height + 10);
      ctx.lineTo(c.x + 14, baseY - 70);
      ctx.moveTo(c.x + 14, baseY - c.height + 10);
      ctx.lineTo(c.x - 14, baseY - 70);
      ctx.stroke();
    }
  });
}

function drawProjectiles() {
  projectiles.forEach(p => {
    ctx.save();
    ctx.shadowColor = '#a5b4fc';
    ctx.shadowBlur = 12;
    ctx.fillStyle = '#c7d2fe';
    ctx.beginPath();
    ctx.arc(p.x, p.y, 6, 0, Math.PI*2);
    ctx.fill();

    // Trail
    ctx.shadowBlur = 0;
    const alpha = [0.35, 0.2, 0.1];
    alpha.forEach((a, i) => {
      ctx.fillStyle = \`rgba(165,180,252,\${a})\`;
      ctx.beginPath();
      ctx.arc(p.x - p.vx*(i+1)*0.8, p.y - p.vy*(i+1)*0.8, 5 - i*1.5, 0, Math.PI*2);
      ctx.fill();
    });
    ctx.restore();
  });
}

function drawParticles() {
  particles.forEach(p => {
    ctx.globalAlpha = p.life;
    ctx.fillStyle = p.color;
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.r, 0, Math.PI*2);
    ctx.fill();
  });
  ctx.globalAlpha = 1;
}

function draw() {
  const w = W(), h = H();
  ctx.clearRect(0, 0, w, h);
  drawStatic();
  if (!gameStarted || gameOver) return;
  const r = ROUNDS[round];
  const angleRad = (r.angle || 45) * Math.PI / 180;
  drawCannon(angleRad);
  drawCastles();
  drawProjectiles();
  drawParticles();
}

// ── ANIMATION ─────────────────────────────────────────────────────────────────
function tick() {
  const h = H();
  projectiles.forEach(p => {
    p.x += p.vx;
    p.y += p.vy;
    p.vy += 0.35; // gravity
  });

  // Check hits
  projectiles = projectiles.filter(p => {
    if (p.y > h - 50) return false;
    let hit = false;
    castles.forEach(c => {
      if (!c.destroyed && !hit &&
          p.x > c.x - 22 && p.x < c.x + 22 &&
          p.y > h - 60 - c.height - 10 && p.y < h - 60) {
        c.hp = Math.max(0, c.hp - 34);
        if (c.hp <= 0) c.destroyed = true;
        spawnExplosion(c.x, p.y, c.hp <= 0 ? '#f472b6' : '#fbbf24');
        hit = true;
      }
    });
    return !hit && p.x < W() + 60;
  });

  // Particles
  particles.forEach(p => {
    p.x += p.vx; p.y += p.vy;
    p.vy += 0.18;
    p.life -= 0.035;
    p.r *= 0.97;
  });
  particles = particles.filter(p => p.life > 0);

  draw();
  animFrame = requestAnimationFrame(tick);
}

function spawnExplosion(x, y, color) {
  for (let i = 0; i < 14; i++) {
    const a = Math.random() * Math.PI * 2;
    const sp = 2 + Math.random() * 4;
    particles.push({ x, y, vx: Math.cos(a)*sp, vy: Math.sin(a)*sp - 2,
      life: 0.9 + Math.random()*0.3, r: 3 + Math.random()*4, color });
  }
}

function fireProjectile() {
  const bx = 80, by = H() - 60;
  const r = ROUNDS[round];
  const angleRad = (r.angle || 45) * Math.PI / 180;
  const speed = 8 + round * 0.4;
  projectiles.push({
    x: bx + 46*Math.cos(angleRad),
    y: by - 46*Math.sin(angleRad),
    vx: Math.cos(angleRad) * speed,
    vy: -Math.sin(angleRad) * speed,
  });
}

// ── CASTLES SETUP ─────────────────────────────────────────────────────────────
function setupCastles() {
  const w = W();
  castles = [
    { x: w * 0.55, height: 80, hp: 100, maxHp: 100, destroyed: false },
    { x: w * 0.70, height: 100, hp: 100, maxHp: 100, destroyed: false },
    { x: w * 0.85, height: 70,  hp: 100, maxHp: 100, destroyed: false },
  ];
}

// ── GAME FLOW ─────────────────────────────────────────────────────────────────
function startGame() {
  document.getElementById('overlay').style.display = 'none';
  round = 0; score = 0; streak = 0;
  gameStarted = true; gameOver = false;
  projectiles = []; particles = [];
  setupCastles();
  updateHUD();
  loadRound();
  if (animFrame) cancelAnimationFrame(animFrame);
  animFrame = requestAnimationFrame(tick);
}

function loadRound() {
  answered = false;
  const r = ROUNDS[round];
  document.getElementById('hud-tag').textContent = r.tag;
  document.getElementById('q-header').textContent = \`🎯 \${r.tag} — \${r.difficulty}\`;
  document.getElementById('q-text').textContent = r.question;
  document.getElementById('feedback').textContent = '';
  document.getElementById('feedback').className = '';

  const container = document.getElementById('q-choices');
  container.innerHTML = '';
  r.choices.forEach((ch, i) => {
    const btn = document.createElement('button');
    btn.className = 'choice-btn';
    btn.textContent = ch;
    btn.onclick = () => selectAnswer(i, btn);
    container.appendChild(btn);
  });
}

function selectAnswer(idx, btn) {
  if (answered) return;
  answered = true;
  const r = ROUNDS[round];
  const allBtns = document.querySelectorAll('.choice-btn');
  allBtns.forEach(b => b.disabled = true);

  const correct = idx === r.answer;
  const fb = document.getElementById('feedback');

  if (correct) {
    btn.classList.add('correct');
    score += 100 + streak * 25;
    streak++;
    fb.textContent = \`✅ Correct! \${r.hint} Streak: \${streak}🔥\`;
    fb.className = 'feedback-correct';
    fireProjectile();
    // Damage castle
    if (castles[round % 3]) {
      const c = castles[round % 3];
      setTimeout(() => {
        c.hp = Math.max(0, c.hp - 50);
        if (c.hp <= 0) c.destroyed = true;
      }, 700);
    }
  } else {
    btn.classList.add('wrong');
    allBtns[r.answer].classList.add('correct');
    streak = 0;
    fb.textContent = \`❌ Not quite. Hint: \${r.hint}\`;
    fb.className = 'feedback-wrong';
  }

  updateHUD();

  setTimeout(() => {
    if (round < ROUNDS.length - 1) {
      round++;
      updateHUD();
      loadRound();
    } else {
      endGame();
    }
  }, 2200);
}

function endGame() {
  gameOver = true;
  cancelAnimationFrame(animFrame);
  const destroyed = castles.filter(c => c.destroyed).length;
  const ov = document.getElementById('overlay');
  ov.style.display = 'flex';
  const pct = Math.round((score / (ROUNDS.length * 125)) * 100);
  ov.innerHTML = \`
    <div class="round-badge">Siege Complete!</div>
    <div class="overlay-title">\${score >= 900 ? '🏆 Master Artillerist' : score >= 600 ? '⭐ Skilled Gunner' : '🎯 Cadet'}</div>
    <div class="overlay-sub">You answered 12 trig challenges and powered the siege!</div>
    <div class="overlay-stat">Final Score: <span>\${score}</span></div>
    <div class="overlay-stat">Towers Destroyed: <span>\${destroyed}/3</span></div>
    <div class="overlay-stat">Accuracy Rating: <span>\${pct}%</span></div>
    <br/>
    <button class="overlay-btn" onclick="startGame()">🔁 Siege Again</button>
  \`;
}

function updateHUD() {
  document.getElementById('hud-round').textContent = Math.min(round + 1, 12);
  document.getElementById('hud-score').textContent = score;
  document.getElementById('hud-streak').textContent = streak;
}

// ── INIT ──────────────────────────────────────────────────────────────────────
resize();
draw();
</script>
</body>
</html>`;

// ── Chat Message Types ────────────────────────────────────────────────────────
interface Message {
  role: 'user' | 'assistant';
  text: string;
  id: string;
}

// ── Main Component ────────────────────────────────────────────────────────────
export default function TrigTower() {
  const [chatOpen, setChatOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'assistant',
      text: "🎯 Ready for siege warfare, soldier? I'm your Trig Tower Tutor. Answer the cannon questions, and if you get stuck — ask me anything! SOH-CAH-TOA, unit circle, Law of Sines... I've got you.",
      id: 'init',
    },
  ]);
  const [input, setInput] = useState('');
  const [sending, setSending] = useState(false);
  const [tab, setTab] = useState<'game' | 'reference'>('game');
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  async function sendMessage() {
    const text = input.trim();
    if (!text || sending) return;
    setInput('');

    const userMsg: Message = { role: 'user', text, id: Date.now().toString() };
    setMessages(prev => [...prev, userMsg]);
    setSending(true);

    try {
      // Use the Taskade agent API
      const response = await fetch(`/api/taskade/agents/${TUTOR_AGENT_ID}/chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: text }),
      });

      if (response.ok) {
        const data = await response.json();
        const reply = data?.payload?.response || data?.response || "I'm thinking... try rephrasing your question!";
        setMessages(prev => [...prev, { role: 'assistant', text: reply, id: Date.now().toString() + 'a' }]);
      } else {
        // Fallback local scaffolding
        const reply = localScaffold(text);
        setMessages(prev => [...prev, { role: 'assistant', text: reply, id: Date.now().toString() + 'a' }]);
      }
    } catch {
      const reply = localScaffold(text);
      setMessages(prev => [...prev, { role: 'assistant', text: reply, id: Date.now().toString() + 'a' }]);
    } finally {
      setSending(false);
    }
  }

  function localScaffold(q: string): string {
    const lq = q.toLowerCase();
    if (lq.includes('sin') && !lq.includes('cos')) return "SOH: sin(θ) = Opposite ÷ Hypotenuse. Think of it as the *height* ratio. On the unit circle, sin gives you the y-coordinate at angle θ.";
    if (lq.includes('cos')) return "CAH: cos(θ) = Adjacent ÷ Hypotenuse. It's the *width* ratio. On the unit circle, cos is the x-coordinate at angle θ.";
    if (lq.includes('tan')) return "TOA: tan(θ) = Opposite ÷ Adjacent. It's slope! tan(45°) = 1 because opp = adj at that angle.";
    if (lq.includes('radian') || lq.includes('degree')) return "Convert degrees → radians: multiply by π/180. So 180° = π, 90° = π/2, 60° = π/3, 45° = π/4, 30° = π/6.";
    if (lq.includes('unit circle')) return "The unit circle has radius 1. At angle θ: the point is (cos θ, sin θ). Key values: 0° → (1,0), 30° → (√3/2, 1/2), 45° → (√2/2, √2/2), 60° → (1/2, √3/2), 90° → (0,1).";
    if (lq.includes('law of sine') || lq.includes('sine rule')) return "Law of Sines: a/sin(A) = b/sin(B) = c/sin(C). Use it when you know an angle-side pair and want to find another side or angle.";
    if (lq.includes('law of cos') || lq.includes('cosine rule')) return "Law of Cosines: c² = a² + b² – 2ab·cos(C). Use it for SAS (two sides + included angle) or SSS (all three sides known).";
    if (lq.includes('identity') || lq.includes('pythagorean')) return "The Pythagorean Identity: sin²θ + cos²θ = 1. This is your best friend! It comes from the Pythagorean theorem applied to the unit circle.";
    if (lq.includes('arcsin') || lq.includes('inverse') || lq.includes('sin⁻¹')) return "Inverse trig undoes the ratio. arcsin(0.5) = 30° because sin(30°) = 0.5. Range of arcsin is [–90°, 90°]. Your calculator writes it as sin⁻¹.";
    return "Great question! Break the problem into steps: (1) What sides or angles do you know? (2) Which trig function connects them? (3) Set up the ratio and solve. What does your problem give you?";
  }

  const REFERENCE = [
    { title: 'SOH-CAH-TOA', body: 'sin = Opp/Hyp · cos = Adj/Hyp · tan = Opp/Adj', color: '#6366f1' },
    { title: 'Unit Circle Key Values', body: '0°→(1,0) · 30°→(√3/2,½) · 45°→(√2/2,√2/2) · 60°→(½,√3/2) · 90°→(0,1)', color: '#8b5cf6' },
    { title: 'Degrees ↔ Radians', body: 'rad = deg × π/180 · deg = rad × 180/π · 180° = π', color: '#a855f7' },
    { title: 'Pythagorean Identity', body: 'sin²θ + cos²θ = 1', color: '#7c3aed' },
    { title: 'Law of Sines', body: 'a/sin A = b/sin B = c/sin C', color: '#6d28d9' },
    { title: 'Law of Cosines', body: 'c² = a² + b² – 2ab·cos C', color: '#5b21b6' },
    { title: 'Common M1 Trap', body: 'Don\'t swap sin and cos! Check: "Opposite to what angle?"', color: '#dc2626' },
    { title: 'Amplitude & Period', body: 'y = A·sin(Bx): Amplitude = |A|, Period = 2π/B', color: '#059669' },
  ];

  return (
    <div className="h-full flex overflow-hidden bg-[#0a0a1a]">
      {/* ── Game Area ────────────────────────────────────────────────────────── */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Tab switcher */}
        <div className="flex items-center gap-1 px-4 py-2 bg-[#0d0d20] border-b border-white/5">
          <button
            onClick={() => setTab('game')}
            className={cn(
              'flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold transition-all',
              tab === 'game' ? 'bg-indigo-600/30 text-indigo-300 border border-indigo-500/40' : 'text-white/40 hover:text-white/70 hover:bg-white/5'
            )}
          >
            <Crosshair size={12} /> Siege Game
          </button>
          <button
            onClick={() => setTab('reference')}
            className={cn(
              'flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold transition-all',
              tab === 'reference' ? 'bg-purple-600/30 text-purple-300 border border-purple-500/40' : 'text-white/40 hover:text-white/70 hover:bg-white/5'
            )}
          >
            <BookOpen size={12} /> Reference Sheet
          </button>

          <div className="ml-auto flex items-center gap-2">
            <div className="text-[10px] text-white/30 font-mono">GAP-4 · HS Trig · HSF.TF.A–C · HSG.SRT.C–D</div>
            <button
              onClick={() => setChatOpen(o => !o)}
              className={cn(
                'flex items-center gap-1.5 h-7 px-3 rounded-lg text-xs font-semibold transition-all border',
                chatOpen
                  ? 'bg-indigo-600 text-white border-indigo-500'
                  : 'bg-indigo-600/15 text-indigo-300 border-indigo-500/30 hover:bg-indigo-600/30'
              )}
            >
              <Bot size={12} />
              Tutor
            </button>
          </div>
        </div>

        {tab === 'game' ? (
          <div className="flex-1 overflow-hidden">
            <iframe
              srcDoc={GAME_HTML}
              className="w-full h-full border-none"
              title="Trig Tower Game"
              sandbox="allow-scripts"
            />
          </div>
        ) : (
          <div className="flex-1 overflow-y-auto p-5">
            <div className="max-w-3xl mx-auto">
              <div className="mb-5">
                <h2 className="text-lg font-bold text-white mb-1">📐 Trigonometry Reference Sheet</h2>
                <p className="text-xs text-white/40">Quick-access formulas for the siege. Open the Tutor panel if you need step-by-step help.</p>
