interface AgentPanelProps {
  open: boolean;
  onClose: () => void;
  activeAgentId: string;
  setActiveAgentId: (id: string) => void;
}

export default function AgentPanel({ open, onClose, activeAgentId, setActiveAgentId }: AgentPanelProps) {
  const [chat, setChat] = useState<ReturnType<typeof createAgentChat> | null>(null);
  const [chatAgentId, setChatAgentId] = useState<string | null>(null);
  const [starting, setStarting] = useState(false);

  const handleStartChat = useCallback(async (agentId: string) => {
    setStarting(true);
    try {
      const { conversationId } = await createConversation(agentId);
      setChat(createAgentChat(agentId, conversationId));
      setChatAgentId(agentId);
    } catch (e) {
      console.error(e);
    } finally {
      setStarting(false);
    }
  }, []);

  const handleSwitchAgent = useCallback(async (agentId: string) => {
    setActiveAgentId(agentId);
    setChat(null);
    setChatAgentId(null);
    await handleStartChat(agentId);
  }, [setActiveAgentId, handleStartChat]);

  const activeAgent = AGENTS.find(a => a.id === activeAgentId) ?? AGENTS[0];

  return (
    <AnimatePresence>
      {open && (
        <>
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/50 backdrop-blur-sm z-40"
            onClick={onClose}
          />

          {/* Panel */}
          <motion.div
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
