              <div
                className="w-8 h-8 rounded-xl flex items-center justify-center text-lg flex-shrink-0"
                style={{ backgroundColor: activeAgent.color + '20' }}
              >
                {activeAgent.emoji}
              </div>
              <div className="flex-1 min-w-0">
                <div className="text-sm font-semibold text-white truncate">{activeAgent.name}</div>
                <div className="text-[10px] text-white/30 truncate">{activeAgent.desc}</div>
              </div>
              <button
                onClick={onClose}
                className="w-7 h-7 rounded-lg bg-white/5 hover:bg-white/10 flex items-center justify-center text-white/40 hover:text-white transition-all"
              >
                <X size={14} />
              </button>
            </div>

            {/* Agent switcher */}
            <div className="flex gap-1.5 px-3 py-2 border-b border-white/5 overflow-x-auto">
              {AGENTS.map(agent => (
                <button
                  key={agent.id}
                  onClick={() => agent.id !== chatAgentId && handleSwitchAgent(agent.id)}
                  className={cn(
                    'flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg text-[11px] font-medium whitespace-nowrap transition-all flex-shrink-0',
                    chatAgentId === agent.id
                      ? 'text-white'
                      : 'text-white/35 hover:text-white/60 hover:bg-white/5'
                  )}
                  style={chatAgentId === agent.id ? { backgroundColor: agent.color + '20', color: agent.color } : {}}
                >
                  {agent.emoji} {agent.name.split(' ')[0]}
                </button>
              ))}
            </div>

            {/* Chat area */}
            <div className="flex-1 overflow-hidden flex flex-col">
              {!chat ? (
                <StartChatPrompt
                  agent={activeAgent}
                  starting={starting}
                  onStart={() => handleStartChat(activeAgentId)}
                />
              ) : (
                <ActiveChat chat={chat} agentColor={activeAgent.color} />
              )}
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
}

function StartChatPrompt({
