function ActiveChat({ chat, agentColor }: { chat: ReturnType<typeof createAgentChat>; agentColor: string }) {
  const { messages, status, addToolApprovalResponse } = useChat({ chat, id: chat.id });
  const hasMessages = messages.length > 0;
  const isSending = status === 'submitted' || status === 'streaming';

  const handleSend = async (text: string) => {
    const trimmed = text.trim();
    if (!trimmed) return;
    await chat.sendMessage({
      id: ulid(),
      role: 'user',
      parts: [{ type: 'text', text: trimmed }],
    });
  };

  const SUGGESTIONS = [
    'Give me a pipeline overview',
    'What concepts need attention?',
    'Find curriculum gaps',
    'Generate a new game idea',
  ];

  return (
    <div className="flex h-full flex-col overflow-hidden">
      <Conversation className="flex-1">
        <ConversationContent>
          {messages.map(msg => (
            <Message key={msg.id} from={msg.role}>
              <MessageContent>
                <MessageParts message={msg} onApprove={addToolApprovalResponse} />
              </MessageContent>
            </Message>
          ))}
        </ConversationContent>
        <ConversationScrollButton />
      </Conversation>

      {!hasMessages && (
        <Suggestions className="px-3">
          {SUGGESTIONS.map(s => (
            <Suggestion key={s} suggestion={s} onClick={handleSend} />
          ))}
        </Suggestions>
      )}

      <PromptInput onSubmit={({ text }) => handleSend(text)} className="border-t border-white/5 m-0 rounded-none">
        <PromptInputTextarea placeholder="Ask anything about the pipeline..." />
        <PromptInputFooter>
          <PromptInputSubmit status={status} style={{ backgroundColor: agentColor }} />
        </PromptInputFooter>
      </PromptInput>
    </div>
  );
}

function MessageParts({
  message,
  onApprove,
}: {
  message: UIMessage;
  onApprove: ReturnType<typeof useChat>['addToolApprovalResponse'];
}) {
  return (
    <>
      {message.parts.map((part, i) => {
        const key = `${message.id}-${i}`;

        if (part.type === 'text') {
          return message.role === 'user' ? (
            <p key={key} className="text-sm text-white/80">{part.text}</p>
          ) : (
            <MessageResponse key={key}>{part.text}</MessageResponse>
          );
        }

        if (isToolUIPart(part)) {
          return (
            <Tool key={key}>
              <ToolHeader type={part.type} state={part.state} />
              <ToolContent>
                <ToolInput input={part.input} />
                <Confirmation approval={part.approval} state={part.state}>
                  <ConfirmationRequest>
                    <ConfirmationTitle>Allow this tool to run?</ConfirmationTitle>
                  </ConfirmationRequest>
                  <ConfirmationAccepted>Approved</ConfirmationAccepted>
                  <ConfirmationRejected>Rejected</ConfirmationRejected>
                  <ConfirmationActions>
                    <ConfirmationAction
                      variant="outline"
                      onClick={() => part.approval != null && onApprove({ id: part.approval.id, approved: false })}
                    >
                      Deny
                    </ConfirmationAction>
                    <ConfirmationAction
                      onClick={() => part.approval != null && onApprove({ id: part.approval.id, approved: true })}
                    >
                      Approve
                    </ConfirmationAction>
                  </ConfirmationActions>
                </Confirmation>
                <ToolOutput output={part.output} errorText={part.errorText} />
              </ToolContent>
            </Tool>
          );
        }

        return null;
      })}
    </>
  );
}

