// M2 — place-value blindness: treating 12+8 like 1+8 or 1+2+8
// M3 — carry confusion: forgetting the regrouped ten
// M4 — order irrelevance misconception: believing A+B ≠ B+A

type Block = 'intro' | 'addition' | 'regroup' | 'quantity';
type GamePhase = 'idle' | 'playing' | 'correct' | 'wrong' | 'complete';

