/* ─────────────────────────────────────────────────────────────────────────────
   HELPERS
───────────────────────────────────────────────────────────────────────────── */

function blockLabel(b: Block, isBonusRound?: boolean): string {
  if (b === 'intro')    return 'Warm-Up';
  if (b === 'addition') return 'Addition Facts';
  if (b === 'regroup')  return isBonusRound ? 'Regrouping · Grade 2+ Bonus' : 'Regrouping';
  return 'Quantity Match';
}

function blockColor(b: Block, isBonusRound?: boolean): string {
  if (b === 'intro')    return 'bg-blue-500/15 border-blue-500/25 text-blue-400';
  if (b === 'addition') return 'bg-indigo-500/15 border-indigo-500/25 text-indigo-400';
  if (b === 'regroup')  return isBonusRound
    ? 'bg-teal-500/15 border-teal-500/25 text-teal-400'
    : 'bg-violet-500/15 border-violet-500/25 text-violet-400';
  return 'bg-pink-500/15 border-pink-500/25 text-pink-400';
}

const MC_META: Record<MisconceptionTag, { label: string; desc: string; color: string }> = {
  M1: { label: 'M1 · Subitizing Shortcut',   desc: 'Grabs the count of one icon group instead of computing both.',         color: 'text-rose-400 bg-rose-400/10 border-rose-400/25' },
  M2: { label: 'M2 · Place-Value Blindness',  desc: 'Treats two-digit numbers as single digits (ignores tens column).',      color: 'text-amber-400 bg-amber-400/10 border-amber-400/25' },
  M3: { label: 'M3 · Carry Confusion',        desc: 'Forgets to regroup (carry the 1) when sum exceeds 9 in ones place.',   color: 'text-purple-400 bg-purple-400/10 border-purple-400/25' },
  M4: { label: 'M4 · Order Irrelevance',      desc: 'Doubts that A + B = B + A — doesn\'t trust commutativity.',           color: 'text-cyan-400 bg-cyan-400/10 border-cyan-400/25' },
  none: { label: '—', desc: 'No misconception targeted this round.', color: 'text-white/25 bg-white/5 border-white/10' },
};

/* ─────────────────────────────────────────────────────────────────────────────
   GAME SCREEN
───────────────────────────────────────────────────────────────────────────── */

function GameScreen() {
  const [roundIdx, setRoundIdx] = useState(0);
  const [phase, setPhase] = useState<GamePhase>('idle');
  const [attempts, setAttempts] = useState(0);
  const [completedRounds, setCompletedRounds] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [shuffledChoices, setShuffledChoices] = useState<number[]>([]);

  const round = ROUNDS[roundIdx];

  const startRound = useCallback((idx: number) => {
    const r = ROUNDS[idx];
    const all = [r.answer, ...r.foils].sort(() => Math.random() - 0.5);
    setShuffledChoices(all);
    setPhase('playing');
    setAttempts(0);
    setSelectedAnswer(null);
  }, []);

  const handleBegin = () => startRound(0);

  const handleChoice = useCallback((val: number) => {
    if (phase !== 'playing') return;
    setSelectedAnswer(val);
    if (val === round.answer) {
      setPhase('correct');
      setCompletedRounds(c => c + 1);
    } else {
      setAttempts(a => a + 1);
      setPhase('wrong');
    }
  }, [phase, round]);

  const handleNext = useCallback(() => {
    const nextIdx = roundIdx + 1;
    if (nextIdx >= ROUNDS.length) {
      setPhase('complete');
    } else {
      setRoundIdx(nextIdx);
      startRound(nextIdx);
    }
  }, [roundIdx, startRound]);

  const handleRetry = useCallback(() => {
    setPhase('playing');
    setSelectedAnswer(null);
  }, []);

  const handleRestart = () => {
    setRoundIdx(0);
    setCompletedRounds(0);
    setPhase('idle');
    setSelectedAnswer(null);
  };

  // Hint logic: boss rounds suppress all hints
  const showHint = phase === 'wrong' && !round.isBossRound;
  const hintText = attempts >= 2 && round.wrongHint2 ? round.wrongHint2 : round.wrongHint;

  /* ── IDLE ── */
  if (phase === 'idle') {
    return (
      <div className="flex flex-col items-center justify-center gap-8 py-16 px-6">
        <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="text-center">
          <div className="text-7xl mb-4">🧁</div>
          <h2 className="text-2xl font-bold text-white mb-2">Bakery Rush</h2>
          <p className="text-white/40 text-sm max-w-xs mx-auto">
            Orders keep coming in! Choose the right total to bake the perfect batch.
          </p>
          <div className="flex items-center justify-center gap-3 mt-4 flex-wrap">
            <span className="text-[10px] text-white/20 bg-white/5 px-3 py-1 rounded-full">K–2 · Addition Fluency</span>
            <span className="text-[10px] text-white/20 bg-white/5 px-3 py-1 rounded-full">12 rounds + bonus</span>
            <span className="text-[10px] text-white/20 bg-white/5 px-3 py-1 rounded-full">CCSS K.OA / 1.OA / 2.NBT</span>
          </div>
        </motion.div>
        <motion.button
          onClick={handleBegin}
          whileTap={{ scale: 0.96 }}
          className="px-8 py-3 rounded-2xl font-bold text-sm bg-gradient-to-r from-orange-500 to-amber-500 text-white shadow-lg shadow-orange-500/30 hover:brightness-110 transition-all"
        >
          Open the Bakery 🍞
        </motion.button>
      </div>
    );
  }

  /* ── COMPLETE ── */
  if (phase === 'complete') {
    return (
      <div className="flex flex-col items-center justify-center gap-6 py-16 px-6">
        <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ type: 'spring', stiffness: 200 }}>
          <div className="text-7xl">🏆</div>
        </motion.div>
        <div className="text-center">
          <h2 className="text-2xl font-bold text-white mb-2">Bakery Complete!</h2>
          <p className="text-white/40 text-sm">All {ROUNDS.length - 1} orders + bonus round delivered. You nailed it!</p>
          <div className="mt-4 px-6 py-3 bg-emerald-500/10 border border-emerald-500/25 rounded-2xl">
            <span className="text-emerald-400 font-bold text-lg">{completedRounds} / {ROUNDS.length}</span>
            <span className="text-white/40 text-sm ml-2">orders filled correctly</span>
          </div>
        </div>
        <button onClick={handleRestart} className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-white/10 hover:bg-white/15 text-white text-sm font-medium transition-all">
          <RotateCcw size={14} /> Bake Again
        </button>
      </div>
    );
  }

  /* ── PLAYING / CORRECT / WRONG ── */
  return (
    <div className="flex flex-col gap-5 px-5 py-6 max-w-lg mx-auto w-full">
      {/* Round HUD */}
      <div className="flex items-center gap-2 flex-wrap">
        <span className="text-xs font-bold text-white/50 tabular-nums">Round {round.roundIndex + 1} / {ROUNDS.length}</span>
        <span className={cn('text-[10px] font-bold px-2 py-0.5 rounded-full border', blockColor(round.block, round.isBossRound && round.block === 'regroup'))}>
          {blockLabel(round.block, round.isBossRound && round.block === 'regroup')}
        </span>
        {round.isBossRound && (
          <span className="flex items-center gap-1 text-[10px] font-bold px-2 py-0.5 rounded-full bg-yellow-500/15 border border-yellow-500/25 text-yellow-400">
            <Star size={9} /> {round.roundIndex === 12 ? 'Bonus Boss · no hints' : 'Boss Round · no hints'}
          </span>
        )}
        {round.misconceptionTag !== 'none' && (
          <span className="flex items-center gap-1 text-[10px] font-bold px-2 py-0.5 rounded-full bg-orange-500/15 border border-orange-500/25 text-orange-400">
            <AlertTriangle size={9} /> {round.misconceptionTag}
          </span>
        )}
        <div className="ml-auto flex gap-1">
          {ROUNDS.map((_, i) => (
            <div key={i} className={cn('w-1.5 h-1.5 rounded-full transition-all', i < completedRounds ? 'bg-emerald-400' : i === roundIdx ? 'bg-orange-400' : 'bg-white/15')} />
          ))}
        </div>
      </div>

      {/* Oven display */}
      <motion.div
        key={round.roundIndex}
        initial={{ opacity: 0, y: 12 }}
        animate={{ opacity: 1, y: 0 }}
        className="rounded-3xl border border-white/10 bg-gradient-to-br from-orange-950/40 to-amber-950/30 p-6 text-center"
        style={{ boxShadow: '0 0 40px rgba(251,146,60,0.08)' }}
      >
        <div className="text-5xl mb-3">{round.emoji}</div>
        <div className="text-3xl font-bold text-white font-mono mb-3 tracking-tight">{round.expression}</div>
        <p className="text-white/55 text-sm leading-relaxed">{round.prompt}</p>
      </motion.div>

      {/* Answer choices */}
      <div className="grid grid-cols-2 gap-3">
        {shuffledChoices.map(val => {
          const isCorrect = val === round.answer;
          const isSelected = val === selectedAnswer;
          const showResult = phase === 'correct' || phase === 'wrong';

          let style = 'bg-white/8 border-white/12 text-white hover:bg-white/12 hover:border-white/20';
          if (showResult && isSelected && isCorrect) style = 'bg-emerald-500/20 border-emerald-500/50 text-emerald-300';
          if (showResult && isSelected && !isCorrect) style = 'bg-red-500/20 border-red-500/40 text-red-300';

          return (
            <motion.button
              key={val}
              onClick={() => handleChoice(val)}
              disabled={phase !== 'playing'}
              whileTap={phase === 'playing' ? { scale: 0.96 } : {}}
              className={cn(
                'flex items-center justify-center py-5 rounded-2xl border text-2xl font-bold transition-all duration-200',
                style,
                phase !== 'playing' && 'cursor-default'
              )}
            >
              {val}
              {showResult && isSelected && isCorrect && <CheckCircle2 size={18} className="ml-2 flex-shrink-0" />}
            </motion.button>
          );
        })}
      </div>

      {/* Feedback */}
      <AnimatePresence mode="wait">
        {phase === 'correct' && (
          <motion.div
            key="correct"
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
            className="flex flex-col gap-3"
          >
            <div className="flex items-center gap-2 bg-emerald-500/10 border border-emerald-500/25 rounded-2xl px-4 py-3">
              <CheckCircle2 size={16} className="text-emerald-400 flex-shrink-0" />
              <span className="text-emerald-300 text-sm font-semibold">Order filled! {round.answer} {round.emoji} baked perfectly.</span>
            </div>
            <button
              onClick={handleNext}
              className="w-full py-3 rounded-2xl font-bold text-sm bg-gradient-to-r from-orange-500 to-amber-500 text-white shadow-md shadow-orange-500/25 hover:brightness-110 transition-all"
            >
              {roundIdx + 1 >= ROUNDS.length ? 'See Final Score 🏆' : roundIdx + 1 === 12 ? 'Bonus Challenge 🌟' : 'Next Order →'}
            </button>
          </motion.div>
        )}

        {phase === 'wrong' && (
          <motion.div
            key="wrong"
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
            className="flex flex-col gap-3"
          >
            {showHint && hintText && (
              <div className="flex items-start gap-2 bg-amber-500/10 border border-amber-500/20 rounded-2xl px-4 py-3">
                <Info size={14} className="text-amber-400 flex-shrink-0 mt-0.5" />
                <span className="text-amber-300/80 text-sm leading-relaxed">{hintText}</span>
              </div>
            )}
            {round.isBossRound && (
              <div className="flex items-center gap-2 bg-yellow-500/10 border border-yellow-500/20 rounded-2xl px-4 py-3">
                <Star size={14} className="text-yellow-400 flex-shrink-0" />
                <span className="text-yellow-300/70 text-sm">Boss round — no hints. Try again!</span>
              </div>
            )}
            <button
              onClick={handleRetry}
              className="w-full py-3 rounded-2xl font-bold text-sm bg-white/10 hover:bg-white/15 text-white transition-all border border-white/10"
            >
              <RotateCcw size={13} className="inline mr-2" />Try Again
            </button>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────────────────────
   LEVEL BROWSER
───────────────────────────────────────────────────────────────────────────── */

function LevelBrowser() {
  const [activeIdx, setActiveIdx] = useState(0);
  const [showAnswer, setShowAnswer] = useState(false);
  const [filterBlock, setFilterBlock] = useState<Block | 'all'>('all');
  const [filterMC, setFilterMC] = useState<MisconceptionTag | 'all'>('all');

  const filtered = ROUNDS.filter(r =>
    (filterBlock === 'all' || r.block === filterBlock) &&
    (filterMC === 'all' || r.misconceptionTag === filterMC)
  );

  const round = filtered[activeIdx] ?? ROUNDS[0];
  const mc = MC_META[round.misconceptionTag];

  return (
    <div className="flex gap-5 h-full overflow-hidden px-5 py-5">
      {/* Left: round list */}
      <div className="w-64 flex-shrink-0 flex flex-col gap-3 overflow-y-auto pr-1">
        {/* Filters */}
        <div className="space-y-2">
          <select
            value={filterBlock}
            onChange={e => { setFilterBlock(e.target.value as Block | 'all'); setActiveIdx(0); }}
            className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-1.5 text-xs text-white/70 focus:outline-none"
          >
            <option value="all">All Blocks</option>
            <option value="intro">Warm-Up</option>
            <option value="addition">Addition Facts</option>
            <option value="regroup">Regrouping</option>
            <option value="quantity">Quantity Match</option>
          </select>
          <select
            value={filterMC}
            onChange={e => { setFilterMC(e.target.value as MisconceptionTag | 'all'); setActiveIdx(0); }}
            className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-1.5 text-xs text-white/70 focus:outline-none"
          >
            <option value="all">All Misconceptions</option>
            <option value="M1">M1 · Subitizing Shortcut</option>
            <option value="M2">M2 · Place-Value Blindness</option>
            <option value="M3">M3 · Carry Confusion</option>
            <option value="M4">M4 · Order Irrelevance</option>
            <option value="none">No Misconception</option>
          </select>
        </div>

        {/* Round rows */}
        {filtered.map((r, i) => (
          <button
            key={r.roundIndex}
            onClick={() => { setActiveIdx(i); setShowAnswer(false); }}
            className={cn(
              'flex items-center gap-2 px-3 py-2.5 rounded-xl border text-left transition-all',
              activeIdx === i
                ? 'bg-orange-500/15 border-orange-500/30 text-white'
                : 'bg-white/[0.025] border-white/8 text-white/50 hover:text-white/70 hover:bg-white/5'
            )}
          >
            <div className="w-7 h-7 rounded-lg bg-white/8 border border-white/10 flex items-center justify-center text-xs font-bold text-white/60 flex-shrink-0">
              R{r.roundIndex}
            </div>
            <div className="flex-1 min-w-0">
              <div className="text-xs font-semibold truncate">{r.expression} = ?</div>
              <div className="text-[10px] text-white/30 truncate">{blockLabel(r.block)}</div>
            </div>
            {r.misconceptionTag !== 'none' && (
              <span className="text-[9px] font-bold text-orange-400 flex-shrink-0">{r.misconceptionTag}</span>
            )}
            {r.isBossRound && <Star size={10} className="text-yellow-400 flex-shrink-0" />}
          </button>
        ))}

        {filtered.length === 0 && (
          <p className="text-white/20 text-xs text-center py-4">No rounds match filters.</p>
        )}
      </div>

      {/* Right: detail panel */}
      <div className="flex-1 overflow-y-auto space-y-4">
        {/* Header */}
        <div className="flex items-center gap-3">
          <div className="text-4xl">{round.emoji}</div>
          <div>
            <h2 className="text-base font-bold text-white">R{round.roundIndex} — {blockLabel(round.block)}</h2>
            <div className="flex items-center gap-2 mt-1 flex-wrap">
              <span className={cn('text-[10px] font-bold px-2 py-0.5 rounded-full border', blockColor(round.block, round.isBossRound && round.block === 'regroup'))}>
                {blockLabel(round.block, round.isBossRound && round.block === 'regroup')}
              </span>
              {round.isBossRound && (
                <span className="flex items-center gap-1 text-[10px] font-bold px-2 py-0.5 rounded-full bg-yellow-500/15 border border-yellow-500/25 text-yellow-400">
                  <Star size={9} /> {round.roundIndex === 12 ? 'Bonus Boss' : 'Boss Round'}
                </span>
              )}
              {round.roundIndex === 12 && (
                <span className="text-[10px] font-bold px-2 py-0.5 rounded-full bg-teal-500/15 border border-teal-500/25 text-teal-400">
                  Grade 2+ Only
                </span>
              )}
            </div>
          </div>
          <button
            onClick={() => setShowAnswer(a => !a)}
