              </div>
            </motion.div>
          )}
        </div>

        {/* Prompt */}
        <div className="bg-white/[0.025] border border-white/8 rounded-xl px-4 py-3">
          <div className="text-[10px] text-white/25 uppercase tracking-widest mb-1">Player Prompt</div>
          <p className="text-white/70 text-sm leading-relaxed">{round.prompt}</p>
        </div>

        {/* Misconception */}
        <div className={cn('border rounded-xl px-4 py-3 space-y-1', mc.color)}>
          <div className="flex items-center gap-2">
            {round.misconceptionTag !== 'none'
              ? <AlertTriangle size={12} />
              : <ShieldCheck size={12} />}
            <span className="text-[11px] font-bold uppercase tracking-wider">{mc.label}</span>
          </div>
          <p className="text-[11px] opacity-70 leading-relaxed">{mc.desc}</p>
        </div>

        {/* Hints */}
        {!round.isBossRound && round.wrongHint && (
          <div className="bg-amber-500/8 border border-amber-500/20 rounded-xl px-4 py-3 space-y-2">
            <div className="text-[10px] text-amber-400/60 uppercase tracking-widest">Hint Progression</div>
