              <span className="text-[10px] text-white/30">Attempt 1:</span>
              <p className="text-white/55 text-xs mt-0.5 leading-relaxed">{round.wrongHint}</p>
            </div>
            {round.wrongHint2 && (
              <div>
                <span className="text-[10px] text-white/30">Attempt 2+:</span>
                <p className="text-white/55 text-xs mt-0.5 leading-relaxed">{round.wrongHint2}</p>
              </div>
            )}
          </div>
