function MCKey() {
  const traps = ROUNDS.filter(r => r.misconceptionTag !== 'none');
  const trapsByTag = ['M1', 'M2', 'M3', 'M4'].map(tag => ({
    tag: tag as MisconceptionTag,
    meta: MC_META[tag as MisconceptionTag],
    rounds: traps.filter(r => r.misconceptionTag === tag).map(r => r.roundIndex),
  }));

  return (
    <div className="px-5 py-5 space-y-4">
      <div className="flex items-center gap-2 mb-4">
        <AlertTriangle size={14} className="text-orange-400" />
        <h2 className="text-sm font-bold text-white">Misconception Register</h2>
        <span className="ml-auto text-[10px] text-white/20">{traps.length} / {ROUNDS.length} rounds have active trap</span>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
        {trapsByTag.map(({ tag, meta, rounds: rIdxs }) => (
          <div key={tag} className={cn('border rounded-2xl px-4 py-3 space-y-2', meta.color)}>
            <div className="text-[11px] font-bold uppercase tracking-wider">{meta.label}</div>
            <p className="text-[11px] opacity-65 leading-relaxed">{meta.desc}</p>
            <div className="flex gap-1.5 flex-wrap">
              {rIdxs.length > 0
                ? rIdxs.map(i => (
                    <span key={i} className="text-[10px] font-bold px-2 py-0.5 rounded-full bg-black/20">R{i}</span>
                  ))
                : <span className="text-[10px] opacity-40">Not used this P1</span>}
            </div>
          </div>
        ))}
      </div>

      <div className="rounded-2xl border border-white/8 bg-white/[0.02] px-4 py-4 space-y-2">
        <div className="text-[10px] text-white/30 uppercase tracking-widest mb-2">P1 Spec Summary</div>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 text-center">
          {[
            { label: 'Rounds', value: `${ROUNDS.length - 1}+1`, color: 'text-white/70' },
            { label: 'M1 Traps', value: ROUNDS.filter(r => r.misconceptionTag === 'M1').length, color: 'text-rose-400' },
            { label: 'M2 / M3', value: ROUNDS.filter(r => r.misconceptionTag === 'M2' || r.misconceptionTag === 'M3').length, color: 'text-amber-400' },
