/* ─── Risk scoring ───────────────────────────────────────────────── */

function riskScore(n: QANode): number {
  let s = 0;
  if (n.auditStatus === 'qs-fail') s += 3;
  else if (n.auditStatus === 'qs-warn') s += 1;
  if (n.correctness === 'cr-fail') s += 4;
  else if (n.correctness === 'cr-warn') s += 2;
  if (n.randHealth === 'rh-fail') s += 3;
  else if (n.randHealth === 'rh-warn') s += 1;
  if (n.hintQuality === 'hq-fail') s += 2;
  else if (n.hintQuality === 'hq-warn') s += 1;
  return s;
}

function riskLabel(score: number): { label: string; color: string; bg: string } {
  if (score >= 6) return { label: 'CRITICAL', color: 'text-red-400',    bg: 'bg-red-500/20' };
  if (score >= 3) return { label: 'HIGH',     color: 'text-amber-400',  bg: 'bg-amber-500/15' };
  if (score >= 1) return { label: 'MEDIUM',   color: 'text-yellow-400', bg: 'bg-yellow-500/10' };
  return              { label: 'LOW',      color: 'text-emerald-400', bg: 'bg-emerald-500/10' };
}

