/* ─── Fetch nodes from a project ─────────────────────────────────── */

// SLS uses a different field schema (@slsf1-5) vs standard QA (@qa01-09).
// Map SLS status options → shared QANode field IDs where possible.
const SLS_STATUS_MAP: Record<string, string> = {
  pass: 'qs-pass', warn: 'qs-warn', fail: 'qs-fail', fixed: 'qs-fail', na: 'qs-pending',
};

async function fetchQANodes(gameId: string, projectId: string): Promise<QANode[]> {
  const r = await axios.get(`/api/taskade/projects/${projectId}/nodes`);
  const nodes = r.data.payload?.nodes ?? [];

  if (gameId === 'snack-line') {
    // SLS schema: @slsf1=Status, @slsf2=Severity, @slsf3=Audit Notes, @slsf4=Fix Applied, @slsf5=Category
    return nodes
      .filter((n: any) => n.fieldValues?.['/attributes/@slsf1'] || n.fieldValues?.['/attributes/@qa01'])
      .map((n: any) => {
        const rawStatus = n.fieldValues['/attributes/@slsf1'] ?? '';
        const auditStatus = SLS_STATUS_MAP[rawStatus] ?? 'qs-pending';
        const rowId = n.fieldValues['/attributes/@qa01'] ?? '';
        return {
          id: n.id,
          title: n.fieldValues['/text'] ?? '(Untitled)',
          template:    rowId.toLowerCase().replace(/^(sls-)?/, 'sls-'),
          auditStatus,
          correctness: 'cr-skip',
          skillAlign:  'sa-skip',
          randHealth:  'rh-na',
          hintQuality: 'hq-skip',
          ageBand:     'ab-skip',
          issues:      n.fieldValues['/attributes/@slsf3'] ?? '',
          fixRequired: n.fieldValues['/attributes/@slsf4'] ?? '',
          gameId,
        };
      })
      .filter((n: QANode) => n.template && n.template !== 'sls-');
  }

  // Standard QA schema
  return nodes
    .filter((n: any) => n.fieldValues?.['/attributes/@qa01'] || n.fieldValues?.['/attributes/@qa02'])
    .map((n: any) => ({
      id: n.id,
      title: n.fieldValues['/text'] ?? '(Untitled)',
      template:    n.fieldValues['/attributes/@qa01'] ?? '',
      auditStatus: n.fieldValues['/attributes/@qa02'] ?? 'qs-pending',
      correctness: n.fieldValues['/attributes/@qa03'] ?? 'cr-skip',
      skillAlign:  n.fieldValues['/attributes/@qa04'] ?? 'sa-skip',
      randHealth:  n.fieldValues['/attributes/@qa05'] ?? 'rh-na',
      hintQuality: n.fieldValues['/attributes/@qa06'] ?? 'hq-skip',
      ageBand:     n.fieldValues['/attributes/@qa07'] ?? 'ab-skip',
      issues:      n.fieldValues['/attributes/@qa08'] ?? '',
      fixRequired: n.fieldValues['/attributes/@qa09'] ?? '',
      gameId,
    }));
}

