// ─── Helper ───────────────────────────────────────────────────────────────────

function evalY(m: number, b: number, x: number): number {
  return m * x + b;
}

function typeColor(t: RoundType) {
  if (t === 'slope_intercept') return 'text-indigo-400 bg-indigo-500/10 border-indigo-500/30';
  if (t === 'negative_slope')  return 'text-amber-400 bg-amber-500/10 border-amber-500/30';
  return 'text-emerald-400 bg-emerald-500/10 border-emerald-500/30';
}

function typeLabel(t: RoundType) {
  if (t === 'slope_intercept') return 'Slope-Intercept';
  if (t === 'negative_slope')  return 'Negative Slope';
  return 'System of Equations';
}

function typeIcon(t: RoundType) {
  if (t === 'system') return <Zap size={11} />;
  if (t === 'negative_slope') return <Minus size={11} />;
  return <Grid3X3 size={11} />;
}

// ─── Coordinate Grid Component ────────────────────────────────────────────────

interface GridProps {
  round: Round;
  placed: { x: number; y: number } | null;
  onPlace: (x: number, y: number) => void;
  showAnswer: boolean;
}

function CoordGrid({ round, placed, onPlace, showAnswer }: GridProps) {
  const svgRef = useRef<SVGSVGElement>(null);
  const size = round.gridSize;
  const SVG = 340;
  const PAD = 28;
  const inner = SVG - PAD * 2;
  const step = inner / (size * 2); // pixels per unit
  const origin = { x: PAD + inner / 2, y: PAD + inner / 2 };

  // Convert grid coords → svg px
  const toSvg = (gx: number, gy: number) => ({
    px: origin.x + gx * step,
    py: origin.y - gy * step,
  });

  const handleClick = useCallback((e: React.MouseEvent<SVGSVGElement>) => {
    if (!svgRef.current) return;
    const rect = svgRef.current.getBoundingClientRect();
    const mx = e.clientX - rect.left;
    const my = e.clientY - rect.top;
    const gx = Math.round((mx - origin.x) / step);
    const gy = Math.round((origin.y - my) / step);
    if (gx < -size || gx > size || gy < -size || gy > size) return;
    onPlace(gx, gy);
  }, [origin, step, size, onPlace]);

  // Build line path for equation
  const linePath = (m: number, b: number, color: string, dash = false) => {
    const pts: string[] = [];
    for (let gx = -size; gx <= size; gx += 0.5) {
      const gy = m * gx + b;
      if (gy < -size - 0.5 || gy > size + 0.5) continue;
      const { px, py } = toSvg(gx, gy);
      pts.push(`${px},${py}`);
    }
    if (pts.length < 2) return null;
    return (
      <polyline
        key={color}
        points={pts.join(' ')}
        fill="none"
        stroke={color}
        strokeWidth={dash ? 1.5 : 2}
        strokeDasharray={dash ? '5,4' : undefined}
        opacity={0.7}
      />
    );
  };

  const gridLines: React.ReactNode[] = [];
  for (let i = -size; i <= size; i++) {
    const { px: x0 } = toSvg(i, -size);
    const { py: y0 } = toSvg(-size, i);
    gridLines.push(
      <line key={`v${i}`} x1={x0} y1={PAD} x2={x0} y2={SVG - PAD}
        stroke={i === 0 ? '#ffffff40' : '#ffffff14'} strokeWidth={i === 0 ? 1.5 : 1} />,
      <line key={`h${i}`} x1={PAD} y1={y0} x2={SVG - PAD} y2={y0}
        stroke={i === 0 ? '#ffffff40' : '#ffffff14'} strokeWidth={i === 0 ? 1.5 : 1} />,
    );
    // tick labels
    if (i !== 0 && i % 2 === 0) {
      const { px } = toSvg(i, 0);
      const { py } = toSvg(0, i);
      gridLines.push(
        <text key={`lv${i}`} x={px} y={origin.y + 14} textAnchor="middle"
          fontSize={9} fill="#ffffff33">{i}</text>,
        <text key={`lh${i}`} x={origin.x - 12} y={py + 3} textAnchor="middle"
          fontSize={9} fill="#ffffff33">{i}</text>,
      );
    }
  }

  const correctPt = toSvg(round.answer.x, round.answer.y);
  const placedPt  = placed ? toSvg(placed.x, placed.y) : null;
  const isCorrect = placed && placed.x === round.answer.x && placed.y === round.answer.y;

  return (
    <div className="relative">
      <svg
        ref={svgRef}
        width={SVG} height={SVG}
        className="cursor-crosshair rounded-xl border border-white/10 bg-[#0d0d18]"
        onClick={handleClick}
      >
        {/* Grid */}
        {gridLines}

        {/* Equation lines */}
        {round.m1 !== undefined && linePath(round.m1, round.b1!, '#818cf8', false)}
        {round.m2 !== undefined && linePath(round.m2, round.b2!, '#34d399', true)}

        {/* City dots */}
        {round.cities.map(c => {
          const { px, py } = toSvg(c.x, c.y);
          return (
            <g key={c.label}>
              <circle cx={px} cy={py} r={7} fill={c.color} opacity={0.25} />
              <circle cx={px} cy={py} r={4} fill={c.color} />
              <text x={px + 8} y={py - 5} fontSize={9} fill={c.color} fontWeight="600">
                {c.label}
              </text>
            </g>
          );
        })}

        {/* Placed tower */}
        {placedPt && (
          <g>
            <circle cx={placedPt.px} cy={placedPt.py} r={10}
              fill={isCorrect ? '#22c55e' : '#f97316'} opacity={0.2} />
            <circle cx={placedPt.px} cy={placedPt.py} r={6}
              fill={isCorrect ? '#22c55e' : '#f97316'} />
            <text x={placedPt.px} y={placedPt.py - 12}
              fontSize={8} fill={isCorrect ? '#22c55e' : '#f97316'}
              textAnchor="middle" fontWeight="700">
              ({placed!.x}, {placed!.y})
            </text>
          </g>
        )}

        {/* Answer reveal */}
        {showAnswer && !isCorrect && (
          <g>
            <circle cx={correctPt.px} cy={correctPt.py} r={10} fill="#6366f1" opacity={0.2} />
            <circle cx={correctPt.px} cy={correctPt.py} r={6} fill="#6366f1" />
            <text x={correctPt.px} y={correctPt.py - 12}
              fontSize={8} fill="#818cf8"
              textAnchor="middle" fontWeight="700">
              ({round.answer.x}, {round.answer.y})
            </text>
          </g>
        )}

        {/* Axis labels */}
        <text x={SVG - PAD + 4} y={origin.y + 4} fontSize={10} fill="#ffffff50">x</text>
        <text x={origin.x + 4} y={PAD - 6} fontSize={10} fill="#ffffff50">y</text>
      </svg>
      <p className="mt-1.5 text-center text-[10px] text-white/25">Click grid to place tower</p>
    </div>
  );
}

