// ─── Main Component ───────────────────────────────────────────────────────────

// Per-round result type
type RoundResult = 'none' | 'correct_first' | 'correct_retry' | 'wrong';

export default function SignalTower() {
  const [activeRound, setActiveRound] = useState(0);
  const [showDesignNotes, setShowDesignNotes] = useState(false);
  const [showSpec, setShowSpec] = useState(false);
  const [placed, setPlaced] = useState<{ x: number; y: number } | null>(null);
  const [showAnswer, setShowAnswer] = useState(false);

  // Per-round result tracker: records the outcome for each round id
  const [results, setResults] = useState<Record<number, RoundResult>>(() =>
    Object.fromEntries(ROUNDS.map(r => [r.id, 'none']))
  );

  // Per-round wrong attempt counter (for hint gating)
  const [wrongAttempts, setWrongAttempts] = useState<Record<number, number>>(() =>
    Object.fromEntries(ROUNDS.map(r => [r.id, 0]))
  );

  // Whether the student opened the hint after a wrong attempt on each round
  const [hintUsed, setHintUsed] = useState<Record<number, boolean>>(() =>
    Object.fromEntries(ROUNDS.map(r => [r.id, false]))
  );

  // Whether M1 nudge was triggered this round (resets on navigation)
  const [m1NudgeVisible, setM1NudgeVisible] = useState(false);

  // Whether the debrief screen has been dismissed (so student can review missions)
  const [debriefDismissed, setDebriefDismissed] = useState(false);

  // Equation input state
  const [x1Input, setX1Input] = useState('');
  const [x2Input, setX2Input] = useState('');

  // Clarity overlays
  const [showPrimer, setShowPrimer] = useState(true);          // R0 substitution primer
  const [hasSeenSystemIntro, setHasSeenSystemIntro] = useState(false); // R8 system banner

  // App mode
  const [mode, setMode] = useState<AppMode>('observer');
  const isStudent = mode === 'student';

  const toggleMode = () => {
    setMode(m => m === 'observer' ? 'student' : 'observer');
    // Reset answer reveal when entering student mode
    if (mode === 'observer') {
      setShowAnswer(false);
      setDebriefDismissed(false);
    }
  };

  const round = ROUNDS[activeRound];
  const isSystem = round.type === 'system';

  // When navigating away from a system round, mark it as seen so the intro never repeats
  const goTo = (idx: number) => {
    if (isSystem) setHasSeenSystemIntro(true);
    setActiveRound(idx);
    setPlaced(null);
    setShowAnswer(false);
    setX1Input('');
    setX2Input('');
    setM1NudgeVisible(false);
  };

  // Computed y values from inputs
  const _c1 = (x1Input !== '' && round.m1 !== undefined)
    ? evalY(round.m1, round.b1!, parseFloat(x1Input))
    : null;
  const computed1 = (_c1 !== null && !isNaN(_c1)) ? _c1 : null;

  const _c2 = (x2Input !== '' && round.m2 !== undefined)
    ? evalY(round.m2, round.b2!, parseFloat(x2Input))
    : null;
  const computed2 = (_c2 !== null && !isNaN(_c2)) ? _c2 : null;

  // Check correctness
  const isCorrect = !!(placed && placed.x === round.answer.x && placed.y === round.answer.y);

  // Hint gating: hint is unlocked after ≥1 wrong attempt (student mode) or always (observer)
  const currentWrongAttempts = wrongAttempts[round.id] ?? 0;
  const hintUnlocked = !isStudent || currentWrongAttempts >= 1 || isCorrect;

  const handlePlace = (x: number, y: number) => {
    const correct = x === round.answer.x && y === round.answer.y;
    const alreadySolved = results[round.id] === 'correct_first' || results[round.id] === 'correct_retry';

    if (alreadySolved) return;

    // ── M1 Trap Detection ──────────────────────────────────────────────────
    // Check if the placed coordinate is the exact M1 misconception answer
    const isM1Hit = !correct
      && round.m1TrapAnswer != null
      && x === round.m1TrapAnswer.x
      && y === round.m1TrapAnswer.y;

    if (isM1Hit) {
      setM1NudgeVisible(true);
    } else {
      setM1NudgeVisible(false);
    }

    // ── Result tracking ────────────────────────────────────────────────────
    setResults(prev => {
      if (correct) {
        const isFirstAttempt = placed === null && wrongAttempts[round.id] === 0;
        return { ...prev, [round.id]: isFirstAttempt ? 'correct_first' : 'correct_retry' };
      }
      return { ...prev, [round.id]: 'wrong' };
    });

    // ── Wrong attempt counter (drives hint gating) ─────────────────────────
    if (!correct) {
      setWrongAttempts(prev => ({ ...prev, [round.id]: (prev[round.id] ?? 0) + 1 }));
    }

    setPlaced({ x, y });
  };

  const reset = () => {
    setPlaced(null);
    setShowAnswer(false);
    setM1NudgeVisible(false);
    // Reset only the current round's result and attempt count
    setResults(prev => ({ ...prev, [round.id]: 'none' }));
    setWrongAttempts(prev => ({ ...prev, [round.id]: 0 }));
    setHintUsed(prev => ({ ...prev, [round.id]: false }));
  };

  const clearSession = () => {
    setResults(Object.fromEntries(ROUNDS.map(r => [r.id, 'none'])));
    setWrongAttempts(Object.fromEntries(ROUNDS.map(r => [r.id, 0])));
    setHintUsed(Object.fromEntries(ROUNDS.map(r => [r.id, false])));
    setActiveRound(0);
    setPlaced(null);
    setShowAnswer(false);
    setM1NudgeVisible(false);
    setDebriefDismissed(false);
    setX1Input('');
    setX2Input('');
  };

  const exportSession = () => {
    const now = new Date();
    const dateStr = now.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
    const timeStr = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });

    const resultLabel = (r: RoundResult) => {
      if (r === 'correct_first') return '✓  Correct — 1st try';
      if (r === 'correct_retry') return '↺  Correct — after retry';
      if (r === 'wrong')         return '✗  Incorrect / not solved';
      return '·  Not attempted';
    };

    const rate = attemptedCount > 0
      ? `${Math.round((firstTryCount / attemptedCount) * 100)}%`
      : 'N/A';
    const hintUsedCount = Object.values(hintUsed).filter(Boolean).length;

    const missedTraps = ROUNDS.filter(r => r.misconception && results[r.id] === 'wrong');

    const lines: string[] = [
      '═══════════════════════════════════════════',
      '  SIGNAL TOWER · Observer Session Report',
      '═══════════════════════════════════════════',
      `  Date : ${dateStr}`,
      `  Time : ${timeStr}`,
      `  Game : Signal Tower  (GAP-3 · 8.EE.C.8)`,
      '───────────────────────────────────────────',
      '',
      '  ROUND-BY-ROUND RESULTS',
      '  ─────────────────────',
      ...ROUNDS.map(r => {
        const res = results[r.id];
        const trap = r.misconception ? '  [M1 TRAP]' : '';
        const hint = hintUsed[r.id] ? '  [hint used]' : '';
        return `  R${String(r.id).padStart(2, '0')}  ${r.equation1.padEnd(18)}  ${resultLabel(res)}${trap}${hint}`;
      }),
      '',
      '───────────────────────────────────────────',
      '  SUMMARY',
      `  Rounds attempted : ${attemptedCount} / ${ROUNDS.length}`,
      `  Correct 1st try  : ${firstTryCount}`,
      `  Correct on retry : ${retryCount}`,
      `  Incorrect        : ${wrongCount}`,
      `  Not attempted    : ${ROUNDS.length - attemptedCount}`,
      `  First-try rate   : ${rate}`,
      `  Hints used       : ${hintUsedCount}`,
      '',
      '───────────────────────────────────────────',
    ];

    if (missedTraps.length > 0) {
      lines.push('  M1 MISCONCEPTION TRAPS MISSED');
      lines.push('  (student placed at y-intercept instead of computed point)');
      missedTraps.forEach(r => {
        lines.push(`  · R${r.id}  ${r.equation1}  —  ${r.misconceptionLabel ?? r.misconception}`);
      });
      lines.push('');
      lines.push('───────────────────────────────────────────');
    } else if (attemptedCount > 0) {
      lines.push('  M1 MISCONCEPTION TRAPS: None missed ✓');
      lines.push('───────────────────────────────────────────');
    }

    lines.push('');
    lines.push('  Signal Tower · Math Game Studio OS');
    lines.push('═══════════════════════════════════════════');

    const blob = new Blob([lines.join('\n')], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `signal-tower-session-${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, '0')}${String(now.getDate()).padStart(2, '0')}-${String(now.getHours()).padStart(2, '0')}${String(now.getMinutes()).padStart(2, '0')}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  // Summary counts
  const firstTryCount  = Object.values(results).filter(r => r === 'correct_first').length;
  const retryCount     = Object.values(results).filter(r => r === 'correct_retry').length;
  const wrongCount     = Object.values(results).filter(r => r === 'wrong').length;
  const attemptedCount = Object.values(results).filter(r => r !== 'none').length;
  const completedCount = firstTryCount + retryCount;
  const progressPercent = Math.round((completedCount / ROUNDS.length) * 100);

  // Stats
  const systemCount  = ROUNDS.filter(r => r.type === 'system').length;
  const negCount     = ROUNDS.filter(r => r.type === 'negative_slope').length;
  const trapCount    = ROUNDS.filter(r => r.misconception).length;

  return (
    <div className="flex h-full overflow-hidden bg-[#0a0a0f] text-white">

      {/* ── Left Sidebar: Round Browser ── */}
      <div className="w-64 shrink-0 border-r border-white/8 flex flex-col overflow-hidden">
        {/* Header */}
        <div className="px-4 py-3 border-b border-white/8">
          <div className="flex items-center gap-2 mb-2">
            <Radio size={14} className="text-indigo-400 shrink-0" />
            <span className="text-sm font-bold text-white">Signal Tower</span>
            {!isStudent && (
              <span className="ml-auto text-[10px] text-white/30 bg-white/5 px-1.5 py-0.5 rounded">GAP-3</span>
            )}
          </div>

          {/* Mode toggle pill */}
          <div className="flex items-center bg-white/5 rounded-lg p-0.5 border border-white/8">
            <button
              onClick={() => { if (isStudent) toggleMode(); }}
              className={cn(
                'flex-1 flex items-center justify-center gap-1.5 text-[10px] font-semibold py-1.5 rounded-md transition-all duration-200',
                !isStudent
                  ? 'bg-indigo-500/25 text-indigo-300 border border-indigo-500/30 shadow-sm'
                  : 'text-white/30 hover:text-white/60'
              )}
            >
              <Users size={10} />
              Observer
            </button>
            <button
              onClick={() => { if (!isStudent) toggleMode(); }}
              className={cn(
                'flex-1 flex items-center justify-center gap-1.5 text-[10px] font-semibold py-1.5 rounded-md transition-all duration-200',
                isStudent
                  ? 'bg-emerald-500/25 text-emerald-300 border border-emerald-500/30 shadow-sm'
                  : 'text-white/30 hover:text-white/60'
              )}
            >
              <GraduationCap size={10} />
              Student
            </button>
          </div>
        </div>

        {/* Observer-only: Stats bar */}
        {!isStudent && (
          <div className="px-3 py-2 border-b border-white/8 grid grid-cols-3 gap-1.5">
            {[
              { label: 'Systems', val: systemCount, color: 'text-emerald-400' },
              { label: 'Neg. Slope', val: negCount, color: 'text-amber-400' },
              { label: 'M1 Traps', val: trapCount, color: 'text-red-400' },
            ].map(s => (
              <div key={s.label} className="bg-white/4 rounded p-1.5 text-center">
                <div className={cn('text-base font-bold', s.color)}>{s.val}</div>
                <div className="text-[9px] text-white/30 leading-tight">{s.label}</div>
              </div>
            ))}
          </div>
        )}

        {/* Observer-only: Legend */}
        {!isStudent && (
          <div className="px-3 py-2 border-b border-white/8 space-y-1">
            {(['slope_intercept', 'negative_slope', 'system'] as RoundType[]).map(t => (
              <div key={t} className={cn('flex items-center gap-1.5 text-[10px] rounded px-1.5 py-0.5 border', typeColor(t))}>
                {typeIcon(t)}
                <span>{typeLabel(t)}</span>
              </div>
            ))}
          </div>
        )}

        {/* Student-only: Mission progress strip */}
        {isStudent && (
          <div className="px-3 py-2.5 border-b border-white/8 space-y-1.5">
            <div className="flex items-center justify-between">
              <span className="text-[10px] text-white/40 uppercase tracking-wider">Mission Progress</span>
              <span className="text-[10px] font-bold text-emerald-400">{completedCount}/{ROUNDS.length}</span>
            </div>
            <div className="w-full h-2 rounded-full bg-white/8 overflow-hidden">
              <motion.div
                className="h-full bg-gradient-to-r from-emerald-500 to-emerald-400 rounded-full"
                initial={false}
                animate={{ width: `${progressPercent}%` }}
                transition={{ duration: 0.5, ease: 'easeOut' }}
              />
            </div>
            <p className="text-[9px] text-white/25 text-right">{progressPercent}% complete</p>
          </div>
        )}

        {/* Round list */}
        <div className="flex-1 overflow-y-auto py-1">
          {ROUNDS.map(r => {
            const result = results[r.id];
            const isActive = activeRound === r.id;
            return (
              <button
                key={r.id}
                onClick={() => goTo(r.id)}
                className={cn(
                  'w-full text-left px-3 py-2 transition-all border-l-2',
                  isActive
                    ? 'bg-indigo-500/10 border-indigo-500'
                    : result === 'correct_first'
                    ? 'border-green-500/60 hover:bg-green-500/5'
                    : result === 'correct_retry'
                    ? 'border-yellow-500/50 hover:bg-yellow-500/5'
                    : result === 'wrong'
                    ? 'border-red-500/40 hover:bg-red-500/5'
                    : 'border-transparent hover:bg-white/4 hover:border-white/20',
                )}
              >
                <div className="flex items-center justify-between mb-0.5">
                  <span className={cn(
                    'text-xs font-semibold',
                    result === 'correct_first' ? 'text-green-300'
                    : result === 'correct_retry' ? 'text-yellow-300'
                    : result === 'wrong' ? 'text-red-300'
                    : 'text-white'
                  )}>
                    {isStudent
                      ? `Mission ${r.id + 1}`
                      : `R${r.id} — ${r.type === 'system' ? '⚡ System' : r.type === 'negative_slope' ? '↘ Neg' : '↗ SI'}`}
                  </span>
                  <div className="flex items-center gap-1">
                    {/* Observer-only: M1 badge */}
                    {!isStudent && r.misconception && (
                      <span className="text-[9px] text-red-400 bg-red-500/10 px-1 rounded border border-red-500/20">M1</span>
                    )}
                    {result === 'correct_first' && (
                      <span title="Correct on first try" className="flex items-center justify-center w-4 h-4 rounded-full bg-green-500/20 text-green-400">
                        <CheckCircle2 size={10} />
                      </span>
                    )}
                    {result === 'correct_retry' && (
                      <span title="Correct after retry" className="flex items-center justify-center w-4 h-4 rounded-full bg-yellow-500/20 text-yellow-400">
                        <CheckCircle2 size={10} />
                      </span>
                    )}
                    {result === 'wrong' && (
                      <span title="Incorrect / still trying" className="flex items-center justify-center w-4 h-4 rounded-full bg-red-500/20 text-red-400">
                        <XCircle size={10} />
                      </span>
                    )}
                    {result === 'none' && (
                      <span className="w-4 h-4 rounded-full border border-white/10 inline-block" />
                    )}
                  </div>
                </div>
                <p className="text-[10px] text-white/40 truncate">
                  {isStudent
                    ? r.type === 'system' ? '⚡ Two-equation challenge'
                      : r.type === 'negative_slope' ? '↘ Falling signal path'
                      : '↗ Signal path'
                    : `${r.equation1}${r.equation2 ? ` & ${r.equation2}` : ''}`}
                </p>
              </button>
            );
          })}
        </div>

        {/* Score Summary */}
        <div className="px-3 py-2.5 border-t border-white/8 space-y-2">
          {/* Header row */}
          <div className="flex items-center justify-between">
            <span className="text-[10px] uppercase tracking-widest text-white/30">
              {isStudent ? 'Towers Built' : 'Session Score'}
            </span>
            <div className="flex items-center gap-1.5">
              <span className="text-[10px] text-white/30">
                {isStudent ? `${completedCount}/${ROUNDS.length}` : `${attemptedCount}/${ROUNDS.length}`}
              </span>
              {/* Observer-only controls */}
              {!isStudent && (
                <>
                  <button
                    onClick={exportSession}
                    title="Export session report as .txt file"
                    className="flex items-center gap-1 text-[9px] text-white/30 hover:text-indigo-300 hover:bg-indigo-500/10 px-1.5 py-0.5 rounded border border-transparent hover:border-indigo-500/20 transition-all"
                  >
                    <FileDown size={9} />
                    Export
                  </button>
                  <button
                    onClick={clearSession}
                    title="Clear session — reset all rounds for a new student"
                    className="flex items-center gap-1 text-[9px] text-white/30 hover:text-red-400 hover:bg-red-500/10 px-1.5 py-0.5 rounded border border-transparent hover:border-red-500/20 transition-all"
                  >
                    <Trash2 size={9} />
                    Clear
                  </button>
                </>
              )}
            </div>
          </div>
          {/* Progress bar */}
          <div className="w-full h-2 rounded-full bg-white/8 overflow-hidden flex">
            {/* First-try correct */}
            <div
              className="h-full bg-green-500 transition-all duration-500"
              style={{ width: `${(firstTryCount / ROUNDS.length) * 100}%` }}
            />
            {/* Correct on retry */}
            <div
              className="h-full bg-yellow-500 transition-all duration-500"
              style={{ width: `${(retryCount / ROUNDS.length) * 100}%` }}
            />
            {/* Wrong / unanswered still wrong */}
            <div
              className="h-full bg-red-500/60 transition-all duration-500"
              style={{ width: `${(wrongCount / ROUNDS.length) * 100}%` }}
            />
          </div>
          {/* Legend pills */}
          <div className="flex items-center gap-2 flex-wrap">
            <div className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-green-500 inline-block" />
              <span className="text-[9px] text-white/40">1st try <strong className="text-green-400">{firstTryCount}</strong></span>
            </div>
            <div className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-yellow-500 inline-block" />
              <span className="text-[9px] text-white/40">retry <strong className="text-yellow-400">{retryCount}</strong></span>
            </div>
            <div className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-red-500/70 inline-block" />
              <span className="text-[9px] text-white/40">wrong <strong className="text-red-400">{wrongCount}</strong></span>
            </div>
          </div>
          {/* Observer-only: First-try rate */}
          {!isStudent && attemptedCount > 0 && (
            <p className="text-[10px] text-white/30 text-right">
              First-try rate:{' '}
              <span className={cn(
                'font-bold',
                firstTryCount / attemptedCount >= 0.7 ? 'text-green-400'
                : firstTryCount / attemptedCount >= 0.4 ? 'text-yellow-400'
                : 'text-red-400'
              )}>
                {Math.round((firstTryCount / attemptedCount) * 100)}%
              </span>
            </p>
          )}

          {/* Student-only: encouragement */}
          {isStudent && completedCount > 0 && completedCount < ROUNDS.length && (
            <p className="text-[9px] text-white/25 text-right italic">
              {completedCount >= 8 ? '🏁 Almost there!' : completedCount >= 4 ? '⚡ Great progress!' : '🚀 Keep going!'}
            </p>
          )}
          {isStudent && completedCount === ROUNDS.length && (
            <p className="text-[9px] text-emerald-400 text-right font-semibold">🏆 All towers built!</p>
          )}
        </div>

        {/* Observer-only: bottom buttons */}
        {!isStudent && (
          <div className="p-3 border-t border-white/8 space-y-1.5">
            <button
              onClick={() => setShowDesignNotes(v => !v)}
              className={cn(
                'w-full flex items-center gap-2 text-xs px-2.5 py-1.5 rounded border transition-all',
                showDesignNotes
                  ? 'bg-indigo-500/15 border-indigo-500/40 text-indigo-300'
                  : 'border-white/10 text-white/50 hover:text-white hover:border-white/20',
              )}
            >
              <BookOpen size={11} />
              {showDesignNotes ? 'Hide' : 'Show'} Design Notes
            </button>
            <button
              onClick={() => setShowSpec(v => !v)}
              className={cn(
                'w-full flex items-center gap-2 text-xs px-2.5 py-1.5 rounded border transition-all',
                showSpec
                  ? 'bg-purple-500/15 border-purple-500/40 text-purple-300'
                  : 'border-white/10 text-white/50 hover:text-white hover:border-white/20',
              )}
            >
              <Info size={11} />
              {showSpec ? 'Hide' : 'Show'} P1 Spec
            </button>
          </div>
        )}
      </div>

      {/* ── Main Panel ── */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Top bar */}
        <div className={cn(
          'px-6 py-3 border-b border-white/8 flex items-center gap-4',
          isStudent && 'bg-gradient-to-r from-emerald-500/5 to-transparent'
        )}>
          <button onClick={() => goTo(Math.max(0, activeRound - 1))} disabled={activeRound === 0}
            className="text-white/40 hover:text-white disabled:opacity-20 transition-colors">
            <ChevronLeft size={16} />
          </button>

          {isStudent ? (
            /* Student: clean mission title */
            <div className="flex items-center gap-3">
              <div>
                <div className="flex items-center gap-2">
                  <span className="text-sm font-bold text-white">Mission {activeRound + 1}</span>
                  <span className="text-[10px] text-white/30">of {ROUNDS.length}</span>
                </div>
                <p className="text-[10px] text-white/40 leading-tight">
                  {round.type === 'system' ? 'Two-equation challenge' : 'Place the signal tower'}
                </p>
              </div>
              {isCorrect && (
                <motion.span
                  initial={{ scale: 0, opacity: 0 }}
                  animate={{ scale: 1, opacity: 1 }}
                  className="flex items-center gap-1 text-[10px] text-emerald-400 bg-emerald-500/15 px-2 py-0.5 rounded-full border border-emerald-500/25"
                >
                  <CheckCircle2 size={10} /> Tower built!
                </motion.span>
              )}
            </div>
          ) : (
            /* Observer: full technical header */
            <>
              <span className="text-sm font-bold text-white">{round.title}</span>
              <span className={cn('text-[10px] font-medium px-2 py-0.5 rounded-full border flex items-center gap-1', typeColor(round.type))}>
                {typeIcon(round.type)} {typeLabel(round.type)}
              </span>
              {round.misconception && (
                <span className="flex items-center gap-1 text-[10px] text-red-400 bg-red-500/10 px-2 py-0.5 rounded-full border border-red-500/20">
                  <AlertTriangle size={10} /> M1 Trap
                </span>
              )}
            </>
          )}

          <div className="ml-auto flex items-center gap-2">
            {/* Observer-only: Reveal Answer */}
            {!isStudent && (
              <button onClick={() => setShowAnswer(v => !v)}
                className={cn('flex items-center gap-1.5 text-xs px-2.5 py-1.5 rounded border transition-all',
                  showAnswer
                    ? 'bg-purple-500/15 border-purple-500/40 text-purple-300'
                    : 'border-white/10 text-white/50 hover:text-white hover:border-white/20')}>
                {showAnswer ? <EyeOff size={11} /> : <Eye size={11} />}
                {showAnswer ? 'Hide' : 'Reveal'} Answer
              </button>
            )}
            <button onClick={reset}
              className="flex items-center gap-1.5 text-xs px-2.5 py-1.5 rounded border border-white/10 text-white/50 hover:text-white transition-colors">
              <RotateCcw size={11} /> Reset
            </button>
            <button onClick={() => goTo(Math.min(11, activeRound + 1))} disabled={activeRound === 11}
              className="text-white/40 hover:text-white disabled:opacity-20 transition-colors">
              <ChevronRight size={16} />
            </button>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto relative">

          {/* ── Debrief Screen (student mode, all missions complete) ── */}
          <AnimatePresence>
            {isStudent && completedCount === ROUNDS.length && !debriefDismissed && (
              <motion.div
                key="debrief"
                initial={{ opacity: 0, scale: 0.97 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0 }}
                transition={{ duration: 0.35, ease: 'easeOut' }}
                className="absolute inset-0 z-20 overflow-y-auto bg-[#0a0a0f] flex items-start justify-center p-8"
              >
                <div className="w-full max-w-xl space-y-5">
                  {/* Hero */}
                  <div className="text-center space-y-3">
                    <motion.div
                      initial={{ scale: 0, rotate: -10 }}
                      animate={{ scale: 1, rotate: 0 }}
                      transition={{ delay: 0.15, type: 'spring', stiffness: 200, damping: 14 }}
                      className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-gradient-to-br from-emerald-500/30 to-emerald-500/10 border border-emerald-500/30 mx-auto"
                    >
                      <Trophy size={28} className="text-emerald-400" />
                    </motion.div>
                    <motion.h2
                      initial={{ opacity: 0, y: 8 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ delay: 0.25 }}
                      className="text-2xl font-bold text-white"
                    >
                      Signal Network Complete!
                    </motion.h2>
                    <motion.p
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      transition={{ delay: 0.35 }}
                      className="text-sm text-white/50"
                    >
                      All {ROUNDS.length} towers placed — cities are connected.
                    </motion.p>
                  </div>

                  {/* Stats grid */}
                  <motion.div
                    initial={{ opacity: 0, y: 12 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.4 }}
                    className="grid grid-cols-2 gap-3"
                  >
                    {[
                      {
                        label: 'First Try',
                        value: firstTryCount,
                        sub: `of ${ROUNDS.length} missions`,
                        color: 'text-emerald-400',
                        bg: 'bg-emerald-500/8 border-emerald-500/20',
                      },
                      {
                        label: 'After Retry',
                        value: retryCount,
                        sub: retryCount === 0 ? 'flawless run!' : 'needed another look',
                        color: 'text-yellow-400',
                        bg: 'bg-yellow-500/8 border-yellow-500/20',
                      },
                      {
                        label: 'Hints Used',
                        value: Object.values(hintUsed).filter(Boolean).length,
                        sub: 'step-by-step helps',
                        color: 'text-blue-400',
                        bg: 'bg-blue-500/8 border-blue-500/20',
                      },
                      {
                        label: 'Accuracy',
                        value: `${Math.round((firstTryCount / ROUNDS.length) * 100)}%`,
                        sub: 'first-try rate',
                        color: firstTryCount / ROUNDS.length >= 0.7 ? 'text-emerald-400'
                          : firstTryCount / ROUNDS.length >= 0.4 ? 'text-yellow-400'
                          : 'text-red-400',
                        bg: 'bg-white/4 border-white/8',
                      },
                    ].map((stat, i) => (
                      <motion.div
                        key={stat.label}
                        initial={{ opacity: 0, y: 8 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: 0.45 + i * 0.07 }}
                        className={cn('rounded-xl border p-4', stat.bg)}
                      >
                        <div className={cn('text-2xl font-bold', stat.color)}>{stat.value}</div>
                        <div className="text-xs font-semibold text-white/70 mt-0.5">{stat.label}</div>
                        <div className="text-[10px] text-white/30 mt-0.5">{stat.sub}</div>
                      </motion.div>
                    ))}
                  </motion.div>

                  {/* Round-by-round recap */}
                  <motion.div
                    initial={{ opacity: 0, y: 12 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.6 }}
                    className="rounded-xl border border-white/8 bg-white/3 overflow-hidden"
                  >
                    <div className="px-4 py-2.5 border-b border-white/8 flex items-center justify-between">
