/* ─────────────────────────────────────────────────────────────────────────────
   TYPES
───────────────────────────────────────────────────────────────────────────── */

type MisconceptionTag = 'M1' | 'M2' | 'M3';
// M1 — repeated addition instead of multiplicative thinking (e.g., 9+5 instead of 9×5)
// M2 — treating division as repeated subtraction instead of partitioning
// M3 — remainder blindness: floor-dividing when ceiling is needed (or ignoring leftover trucks)

type Block = 'intro' | 'multiply' | 'divide' | 'multi-step';
type GamePhase = 'idle' | 'playing' | 'dispatched' | 'wrong' | 'complete';

interface Zone {
  id: string;
  name: string;
  emoji: string;
  severity: 'minor' | 'serious' | 'critical';
  trucksPerUnit: number;
  units: number;
  answer: number;
  prompt: string;
  // For divide rounds: the total pool being split (so equation reveal reads totalPool ÷ trucksPerUnit = answer)
  totalPool?: number;
  // If true this is a remainder scenario; leftover shows in equation reveal
  hasRemainder?: boolean;
  remainder?: number;
}

interface Round {
  roundIndex: number;
  block: Block;
  misconceptionTag: MisconceptionTag | null;
  totalTrucks: number;
  zones: Zone[];
  truckGauge: number;          // correct trucks to dispatch
  wrongHint: string;           // shown after FIRST wrong attempt — never reveals answer
  wrongHint2?: string;         // shown after SECOND+ wrong attempt — a step deeper, still no answer
  designNote: string;
  isBossRound?: boolean;       // hint suppressed for boss round
  stepLabel?: string;          // e.g. "Multi-step · Step 1 then Step 2" — shown in HUD
}

