function misconPill(tag: MisconceptionTag | null) {
  if (!tag) return <span className="flex items-center gap-1 text-[10px] text-white/25"><ShieldCheck size={9} /> Clean</span>;
  const colors: Record<MisconceptionTag, string> = {
    M1: 'bg-orange-500/15 border-orange-500/25 text-orange-400',
