function LevelBrowser() {
  const [filter, setFilter] = useState<'all' | Block>('all');
  const filtered = filter === 'all' ? ROUNDS : ROUNDS.filter(r => r.block === filter);

  return (
    <div className="space-y-4 px-4 py-5 max-w-2xl mx-auto w-full">
      <div className="flex items-center gap-2 flex-wrap">
        {(['all', 'intro', 'multiply', 'divide', 'multi-step'] as const).map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            className={cn(
              'px-3 py-1 rounded-lg text-xs font-semibold transition-all capitalize',
              filter === f ? 'bg-white/12 text-white' : 'text-white/35 hover:text-white/60'
            )}
          >
            {f === 'all' ? 'All' : BLOCK_META[f as Block].label}
          </button>
        ))}
        <span className="ml-auto text-[10px] text-white/25">{filtered.length} rounds</span>
      </div>

      {/* Misconception key */}
      <div className="grid grid-cols-3 gap-2">
        {([
          { tag: 'M1', desc: 'Repeated addition (adds instead of multiplies)', color: 'text-orange-400' },
          { tag: 'M2', desc: 'Subtraction approach to division', color: 'text-pink-400' },
          { tag: 'M3', desc: 'Remainder blindness (ignores leftover)', color: 'text-purple-400' },
        ]).map(m => (
          <div key={m.tag} className="bg-white/3 border border-white/8 rounded-xl px-3 py-2">
            <div className={cn('text-[11px] font-bold mb-0.5', m.color)}>{m.tag}</div>
            <div className="text-[10px] text-white/35 leading-snug">{m.desc}</div>
          </div>
        ))}
      </div>

      {filtered.map(r => (
        <RoundBrowserRow key={r.roundIndex} round={r} />
      ))}
    </div>
  );
}

function RoundBrowserRow({ round }: { round: Round }) {
  const [open, setOpen] = useState(false);
  const [showAnswer, setShowAnswer] = useState(false);
  const zone = round.zones[0];

  return (
    <div className="rounded-2xl border border-white/8 bg-white/[0.025] overflow-hidden">
      <button
        onClick={() => setOpen(o => !o)}
        className="w-full flex items-center gap-3 px-4 py-3 hover:bg-white/[0.03] transition-colors text-left"
      >
        <div className="w-8 h-8 rounded-xl bg-white/8 border border-white/10 flex items-center justify-center text-xs font-bold text-white/60">
          R{round.roundIndex + 1}
        </div>
        {blockPill(round.block)}
        {misconPill(round.misconceptionTag)}
        <div className="flex-1 min-w-0 hidden sm:block">
          <span className="text-white/40 text-[11px] truncate">{zone.name} — {zone.prompt.slice(0, 50)}…</span>
        </div>
        {open ? <ChevronUp size={13} className="text-white/30 flex-shrink-0" /> : <ChevronDown size={13} className="text-white/30 flex-shrink-0" />}
      </button>

      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.18 }}
            className="overflow-hidden border-t border-white/5"
          >
            <div className="px-4 py-4 space-y-4">
              {/* Zone detail */}
              <div className="grid grid-cols-2 gap-3">
                <div className="bg-white/4 border border-white/8 rounded-xl p-3 space-y-1">
                  <div className="text-[10px] text-white/30">Zone</div>
                  <div className="text-sm font-semibold text-white">{zone.emoji} {zone.name}</div>
                  <div className="text-[11px] text-white/50 capitalize">{zone.severity} severity</div>
                </div>
                <div className="bg-white/4 border border-white/8 rounded-xl p-3 space-y-1">
                  <div className="text-[10px] text-white/30">Fleet</div>
                  <div className="text-sm font-semibold text-white">{round.totalTrucks} trucks</div>
                  <div className="text-[11px] text-white/50">{zone.trucksPerUnit}/unit × {zone.units} units</div>
                </div>
              </div>

              {/* Prompt */}
              <div className="bg-black/20 border border-white/8 rounded-xl px-4 py-3">
                <div className="text-[10px] text-white/25 uppercase tracking-wider mb-1">Player prompt</div>
                <p className="text-white/70 text-[12px] leading-relaxed">{zone.prompt}</p>
              </div>

              {/* Answer reveal */}
              <div className="flex items-center gap-3">
                <button
                  onClick={() => setShowAnswer(a => !a)}
                  className={cn(
                    'flex items-center gap-1.5 text-[11px] px-3 py-1.5 rounded-lg border transition-all',
                    showAnswer
                      ? 'bg-indigo-500/20 border-indigo-500/30 text-indigo-300'
                      : 'bg-white/5 border-white/10 text-white/35 hover:text-white/60'
                  )}
                >
                  {showAnswer ? <EyeOff size={11} /> : <Eye size={11} />}
                  {showAnswer ? 'Hide answer' : 'Reveal answer'}
                </button>

                {showAnswer && (
                  <motion.div
                    initial={{ opacity: 0, x: -8 }}
                    animate={{ opacity: 1, x: 0 }}
                    className="flex items-center gap-2 flex-wrap"
                  >
                    {round.block === 'divide' ? (
                      <span className="font-mono text-white font-bold">
                        {zone.totalPool ?? round.totalTrucks} ÷ {zone.trucksPerUnit} = <span className="text-emerald-400">{zone.answer}</span>
                        {zone.hasRemainder && zone.remainder !== undefined && zone.remainder > 0 && (
                          <span className="text-white/40 text-sm font-normal"> r{zone.remainder}</span>
                        )}
                      </span>
                    ) : (
                      <span className="font-mono text-white font-bold">
                        {zone.trucksPerUnit} × {zone.units} = <span className="text-emerald-400">{zone.answer}</span>
                      </span>
                    )}
                    <span className="text-[10px] text-white/25">trucks to dispatch</span>
                  </motion.div>
                )}
              </div>

              {/* Hints */}
              <div className="bg-red-500/8 border border-red-500/20 rounded-xl px-4 py-3 space-y-2.5">
                <div className="text-[10px] text-red-400/70 uppercase tracking-widest">
                  {round.isBossRound ? 'Boss round — hints suppressed' : 'Wrong-attempt hints'}
                </div>
                {!round.isBossRound && (
                  <>
                    <div>
                      <div className="text-[9px] text-white/25 mb-0.5">Attempt 1</div>
                      <p className="text-white/55 text-[12px] italic">"{round.wrongHint}"</p>
                    </div>
                    {round.wrongHint2 && (
                      <div>
                        <div className="text-[9px] text-white/25 mb-0.5">Attempt 2+ (deeper scaffold)</div>
                        <p className="text-white/55 text-[12px] italic">"{round.wrongHint2}"</p>
                      </div>
                    )}
                    <p className="text-white/25 text-[10px]">No answer given · Directs thinking · Targets misconception</p>
                  </>
                )}
                {round.isBossRound && (
                  <p className="text-white/35 text-[11px]">Final zone: student must apply all skills independently. No hint shown.</p>
                )}
              </div>

              {/* Design note */}
              <div className="bg-white/3 border border-white/8 rounded-xl px-4 py-3 space-y-1">
                <div className="text-[10px] text-white/25 uppercase tracking-widest">Design note</div>
                <p className="text-white/45 text-[11px] leading-relaxed">{round.designNote}</p>
                {round.stepLabel && (
                  <p className="text-[10px] text-rose-400/60">Step indicator: {round.stepLabel}</p>
                )}
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

