              tab === t.id
                ? 'border-red-500 text-white bg-white/[0.04]'
                : 'border-transparent text-white/35 hover:text-white/60 hover:bg-white/[0.02]'
            )}
          >
            <span className="text-xs font-semibold">{t.label}</span>
            <span className="text-[10px] text-white/25">{t.sub}</span>
          </button>
        ))}

        <div className="ml-auto flex items-center gap-2 pb-2.5">
          <span className="text-[10px] text-white/20">P1 · Grade 3–5 · CCSS.3.OA · ×÷ fluency</span>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto">
        <AnimatePresence mode="wait">
          <motion.div
            key={tab}
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -8 }}
            transition={{ duration: 0.18 }}
            className="h-full"
          >
            {tab === 'play' && <GameScreen />}
            {tab === 'browser' && <LevelBrowser />}
          </motion.div>
        </AnimatePresence>
      </div>
    </div>
  );
}

import * as React from 'react';
import { useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { cn } from '@/lib/utils';
import { ChevronLeft, ChevronRight, RotateCcw, Eye, EyeOff, ArrowUp, ArrowDown, ArrowLeft, ArrowRight, Flower2, Frog } from 'lucide-react';

// ─── Types ────────────────────────────────────────────────────────────────────

type Dir = 'U' | 'D' | 'L' | 'R';
type TileType = 'grass' | 'puddle' | 'flower' | 'start';
type Misconception = 'M1' | 'M2' | 'M3' | 'M4' | 'none';

interface Cell {
  row: number;
  col: number;
  type: TileType;
}

interface LevelRound {
  id: string;          // R0–R11
  label: string;
  gridSize: number;    // 4, 5, 6, or 8
  stepLimit: number;
  isTrap: boolean;     // M1 repeated-step trap?
  misconception: Misconception;
  grid: Cell[][];      // pre-defined layout
  solution: Dir[];     // correct arrow sequence
  designNotes: string;
  ccss: string;
}

// ─── Level Definitions ─────────────────────────────────────────────────────

function buildGrid(size: number, puddles: [number, number][], flower: [number, number]): Cell[][] {
  return Array.from({ length: size }, (_, r) =>
    Array.from({ length: size }, (_, c) => {
      if (r === 0 && c === 0) return { row: r, col: c, type: 'start' as TileType };
      if (r === flower[0] && c === flower[1]) return { row: r, col: c, type: 'flower' as TileType };
      if (puddles.some(([pr, pc]) => pr === r && pc === c)) return { row: r, col: c, type: 'puddle' as TileType };
      return { row: r, col: c, type: 'grass' as TileType };
    })
  );
}

