];

// ─── Helpers ───────────────────────────────────────────────────────────────

const MISCONCEPTION_META: Record<Misconception, { label: string; color: string; short: string }> = {
  M1: { label: 'M1 · Repeated-Step', color: 'text-rose-400 bg-rose-400/10 border-rose-400/20', short: 'Repeated' },
  M2: { label: 'M2 · Diagonal Counting', color: 'text-amber-400 bg-amber-400/10 border-amber-400/20', short: 'Diagonal' },
  M3: { label: 'M3 · No-Backtrack', color: 'text-purple-400 bg-purple-400/10 border-purple-400/20', short: 'No-Back' },
  M4: { label: 'M4 · Off-by-One', color: 'text-cyan-400 bg-cyan-400/10 border-cyan-400/20', short: 'Off-by-1' },
  none: { label: '—', color: 'text-white/20 bg-white/5 border-white/10', short: '—' },
};

function dirIcon(d: Dir) {
  switch (d) {
    case 'U': return <ArrowUp size={10} />;
    case 'D': return <ArrowDown size={10} />;
    case 'L': return <ArrowLeft size={10} />;
    case 'R': return <ArrowRight size={10} />;
  }
}

function simulate(grid: Cell[][], solution: Dir[]): [number, number][] {
  const path: [number, number][] = [[0, 0]];
  let r = 0, c = 0;
  for (const d of solution) {
    if (d === 'U') r--;
    if (d === 'D') r++;
    if (d === 'L') c--;
    if (d === 'R') c++;
    path.push([r, c]);
  }
  return path;
}

// ─── Sub-components ────────────────────────────────────────────────────────

function TileCell({ cell, isOnPath, isFrog, showSolution }: {
  cell: Cell; isOnPath: boolean; isFrog: boolean; showSolution: boolean;
}) {
  const baseClass = 'relative flex items-center justify-center rounded-md transition-all duration-150 select-none';
  const bgClass =
    cell.type === 'puddle' ? 'bg-blue-900/70 border border-blue-400/30' :
    cell.type === 'flower' ? 'bg-emerald-900/50 border border-emerald-400/40' :
    cell.type === 'start'  ? 'bg-indigo-900/40 border border-indigo-400/30' :
    'bg-white/4 border border-white/6';
  const pathClass = showSolution && isOnPath && cell.type !== 'puddle'
    ? 'ring-1 ring-indigo-400/50 bg-indigo-900/30'
    : '';

  return (
    <div className={cn(baseClass, bgClass, pathClass, 'aspect-square')}>
      {cell.type === 'puddle' && (
        <span className="text-blue-300 select-none" style={{ fontSize: '60%' }}>💧</span>
      )}
      {cell.type === 'flower' && (
        <Flower2 size={12} className="text-emerald-400" />
      )}
      {isFrog && showSolution && (
        <motion.span
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          className="absolute inset-0 flex items-center justify-center text-xs"
        >
          🐸
        </motion.span>
      )}
    </div>
  );
}

function LevelGrid({ round, showSolution, step }: { round: LevelRound; showSolution: boolean; step: number }) {
  const path = showSolution ? simulate(round.grid, round.solution) : [];
  const frogPos = showSolution && path.length > 0 ? path[Math.min(step, path.length - 1)] : [0, 0];
  const pathSet = new Set(path.slice(0, step + 1).map(([r, c]) => `${r},${c}`));

  const cellSize = round.gridSize <= 4 ? 52 : round.gridSize <= 5 ? 44 : round.gridSize <= 6 ? 36 : 26;

  return (
    <div
      className="grid gap-1 mx-auto"
      style={{
        gridTemplateColumns: `repeat(${round.gridSize}, ${cellSize}px)`,
        gridTemplateRows: `repeat(${round.gridSize}, ${cellSize}px)`,
        width: 'fit-content',
      }}
    >
      {round.grid.flat().map(cell => (
        <TileCell
          key={`${cell.row}-${cell.col}`}
          cell={cell}
          isOnPath={pathSet.has(`${cell.row},${cell.col}`)}
          isFrog={showSolution && frogPos[0] === cell.row && frogPos[1] === cell.col}
          showSolution={showSolution}
        />
      ))}
    </div>
  );
}

function SolutionArrows({ solution, step, showSolution }: { solution: Dir[]; step: number; showSolution: boolean }) {
  return (
    <div className="flex flex-wrap gap-1 mt-3">
      {solution.map((d, i) => (
        <motion.div
          key={i}
          initial={{ opacity: 0, scale: 0.7 }}
          animate={{ opacity: showSolution ? 1 : 0.15, scale: 1 }}
          transition={{ delay: i * 0.04 }}
          className={cn(
            'w-6 h-6 rounded-md flex items-center justify-center border text-[10px] font-bold transition-all duration-200',
            showSolution && i < step
              ? 'bg-indigo-500/80 border-indigo-400/60 text-white'
              : showSolution
              ? 'bg-white/5 border-white/10 text-white/50'
              : 'bg-white/3 border-white/5 text-white/15'
          )}
        >
          {dirIcon(d)}
        </motion.div>
      ))}
    </div>
  );
}

// ─── Main Component ────────────────────────────────────────────────────────

type FilterType = 'all' | 'trap' | 'clean';

export default function PuddlePatrol() {
