              {/* Core info */}
              <InfoBlock label="Grid">
                {selected.gridSize}×{selected.gridSize} ({selected.gridSize * selected.gridSize} tiles)
              </InfoBlock>
              <InfoBlock label="Step Limit">{selected.stepLimit} arrows</InfoBlock>
              <InfoBlock label="Solution Length">{selected.solution.length} moves</InfoBlock>
              <InfoBlock label="Standard">{selected.ccss}</InfoBlock>
              <InfoBlock label="Misconception Probe">{mc.label}</InfoBlock>
              <InfoBlock label="Trap Round">{selected.isTrap ? '✅ Yes — M1 repeated-step' : 'No'}</InfoBlock>
              <InfoBlock label="Arrow Sequence">
                <div className="flex flex-wrap gap-0.5 mt-1">
                  {selected.solution.map((d, i) => (
                    <span key={i} className="font-mono text-[9px] bg-white/5 border border-white/8 px-1 py-0.5 rounded text-white/60">
                      {d}
                    </span>
                  ))}
                </div>
              </InfoBlock>

              {/* Observer note — toggled */}
              <AnimatePresence>
                {showNotes && (
                  <motion.div
                    initial={{ opacity: 0, height: 0 }}
                    animate={{ opacity: 1, height: 'auto' }}
                    exit={{ opacity: 0, height: 0 }}
                  >
                    <div className="rounded-lg border border-amber-400/20 bg-amber-400/5 p-3">
                      <div className="text-[9px] text-amber-400/70 uppercase tracking-wider mb-1 font-semibold">Observer Note</div>
                      <p className="text-[10px] text-amber-100/70 leading-relaxed">{selected.designNotes}</p>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>
            </div>

            {/* P1 Spec Summary */}
            <div className="border-t border-white/5 p-4 space-y-2">
              <div className="text-[9px] text-white/25 uppercase tracking-wider mb-2">P1 Spec</div>
              <SpecRow label="Age range" value="K–2 (ages 5–8)" />
              <SpecRow label="Session" value="5–10 min per round" />
              <SpecRow label="Mechanic" value="Drag arrows → frog walks" />
              <SpecRow label="Win condition" value="Reach flower in step limit" />
              <SpecRow label="Fail state" value="Hit puddle or exceed steps" />
              <SpecRow label="Fantasy" value="'You are the garden guide'" />
              <SpecRow label="Gates" value="8 (K-1 spec)" />
              <SpecRow label="CC" value="CCSS K.G.A.1" />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Utility sub-components ────────────────────────────────────────────────

function StatPill({ label, value, color }: { label: string; value: string; color: string }) {
  return (
    <div className="flex flex-col items-center bg-white/5 border border-white/8 rounded-lg px-3 py-1.5">
      <span className={cn('text-sm font-bold leading-none', color)}>{value}</span>
      <span className="text-[9px] text-white/30 mt-0.5">{label}</span>
    </div>
  );
}

function InfoBlock({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div>
      <div className="text-[9px] text-white/30 uppercase tracking-wider mb-0.5">{label}</div>
      <div className="text-xs text-white/70">{children}</div>
    </div>
