}

import * as React from 'react';
import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, BookOpen, Filter } from 'lucide-react';
import { cn } from '@/lib/utils';
import type { CurriculumNode } from '@/App';
import axios from 'axios';

const CURRICULUM_ID = 'fQKsxPJWgG2kPRoQ';

const GRADE_BANDS = [
  { id: 'gb-k2',  label: 'K–2',  color: '#f97316' },
  { id: 'gb-35',  label: '3–5',  color: '#eab308' },
  { id: 'gb-68',  label: '6–8',  color: '#22c55e' },
  { id: 'gb-912', label: '9–12', color: '#3b82f6' },
];

const SUBJECTS = [
  { id: 'subj-math', label: 'Mathematics',         emoji: '🔢', color: '#6366f1' },
  { id: 'subj-ela',  label: 'English / ELA',       emoji: '📖', color: '#ec4899' },
  { id: 'subj-sci',  label: 'Science',             emoji: '🔬', color: '#14b8a6' },
  { id: 'subj-ss',   label: 'Social Studies',      emoji: '🌍', color: '#f59e0b' },
  { id: 'subj-cs',   label: 'Coding / CS',         emoji: '💻', color: '#8b5cf6' },
  { id: 'subj-fin',  label: 'Financial Literacy',  emoji: '💰', color: '#10b981' },
];

const STATUS_CONFIG: Record<string, { label: string; dot: string; badge: string }> = {
  'st-open':       { label: 'Open Slot',    dot: 'bg-white/15',   badge: 'bg-white/5 text-white/30 border-white/10' },
  'st-brainstorm': { label: 'Brainstorm',   dot: 'bg-amber-400',  badge: 'bg-amber-500/10 text-amber-300 border-amber-500/20' },
  'st-pipeline':   { label: 'In Pipeline',  dot: 'bg-purple-400', badge: 'bg-purple-500/10 text-purple-300 border-purple-500/20' },
  'st-approved':   { label: 'Approved',     dot: 'bg-green-400',  badge: 'bg-green-500/10 text-green-300 border-green-500/20' },
  'st-building':   { label: 'Building',     dot: 'bg-blue-400',   badge: 'bg-blue-500/10 text-blue-300 border-blue-500/20' },
  'st-done':       { label: 'Complete',     dot: 'bg-emerald-400',badge: 'bg-emerald-500/10 text-emerald-300 border-emerald-500/20' },
};

interface CurriculumMapProps {
  nodes: CurriculumNode[];
  onRefresh: () => void;
}

export default function CurriculumMap({ nodes, onRefresh }: CurriculumMapProps) {
  const [selected, setSelected] = useState<CurriculumNode | null>(null);
  const [filterSubject, setFilterSubject] = useState<string>('all');

  const filteredNodes = filterSubject === 'all' ? nodes : nodes.filter(n => n.subject === filterSubject);

  const openCount = nodes.filter(n => n.status === 'st-open' || !n.status).length;
  const approvedCount = nodes.filter(n => n.status === 'st-approved' || n.status === 'st-done').length;
  const inProgressCount = nodes.filter(n => ['st-brainstorm', 'st-pipeline', 'st-building'].includes(n.status)).length;

  return (
    <div className="flex flex-col h-full overflow-hidden">
      {/* Stats + filter */}
      <div className="px-5 pt-4 pb-3 border-b border-white/5 flex items-center gap-3 flex-wrap">
        <div className="flex items-center gap-2 text-xs">
          <span className="text-white/30">Open:</span>
          <span className="text-white/60 font-medium">{openCount}</span>
          <span className="text-white/10">·</span>
          <span className="text-white/30">Active:</span>
          <span className="text-amber-400 font-medium">{inProgressCount}</span>
          <span className="text-white/10">·</span>
          <span className="text-white/30">Done:</span>
          <span className="text-green-400 font-medium">{approvedCount}</span>
        </div>

        <div className="ml-auto flex items-center gap-1.5">
          <Filter size={11} className="text-white/30" />
          <button
            onClick={() => setFilterSubject('all')}
            className={cn('px-2.5 py-1 rounded-lg text-xs transition-all', filterSubject === 'all' ? 'bg-white/10 text-white' : 'text-white/30 hover:text-white/60')}
          >
            All
          </button>
          {SUBJECTS.map(s => (
            <button
              key={s.id}
              onClick={() => setFilterSubject(filterSubject === s.id ? 'all' : s.id)}
              className={cn('px-2.5 py-1 rounded-lg text-xs transition-all', filterSubject === s.id ? 'text-white' : 'text-white/30 hover:text-white/60')}
              style={filterSubject === s.id ? { backgroundColor: s.color + '25', color: s.color } : {}}
            >
              {s.emoji} <span className="hidden sm:inline">{s.label}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Grid */}
      <div className="flex-1 overflow-auto p-5">
        <div className="grid gap-5">
          {/* Grade band rows */}
          {GRADE_BANDS.map(band => {
            const bandNodes = filteredNodes.filter(n => n.gradeBand === band.id);
            if (bandNodes.length === 0 && filterSubject !== 'all') return null;
            return (
              <motion.div
                key={band.id}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="bg-white/[0.02] border border-white/5 rounded-2xl overflow-hidden"
              >
                {/* Band header */}
                <div
                  className="flex items-center gap-3 px-4 py-3 border-b border-white/5"
                  style={{ background: `linear-gradient(135deg, ${band.color}10, transparent)` }}
                >
                  <div className="w-8 h-8 rounded-lg flex items-center justify-center font-bold text-sm" style={{ backgroundColor: band.color + '20', color: band.color }}>
                    {band.label}
                  </div>
                  <div>
                    <div className="text-sm font-semibold text-white">Grade {band.label}</div>
                    <div className="text-[10px] text-white/30">{bandNodes.length} skill slot{bandNodes.length !== 1 ? 's' : ''}</div>
                  </div>
                  {/* Coverage bar */}
                  <div className="ml-auto flex items-center gap-2">
                    <div className="w-24 h-1.5 bg-white/5 rounded-full overflow-hidden">
                      {bandNodes.length > 0 && (
                        <motion.div
                          initial={{ width: 0 }}
                          animate={{ width: `${Math.round((bandNodes.filter(n => n.status === 'st-done' || n.status === 'st-approved').length / bandNodes.length) * 100)}%` }}
                          className="h-full rounded-full"
                          style={{ backgroundColor: band.color }}
                        />
                      )}
                    </div>
                    <span className="text-[10px] text-white/30">
                      {bandNodes.length > 0 ? Math.round((bandNodes.filter(n => n.status === 'st-done' || n.status === 'st-approved').length / bandNodes.length) * 100) : 0}%
                    </span>
                  </div>
                </div>

                {/* Skill cards */}
                <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-2 p-3">
                  {bandNodes.map(node => {
                    const subj = SUBJECTS.find(s => s.id === node.subject);
                    const status = STATUS_CONFIG[node.status] ?? STATUS_CONFIG['st-open'];
                    return (
                      <motion.button
                        key={node.id}
                        whileHover={{ scale: 1.02 }}
                        whileTap={{ scale: 0.98 }}
                        onClick={() => setSelected(node)}
                        className="text-left bg-white/[0.03] hover:bg-white/[0.06] border border-white/[0.05] hover:border-white/10 rounded-xl p-3 transition-all"
                      >
                        <div className="flex items-center gap-1.5 mb-1.5">
                          <span className="text-sm">{subj?.emoji ?? '📋'}</span>
                          <span className={cn('w-1.5 h-1.5 rounded-full flex-shrink-0', status.dot)} />
                        </div>
                        <p className="text-xs font-medium text-white/70 line-clamp-2 leading-snug mb-1">{node.title}</p>
                        {node.linkedGame && (
                          <p className="text-[10px] text-white/30 truncate">↗ {node.linkedGame}</p>
                        )}
                      </motion.button>
                    );
                  })}

                  {/* Open slot placeholder if no entries for a subject in this band */}
                  {bandNodes.length === 0 && (
                    <div className="border border-dashed border-white/5 rounded-xl p-3 text-[10px] text-white/20 flex items-center justify-center col-span-2">
                      No slots in this band for current filter
                    </div>
                  )}
                </div>
              </motion.div>
            );
          })}
        </div>
      </div>

      {/* Detail drawer */}
      <AnimatePresence>
        {selected && <CurriculumDrawer node={selected} onClose={() => setSelected(null)} onRefresh={onRefresh} />}
      </AnimatePresence>
    </div>
  );
}

function CurriculumDrawer({ node, onClose, onRefresh }: { node: CurriculumNode; onClose: () => void; onRefresh: () => void }) {
  const [status, setStatus] = useState(node.status);
  const [saving, setSaving] = useState(false);
  const subj = SUBJECTS.find(s => s.id === node.subject);
  const band = GRADE_BANDS.find(b => b.id === node.gradeBand);

  const handleSave = async () => {
    setSaving(true);
    try {
      await axios.patch(`/api/taskade/projects/${CURRICULUM_ID}/nodes/${node.id}`, {
        '/attributes/@cm04': status,
      });
      await onRefresh();
      onClose();
    } catch (e) {
      console.error(e);
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 bg-black/60 backdrop-blur-sm z-40" onClick={onClose} />
      <motion.div
        initial={{ x: '100%' }} animate={{ x: 0 }} exit={{ x: '100%' }}
        transition={{ type: 'spring', damping: 28, stiffness: 300 }}
        className="fixed right-0 top-0 bottom-0 w-full max-w-sm bg-[#0f0f1a] border-l border-white/10 z-50 overflow-y-auto"
      >
        <div className="p-5">
          <div className="flex items-start justify-between mb-5">
            <div className="flex items-center gap-2">
              <BookOpen size={15} className="text-green-400" />
              <span className="text-xs text-green-400 font-medium uppercase tracking-wider">Curriculum Slot</span>
            </div>
            <button onClick={onClose} className="w-7 h-7 rounded-lg bg-white/5 hover:bg-white/10 flex items-center justify-center text-white/40 hover:text-white transition-all"><X size={14} /></button>
          </div>

          <div className="flex items-center gap-2 mb-3">
            <span className="text-2xl">{subj?.emoji}</span>
            <div>
              <div className="text-xs text-white/40">{subj?.label} · {band?.label}</div>
              <h2 className="text-base font-semibold text-white leading-snug">{node.title}</h2>
            </div>
          </div>

          {node.coreSkill && <InfoRow label="Core Skill" value={node.coreSkill} />}
          {node.standard && <InfoRow label="Learning Standard" value={node.standard} />}
          {node.linkedGame && <InfoRow label="Linked Game" value={node.linkedGame} />}

          <div className="mt-4">
            <label className="text-[10px] text-white/30 uppercase tracking-wider mb-1.5 block">Status</label>
            <select
              value={status}
              onChange={e => setStatus(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-xs text-white focus:outline-none focus:border-green-500/50"
            >
              {Object.entries(STATUS_CONFIG).map(([k, v]) => (
                <option key={k} value={k}>{v.label}</option>
              ))}
            </select>
          </div>

          <button onClick={handleSave} disabled={saving} className="w-full mt-4 py-2.5 rounded-xl bg-green-600 hover:bg-green-500 disabled:opacity-50 text-sm font-medium text-white transition-all">
            {saving ? 'Saving...' : 'Save Changes'}
          </button>
        </div>
      </motion.div>
    </>
  );
}

function InfoRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="mb-3">
      <div className="text-[10px] text-white/30 uppercase tracking-wider mb-0.5">{label}</div>
      <div className="text-xs text-white/65">{value}</div>
    </div>
  );
}

import * as React from 'react';
import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, ChevronRight, Gamepad2, Star, AlertCircle, CheckCircle, Clock, XCircle } from 'lucide-react';
import { cn } from '@/lib/utils';
import type { PipelineNode } from '@/App';
import axios from 'axios';

const PIPELINE_ID = 'LnpYq2qGt5DrXpda';

const STAGES = [
  { id: 'stage-idea', label: 'Idea', color: '#6366f1', short: 'IDEA' },
  { id: 'stage-spec', label: 'GX Spec', color: '#8b5cf6', short: 'SPEC' },
  { id: 'stage-precheck', label: 'Pre-Check', color: '#f59e0b', short: 'PRE' },
  { id: 'stage-delight', label: 'Delight Gate', color: '#ec4899', short: 'DLT' },
  { id: 'stage-design', label: 'Design Checks', color: '#14b8a6', short: 'DES' },
  { id: 'stage-overlap', label: 'Overlap Review', color: '#f97316', short: 'OVR' },
  { id: 'stage-gono', label: 'GO / NO-GO', color: '#22c55e', short: 'G/NG' },
  { id: 'stage-p1', label: 'P1 Core Loop', color: '#0ea5e9', short: 'P1' },
  { id: 'stage-p2a', label: 'P2A Feedback', color: '#0284c7', short: 'P2A' },
  { id: 'stage-p2b', label: 'P2B Progress', color: '#0369a1', short: 'P2B' },
  { id: 'stage-p3', label: 'P3 UI Polish', color: '#7c3aed', short: 'P3' },
  { id: 'stage-p4', label: 'P4 Juice', color: '#db2777', short: 'P4' },
  { id: 'stage-p5', label: 'Release', color: '#16a34a', short: 'P5' },
];

const GONO_CONFIG: Record<string, { label: string; icon: React.ReactNode; cls: string }> = {
  'gono-go':     { label: 'GO',      icon: <CheckCircle size={11} />, cls: 'bg-green-500/15 text-green-400 border-green-500/30' },
  'gono-nogo':   { label: 'NO-GO',   icon: <XCircle size={11} />,     cls: 'bg-red-500/15 text-red-400 border-red-500/30' },
  'gono-revise': { label: 'Revise',  icon: <AlertCircle size={11} />, cls: 'bg-amber-500/15 text-amber-400 border-amber-500/30' },
  'gono-pause':  { label: 'Pause',   icon: <Clock size={11} />,       cls: 'bg-slate-500/15 text-slate-400 border-slate-500/30' },
  'gono-pending':{ label: 'Pending', icon: <Clock size={11} />,       cls: 'bg-white/5 text-white/30 border-white/10' },
};

const DG_CONFIG: Record<string, { label: string; dot: string }> = {
  'dg-pass':    { label: 'Pass',    dot: 'bg-green-400' },
  'dg-fail':    { label: 'Fail',    dot: 'bg-red-400' },
  'dg-pending': { label: 'Pending', dot: 'bg-white/20' },
};

interface PipelineBoardProps {
  nodes: PipelineNode[];
  onRefresh: () => void;
}

export default function PipelineBoard({ nodes, onRefresh }: PipelineBoardProps) {
  const [selected, setSelected] = useState<PipelineNode | null>(null);
  const [newConceptTitle, setNewConceptTitle] = useState('');
  const [adding, setAdding] = useState(false);

  const byStage = STAGES.map(s => ({
    ...s,
    cards: nodes.filter(n => n.stage === s.id),
  }));

  const totalGo = nodes.filter(n => n.goNoGo === 'gono-go').length;
  const totalNoGo = nodes.filter(n => n.goNoGo === 'gono-nogo').length;
  const totalBuilding = nodes.filter(n => n.stage.startsWith('stage-p')).length;
  const delightPass = nodes.filter(n => n.delightGate === 'dg-pass').length;

  const handleAddConcept = async () => {
    if (!newConceptTitle.trim()) return;
    setAdding(true);
    try {
      await axios.post(`/api/taskade/projects/${PIPELINE_ID}/nodes`, {
        '/text': newConceptTitle.trim(),
        '/attributes/@gcf04': 'stage-idea',
        '/attributes/@gcf05': 'gono-pending',
        '/attributes/@gcf06': 'dg-pending',
      });
      setNewConceptTitle('');
      await onRefresh();
    } catch (e) {
      console.error(e);
    } finally {
      setAdding(false);
    }
  };

  return (
    <div className="flex flex-col h-full">
      {/* Stats bar */}
      <div className="px-5 pt-4 pb-3 border-b border-white/5">
        <div className="flex items-center gap-3 flex-wrap">
          <StatPill label="Total Concepts" value={nodes.length} color="indigo" />
          <StatPill label="GO" value={totalGo} color="green" />
          <StatPill label="NO-GO" value={totalNoGo} color="red" />
          <StatPill label="In Build" value={totalBuilding} color="blue" />
          <StatPill label="Delight Pass" value={delightPass} color="pink" />
          <div className="ml-auto flex items-center gap-2">
            <input
              type="text"
              value={newConceptTitle}
              onChange={e => setNewConceptTitle(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && handleAddConcept()}
              placeholder="+ New concept..."
              className="bg-white/5 border border-white/10 rounded-lg px-3 py-1.5 text-xs text-white placeholder:text-white/25 focus:outline-none focus:border-indigo-500/50 w-48"
            />
            <button
              onClick={handleAddConcept}
              disabled={adding || !newConceptTitle.trim()}
              className="px-3 py-1.5 rounded-lg bg-indigo-600 hover:bg-indigo-500 disabled:opacity-40 text-xs font-medium text-white transition-all"
            >
              {adding ? '...' : 'Add'}
            </button>
          </div>
        </div>
      </div>

      {/* Board */}
      <div className="flex-1 overflow-x-auto overflow-y-hidden">
        <div className="flex gap-3 p-4 h-full min-w-max">
          {byStage.map(stage => (
            <div key={stage.id} className="w-56 flex flex-col gap-2">
              {/* Column header */}
              <div className="flex items-center gap-2 px-2 py-1.5">
                <div className="w-2 h-2 rounded-full flex-shrink-0" style={{ backgroundColor: stage.color }} />
                <span className="text-xs font-semibold text-white/60 truncate">{stage.label}</span>
                <span className="ml-auto text-[10px] text-white/30 bg-white/5 px-1.5 py-0.5 rounded-md font-mono">
                  {stage.cards.length}
                </span>
              </div>

              {/* Cards */}
              <div className="flex flex-col gap-2 flex-1 overflow-y-auto pr-1">
                <AnimatePresence>
                  {stage.cards.map(card => (
                    <motion.div
                      key={card.id}
                      layout
                      initial={{ opacity: 0, scale: 0.95 }}
                      animate={{ opacity: 1, scale: 1 }}
                      exit={{ opacity: 0, scale: 0.95 }}
                      whileHover={{ y: -2 }}
                      onClick={() => setSelected(card)}
                      className="bg-white/[0.04] hover:bg-white/[0.07] border border-white/[0.06] hover:border-white/10 rounded-xl p-3 cursor-pointer transition-all group"
                    >
                      <div className="flex items-start gap-2 mb-2">
                        <div
                          className="w-1 self-stretch rounded-full flex-shrink-0"
                          style={{ backgroundColor: stage.color + '80' }}
                        />
                        <p className="text-xs font-medium text-white/80 leading-snug line-clamp-2 flex-1 group-hover:text-white transition-colors">
                          {card.title}
                        </p>
                      </div>

                      <div className="flex items-center gap-1.5 flex-wrap">
                        {card.goNoGo && GONO_CONFIG[card.goNoGo] && (
                          <span className={cn(
                            'flex items-center gap-1 px-1.5 py-0.5 rounded-md text-[10px] font-semibold border',
                            GONO_CONFIG[card.goNoGo].cls
                          )}>
                            {GONO_CONFIG[card.goNoGo].icon}
                            {GONO_CONFIG[card.goNoGo].label}
                          </span>
                        )}
                        {card.delightGate && DG_CONFIG[card.delightGate] && (
                          <span className="flex items-center gap-1 text-[10px] text-white/30">
                            <span className={cn('w-1.5 h-1.5 rounded-full', DG_CONFIG[card.delightGate].dot)} />
                            {DG_CONFIG[card.delightGate].label}
                          </span>
                        )}
                      </div>

                      {card.mathSkill && (
                        <div className="mt-2 text-[10px] text-white/25 truncate">{card.mathSkill}</div>
                      )}
                    </motion.div>
                  ))}
                </AnimatePresence>

                {stage.cards.length === 0 && (
