];

const DEV_STATUS: Record<string, { label: string; cls: string }> = {
  'ds-spec':    { label: 'Spec Ready', cls: 'bg-slate-500/15 text-slate-300 border-slate-500/20' },
  'ds-wip':     { label: 'In Dev',     cls: 'bg-amber-500/15 text-amber-300 border-amber-500/20' },
