  'ds-shipped': { label: 'Shipped',    cls: 'bg-green-500/15 text-green-300 border-green-500/20' },
};

const phaseProgress = (id: string) => {
  const idx = BUILD_PHASES.findIndex(p => p.id === id);
  return idx < 0 ? 0 : Math.round(((idx + 1) / BUILD_PHASES.length) * 100);
};

