/* ─── Types ──────────────────────────────────────────────────────── */

interface MLNode {
  id: string;
  title: string;
  game: string;          // @ml01 option id
  errorCategory: string; // @ml02 option id
  description: string;   // @ml03
  failureSignal: string; // @ml04
  designResponse: string;// @ml05
  status: string;        // @ml06 option id
  futureApplies: string; // @ml07
}

/* ─── Fetch ──────────────────────────────────────────────────────── */

async function fetchMLNodes(): Promise<MLNode[]> {
  const r = await axios.get(`/api/taskade/projects/${ML_PROJECT_ID}/nodes`);
  return (r.data.payload?.nodes ?? [])
    .filter((n: any) => n.fieldValues?.['/attributes/@ml01'] || n.fieldValues?.['/attributes/@ml02'])
    .map((n: any) => ({
      id: n.id,
      title: n.fieldValues['/text'] ?? '(Untitled)',
      game:           n.fieldValues['/attributes/@ml01'] ?? '',
      errorCategory:  n.fieldValues['/attributes/@ml02'] ?? '',
      description:    n.fieldValues['/attributes/@ml03'] ?? '',
      failureSignal:  n.fieldValues['/attributes/@ml04'] ?? '',
      designResponse: n.fieldValues['/attributes/@ml05'] ?? '',
      status:         n.fieldValues['/attributes/@ml06'] ?? '',
      futureApplies:  n.fieldValues['/attributes/@ml07'] ?? '',
    }));
}

