export default function MisconceptionLibrary() {
  const [nodes, setNodes] = useState<MLNode[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [refreshing, setRefreshing] = useState(false);
  const [selected, setSelected] = useState<MLNode | null>(null);

  /* Filters */
  const [search, setSearch] = useState('');
  const [gameFilter, setGameFilter] = useState('');
  const [catFilter, setCatFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');

  const load = useCallback(async () => {
    setError(null);
    try {
      const data = await fetchMLNodes();
      setNodes(data);
    } catch (e: any) {
      setError(e?.message ?? 'Failed to load');
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useEffect(() => { load(); }, [load]);

  const handleRefresh = () => { setRefreshing(true); load(); };

  /* Filtered list */
  const filtered = useMemo(() => {
    const q = search.toLowerCase();
    return nodes.filter(n => {
      if (gameFilter && n.game !== gameFilter) return false;
      if (catFilter && n.errorCategory !== catFilter) return false;
      if (statusFilter && n.status !== statusFilter) return false;
      if (q) {
        const haystack = [n.title, n.description, n.failureSignal, n.designResponse, n.futureApplies].join(' ').toLowerCase();
        if (!haystack.includes(q)) return false;
      }
      return true;
    });
  }, [nodes, search, gameFilter, catFilter, statusFilter]);

  /* Group by game */
  const grouped = useMemo(() => {
    const map = new Map<string, MLNode[]>();
    for (const n of filtered) {
      const key = n.game || 'unknown';
      if (!map.has(key)) map.set(key, []);
      map.get(key)!.push(n);
    }
    return map;
  }, [filtered]);

  /* Stats */
  const totalEntries = nodes.length;
  const gamesCount = new Set(nodes.map(n => n.game)).size;
  const criticalCount = nodes.filter(n => ['ec-proc', 'ec-concept'].includes(n.errorCategory)).length;
  const newCount = nodes.filter(n => n.status === 'ls-new' || n.status === 'ls-pending').length;

  const clearFilters = () => { setSearch(''); setGameFilter(''); setCatFilter(''); setStatusFilter(''); };
  const hasFilters = search || gameFilter || catFilter || statusFilter;

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full min-h-[60vh]">
        <div className="flex flex-col items-center gap-4">
          <motion.div
            className="w-10 h-10 border-2 border-t-violet-400 border-white/10 rounded-full"
            animate={{ rotate: 360 }}
            transition={{ duration: 1, repeat: Infinity, ease: 'linear' }}
          />
          <p className="text-white/30 text-sm">Loading misconception library…</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center justify-center h-full min-h-[60vh]">
        <div className="text-center space-y-3">
          <Brain size={36} className="text-red-400 mx-auto" />
          <p className="text-red-300 text-sm">{error}</p>
          <button onClick={handleRefresh} className="px-4 py-2 bg-white/10 hover:bg-white/15 rounded-lg text-xs text-white transition-all">
            Retry
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-full overflow-hidden">

      {/* ── Left: browse panel ── */}
      <div className="flex-1 flex flex-col overflow-hidden min-w-0">

        {/* Header */}
        <div className="px-5 py-4 border-b border-white/5 shrink-0 space-y-4">
          <div className="flex items-center justify-between gap-4">
            <div>
              <div className="flex items-center gap-2.5 mb-0.5">
                <Brain size={18} className="text-violet-400" />
                <h1 className="text-base font-bold text-white">Misconception Library</h1>
                <a
                  href={`https://www.taskade.com/d/${ML_PROJECT_ID}`}
