            <SummaryCard label="Games Covered"  value={gamesCount}   color="text-blue-400"   emoji="🎮" />
            <SummaryCard label="Proc + Concept" value={criticalCount} color="text-amber-400" emoji="⚠️" />
            <SummaryCard label="New / Pending"  value={newCount}     color="text-purple-400" emoji="🔮" />
