**Insert:**
```js
// PC2 — labeled action feedback overlays
let actionFeedbacks = []; // [{msg, color, y, alpha, timer, duration}]
function showActionFeedback(msg, color, duration) {
  actionFeedbacks.push({ msg, color, y: H/2 - 80, alpha: 1, timer: 0, duration: duration || 1.4 });
}
function updateActionFeedbacks(dt) {
  for (let i = actionFeedbacks.length - 1; i >= 0; i--) {
    const f = actionFeedbacks[i];
    f.timer += dt;
    f.y -= 28 * dt;
    f.alpha = Math.max(0, 1 - f.timer / f.duration);
    if (f.timer >= f.duration) actionFeedbacks.splice(i, 1);
  }
}
function drawActionFeedbacks() {
  ctx.save();
  for (const f of actionFeedbacks) {
    ctx.globalAlpha = f.alpha;
    ctx.fillStyle = f.color;
    ctx.font = 'bold 15px monospace';
    ctx.textAlign = 'center';
    ctx.fillText(f.msg, W / 2, f.y);
  }
  ctx.globalAlpha = 1;
  ctx.restore();
}
```

