// Canvas is sized in initUI() called from main.js after all scripts load
const canvas = document.getElementById('game');
const ctx = canvas.getContext('2d');

function initUI(){
  canvas.width = W;
  canvas.height = H;
}

// ── Tile renderer ────────────────────────────────
function drawTile(col, row, tileId){
  const x = col * TILE, y = row * TILE;
  const color = COLORS[tileId] || COLORS[T.FLOOR];
  ctx.fillStyle = color;
  ctx.fillRect(x, y, TILE, TILE);

  // Tile detail
  switch(tileId){
    case T.WALL:
      ctx.fillStyle = 'rgba(255,255,255,0.04)';
      ctx.fillRect(x+2, y+2, TILE-4, 3);
      break;
    case T.TERMINAL:
      // Blue glow screen
      ctx.fillStyle = '#0d2137';
      ctx.fillRect(x, y, TILE, TILE);
      ctx.fillStyle = '#00e5ff';
      ctx.font = 'bold 14px monospace';
      ctx.textAlign = 'center';
      ctx.fillText('🖥', x+TILE/2, y+TILE/2+5);
      ctx.textAlign = 'left';
      break;
    case T.LOOT:
      ctx.fillStyle = '#2a2a1a';
      ctx.fillRect(x, y, TILE, TILE);
      ctx.font = '20px sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('💎', x+TILE/2, y+TILE/2+7);
      ctx.textAlign = 'left';
      break;
    case T.EXIT:
      ctx.fillStyle = '#0f3d1a';
      ctx.fillRect(x, y, TILE, TILE);
      ctx.strokeStyle = '#22c55e';
      ctx.lineWidth = 2;
      ctx.strokeRect(x+3, y+3, TILE-6, TILE-6);
      ctx.fillStyle = '#22c55e';
      ctx.font = 'bold 10px monospace';
      ctx.textAlign = 'center';
      ctx.fillText('EXIT', x+TILE/2, y+TILE/2+4);
      ctx.textAlign = 'left';
      break;
    case T.DOOR_LOCKED:
      ctx.fillStyle = '#8b4513';
      ctx.fillRect(x, y, TILE, TILE);
      ctx.fillStyle = '#ffd700';
      ctx.font = '16px sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('🔒', x+TILE/2, y+TILE/2+6);
      ctx.textAlign = 'left';
      break;
    case T.DOOR_OPEN:
      ctx.fillStyle = '#3a2a1a';
      ctx.fillRect(x, y, TILE, TILE);
      break;
    case T.CARPET:
      // Subtle pattern
      ctx.fillStyle = 'rgba(34,197,94,0.06)';
      for(let cx = x; cx < x+TILE; cx+=8){
        ctx.fillRect(cx, y, 4, TILE);
      }
      break;
    case T.METAL:
      // Metallic sheen
      ctx.fillStyle = 'rgba(255,255,255,0.05)';
      for(let ry = y; ry < y+TILE; ry+=6){
        ctx.fillRect(x, ry, TILE, 2);
      }
      break;
    case T.VENT:
      ctx.fillStyle = 'rgba(148,163,184,0.08)';
      ctx.fillRect(x+4, y+4, TILE-8, TILE-8);
      ctx.strokeStyle = 'rgba(148,163,184,0.2)';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(x, y+TILE/2); ctx.lineTo(x+TILE, y+TILE/2);
      ctx.moveTo(x+TILE/2, y); ctx.lineTo(x+TILE/2, y+TILE);
      ctx.stroke();
      break;
    case T.SPAWN:
      ctx.fillStyle = '#1a1f2e';
      ctx.fillRect(x, y, TILE, TILE);
      ctx.strokeStyle = 'rgba(0,229,255,0.2)';
      ctx.lineWidth = 1;
      ctx.strokeRect(x+4, y+4, TILE-8, TILE-8);
      break;
  }
}

// ── Draw grid ────────────────────────────────────
function drawGrid(){
  const grid = G.level.grid;
  for(let r = 0; r < 16; r++){
    for(let c = 0; c < 24; c++){
      drawTile(c, r, grid[r][c]);
    }
  }

  // Open doors
  (G.doors || []).forEach(d => {
    if(d.open) drawTile(d.col, d.row, T.DOOR_OPEN);
  });

  // Subtle grid lines
  ctx.strokeStyle = 'rgba(255,255,255,0.025)';
  ctx.lineWidth = 0.5;
  for(let c = 0; c <= 24; c++){
    ctx.beginPath(); ctx.moveTo(c*TILE, 0); ctx.lineTo(c*TILE, H); ctx.stroke();
  }
  for(let r = 0; r <= 16; r++){
    ctx.beginPath(); ctx.moveTo(0, r*TILE); ctx.lineTo(W, r*TILE); ctx.stroke();
  }
}

// ── Draw cameras ──────────────────────────────────
function drawCameras(){
  for(const cam of G.cameras){
    const { x, y, currentAngle, sweep, disabled } = cam;
    const halfSweep = sweep * DEG / 2;
    const range = 180;

    if(!disabled){
      // Cone
      ctx.save();
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.arc(x, y, range, currentAngle - halfSweep, currentAngle + halfSweep);
      ctx.closePath();
      ctx.fillStyle = COLORS.cameraCone;
      ctx.fill();
      ctx.restore();
    }

    // Body
    ctx.beginPath();
    ctx.arc(x, y, 7, 0, Math.PI * 2);
    ctx.fillStyle = disabled ? '#444' : COLORS.cameraBody;
    ctx.fill();
    ctx.strokeStyle = disabled ? '#333' : '#aa8800';
    ctx.lineWidth = 1.5;
    ctx.stroke();
  }
}

// ── Draw guards ───────────────────────────────────
function drawGuards(){
  for(const guard of G.guards){
    const { x, y, coneAngle, coneSweep, coneRange, state } = guard;

    // Vision cone
    ctx.save();
    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.arc(x, y, coneRange, coneAngle - coneSweep/2, coneAngle + coneSweep/2);
    ctx.closePath();
    const coneColor = state === 'chase' ? 'rgba(255,68,68,0.18)' :
                      state === 'alert' ? 'rgba(255,136,0,0.15)' : COLORS.guardCone;
    ctx.fillStyle = coneColor;
    ctx.fill();
    ctx.restore();

    // Body
    ctx.beginPath();
    ctx.arc(x, y, 12, 0, Math.PI * 2);
    ctx.fillStyle = state === 'chase' ? '#ff2222' :
                    state === 'alert' ? COLORS.guardAlert : COLORS.guard;
    ctx.fill();
    ctx.strokeStyle = 'rgba(255,255,255,0.15)';
    ctx.lineWidth = 1;
    ctx.stroke();

    // State icon
    if(state === 'chase' || state === 'alert'){
      ctx.font = 'bold 12px sans-serif';
      ctx.textAlign = 'center';
      ctx.fillStyle = '#fff';
      ctx.fillText(state === 'chase' ? '!' : '?', x, y - 16);
      ctx.textAlign = 'left';
    }
  }
}

// ── Draw echo ghosts ──────────────────────────────
function drawEchoGhosts(){
  for(const ghost of G.echoGhosts){
    ctx.beginPath();
    ctx.arc(ghost.x, ghost.y, 10, 0, Math.PI*2);
    ctx.fillStyle = COLORS.ghost;
    ctx.fill();
  }

  // Recording trail
  if(G.echoRecording && G.echoPath.length > 1){
    ctx.save();
    ctx.strokeStyle = 'rgba(0,229,255,0.4)';
    ctx.lineWidth = 2;
    ctx.setLineDash([4,4]);
    ctx.beginPath();
    ctx.moveTo(G.echoPath[0].x, G.echoPath[0].y);
    G.echoPath.forEach(p => ctx.lineTo(p.x, p.y));
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.restore();
  }
}

// ── Draw gadget ───────────────────────────────────
function drawGadget(){
  if(!G.gadget) return;
  const { x, y, phase } = G.gadget;
  ctx.font = '16px sans-serif';
  ctx.textAlign = 'center';
  ctx.fillText(phase === 'active' ? '📢' : '📦', x, y + 6);
  ctx.textAlign = 'left';

  if(phase === 'active'){
    const r = 80 + Math.sin(Date.now() * 0.01) * 20;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI*2);
    ctx.strokeStyle = 'rgba(245,158,11,0.3)';
    ctx.lineWidth = 2;
    ctx.stroke();
  }
}

// ── Draw player ───────────────────────────────────
function drawPlayer(){
  const { px, py, pAngle, crouching, cls } = G;
  const radius = crouching ? 8 : 12;

  // Glow
  const grad = ctx.createRadialGradient(px, py, 0, px, py, radius * 2.5);
  grad.addColorStop(0, cls.color + '40');
  grad.addColorStop(1, 'transparent');
  ctx.beginPath();
  ctx.arc(px, py, radius * 2.5, 0, Math.PI*2);
  ctx.fillStyle = grad;
  ctx.fill();

  // Body
  ctx.beginPath();
  ctx.arc(px, py, radius, 0, Math.PI*2);
  ctx.fillStyle = cls.color;
  ctx.fill();
  ctx.strokeStyle = 'rgba(255,255,255,0.3)';
  ctx.lineWidth = 1.5;
  ctx.stroke();

  // Direction indicator
  ctx.beginPath();
  ctx.moveTo(px, py);
  ctx.lineTo(px + Math.cos(pAngle)*radius*1.6, py + Math.sin(pAngle)*radius*1.6);
  ctx.strokeStyle = '#fff';
  ctx.lineWidth = 2;
  ctx.stroke();

  // Crouching indicator
  if(crouching){
    ctx.fillStyle = 'rgba(0,229,255,0.5)';
    ctx.font = '10px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('▼', px, py - 18);
    ctx.textAlign = 'left';
  }

  // [E] interact prompt
  const pt = playerTile();
  const neighbors = [[pt.col-1,pt.row],[pt.col+1,pt.row],[pt.col,pt.row-1],[pt.col,pt.row+1]];
  for(const [c,r] of neighbors){
    const tile = tileAt(c, r);
    if(tile === T.TERMINAL || tile === T.LOOT){
      ctx.fillStyle = 'rgba(0,229,255,0.9)';
      ctx.font = 'bold 11px monospace';
      ctx.textAlign = 'center';
      ctx.fillText('[E]', px, py - 24);
      ctx.textAlign = 'left';
      break;
    }
  }
}

// ── HUD ───────────────────────────────────────────
const HUD_H = 44;

function drawHUD(){
  // Top bar
  ctx.fillStyle = COLORS.hud + 'ee';
  ctx.fillRect(0, 0, W, HUD_H);
  ctx.strokeStyle = 'rgba(255,255,255,0.06)';
  ctx.lineWidth = 1;
  ctx.beginPath(); ctx.moveTo(0,HUD_H); ctx.lineTo(W,HUD_H); ctx.stroke();

  const cls = G.cls;

  // Class
  ctx.fillStyle = cls.color;
  ctx.font = 'bold 12px monospace';
  ctx.fillText(`${cls.icon} ${cls.name}`, 12, 28);

  // Mission name
  ctx.fillStyle = COLORS.hudText;
  ctx.font = '11px monospace';
  ctx.fillText(G.mission.name, 120, 28);

  // District badge
  const distNames = ['D1','D2','D3'];
  const distColors = ['#22c55e','#f59e0b','#ef4444'];
  const dist = getDistrict(G.missionId);
  ctx.fillStyle = distColors[dist] + '30';
  ctx.fillRect(260, 8, 30, 20);
  ctx.fillStyle = distColors[dist];
  ctx.font = 'bold 10px monospace';
  ctx.fillText(distNames[dist], 265, 22);

  // MATH counter
  ctx.fillStyle = COLORS.hudAccent;
  ctx.font = '10px monospace';
  ctx.fillText(`MATH ${G.mathCorrect}/${G.mathAttempts}`, 305, 22);

  // Timer
  const timeLeft = Math.max(0, G.missionTimeLimit - G.missionTimer);
  const timerColor = timeLeft < 30 ? '#ef4444' : COLORS.hudText;
  ctx.fillStyle = timerColor;
  ctx.font = 'bold 13px monospace';
  ctx.textAlign = 'right';
