  drawBottomHUD();
}

function drawBottomHUD(){
  const by = H - 44;
  ctx.fillStyle = COLORS.hud + 'ee';
  ctx.fillRect(0, by, W, 44);
  ctx.strokeStyle = 'rgba(255,255,255,0.06)';
  ctx.lineWidth = 1;
  ctx.beginPath(); ctx.moveTo(0,by); ctx.lineTo(W,by); ctx.stroke();

  const barsY = by + 10;

  // HEAT bar
  drawBar(12, barsY, 100, 10, G.heat, 100, COLORS.heat, 'HEAT');
  // NOISE bar
  drawBar(12, barsY + 16, 100, 10, G.noise, 100, COLORS.noise, 'NOISE');

  // Ability
  const abilX = 140;
  ctx.fillStyle = COLORS.hudText;
  ctx.font = '10px monospace';
  if(G.abilityCooldown > 0){
    ctx.fillStyle = '#64748b';
    ctx.fillText(`[Space] ${G.cls.abilityName} (${Math.ceil(G.abilityCooldown)}s)`, abilX, by+16);
  } else if(G.abilityActive){
    ctx.fillStyle = G.cls.color;
    ctx.fillText(`${G.cls.abilityName} ✓ ACTIVE (${Math.ceil(G.abilityTimeLeft)}s)`, abilX, by+16);
  } else {
    ctx.fillStyle = G.cls.color;
    ctx.fillText(`[Space] ${G.cls.abilityName} READY`, abilX, by+16);
  }

  // Gadget
  ctx.fillStyle = G.gadgetPlaced ? '#64748b' : '#94a3b8';
  ctx.font = '10px monospace';
  ctx.fillText(`[Q] Gadget ${G.gadgetPlaced ? (G.noiseMakerActive ? 'NOISE ●' : 'placed') : 'ready'}`, abilX, by+30);

  // Echo
  ctx.fillStyle = G.echoRecording ? '#ef4444' : '#94a3b8';
  ctx.fillText(`[R] ECHO ${G.echoRecording ? '● REC' : G.echoGhosts.length > 0 ? '▶ REPLAY' : `×${G.echoCharges}`}`, abilX + 200, by+16);

  // Focus
  ctx.fillStyle = G.focusMode ? '#a855f7' : '#64748b';
  ctx.fillText(`[Tab] Focus ${G.focusMode ? 'ON' : 'OFF'}`, abilX + 200, by+30);
}

function drawBar(x, y, w, h, val, max, color, label){
  const pct = Math.max(0, Math.min(1, val / max));
  ctx.fillStyle = 'rgba(255,255,255,0.05)';
  ctx.fillRect(x, y, w, h);
  ctx.fillStyle = color;
  ctx.fillRect(x, y, w * pct, h);
  ctx.fillStyle = COLORS.hudText;
  ctx.font = '9px monospace';
  ctx.fillText(label, x + w + 5, y + h - 1);
}

function formatTime(s){
  const m = Math.floor(s/60);
  const sec = Math.floor(s%60);
  return `${m}:${String(sec).padStart(2,'0')}`;
}

// ── Vault warning (PATCH -08b) ────────────────────
function drawVaultWarning(){
  if(!G.vaultActive) return;
  const remaining = G.vaultTimeLimit - G.vaultTimer;
  if(remaining > 15) return;

  // Pulsing amber banner
  const alpha = 0.5 + 0.4 * Math.sin(Date.now() * 0.006 * Math.PI);
  ctx.fillStyle = `rgba(245,158,11,${alpha * 0.25})`;
  ctx.fillRect(0, HUD_H, W, 30);
  ctx.fillStyle = `rgba(245,158,11,${alpha})`;
  ctx.font = 'bold 13px monospace';
  ctx.textAlign = 'center';
  ctx.fillText(`⚠ VAULT TIMER: ${Math.ceil(remaining)}s REMAINING`, W/2, HUD_H+20);
  ctx.textAlign = 'left';

  // Enlarged red timer in center
  ctx.fillStyle = '#ef4444';
  ctx.font = `bold 36px monospace`;
  ctx.textAlign = 'center';
  ctx.fillText(Math.ceil(remaining), W/2, H/2 - 30);
  ctx.textAlign = 'left';

  // Screen flash at 2 Hz
  const flashOn = Math.floor(Date.now() / 500) % 2 === 0;
  if(flashOn){
    ctx.fillStyle = 'rgba(239,68,68,0.06)';
    ctx.fillRect(0, 0, W, H);
  }
}

