  }

  ctx.textAlign = 'left';
}

// ── Interact prompt near loot ─────────────────────
function drawInteractPrompts(){
  if(!G.lootCollected && !G.vaultActive){
    const loot = G.level.loot;
    const lx = (loot.col+0.5)*TILE, ly = (loot.row+0.5)*TILE;
    const d = Math.hypot(G.px-lx, G.py-ly);
    if(d < TILE*2){
      ctx.fillStyle = '#ffd700';
      ctx.font = 'bold 11px monospace';
      ctx.textAlign = 'center';
      ctx.fillText('Walk into the 💎 to begin Vault', lx, ly - 28);
      ctx.textAlign = 'left';
    }
  }
  if(G.lootCollected && !G.escaped){
    const exit = G.level.exit;
    const ex = (exit.col+0.5)*TILE, ey = (exit.row+0.5)*TILE;
    const d = Math.hypot(G.px-ex, G.py-ey);
    if(d < TILE*3){
      ctx.fillStyle = '#22c55e';
      ctx.font = 'bold 11px monospace';
      ctx.textAlign = 'center';
      ctx.fillText('Walk to EXIT tile to trigger Escape Gate', ex, ey - 28);
      ctx.textAlign = 'left';
    }
  }
}

