// ── Class select menu ─────────────────────────────
function drawClassSelectMenu(){
  ctx.fillStyle = COLORS.bg;
  ctx.fillRect(0, 0, W, H);

  ctx.textAlign = 'center';
  ctx.fillStyle = '#00e5ff';
  ctx.font = 'bold 28px monospace';
  ctx.fillText('ECHO HEIST', W/2, 80);

  ctx.fillStyle = '#94a3b8';
  ctx.font = '13px monospace';
  ctx.fillText('Select your operative class', W/2, 110);

  const classes = Object.entries(CLASSES);
  classes.forEach(([key, cls], i) => {
    const x = W/2 - 300 + i * 300, y = 180;
    const w = 240, h = 220;
    const _isUnlocked = window.isClassUnlocked || (()=>true);
    const locked = (key === 'ghost' && !_isUnlocked('ghost')) ||
                   (key === 'runner' && !_isUnlocked('runner'));

    ctx.fillStyle = locked ? 'rgba(30,30,40,0.6)' : 'rgba(15,20,35,0.9)';
    ctx.strokeStyle = locked ? '#333' : cls.color + '60';
    ctx.lineWidth = 2;
    roundRect(ctx, x, y, w, h, 12);
    ctx.fill(); ctx.stroke();

    ctx.fillStyle = locked ? '#444' : cls.color;
    ctx.font = '40px sans-serif';
    ctx.fillText(cls.icon, x+w/2, y+60);

    ctx.fillStyle = locked ? '#555' : '#fff';
    ctx.font = 'bold 16px monospace';
    ctx.fillText(cls.name, x+w/2, y+90);

    ctx.fillStyle = locked ? '#444' : '#94a3b8';
    ctx.font = '10px monospace';
    const words = cls.desc.split(' ');
    let line = '', lineY = y+112;
    for(const word of words){
      const test = line + word + ' ';
      if(ctx.measureText(test).width > w-20){ ctx.fillText(line, x+w/2, lineY); line=word+' '; lineY+=14; }
      else line = test;
    }
    ctx.fillText(line, x+w/2, lineY);

    if(locked){
      ctx.fillStyle = '#f59e0b';
      ctx.font = '10px monospace';
      const req = key === 'ghost' ? '(unlock: 5 missions)' : '(unlock: 10 missions)';
      ctx.fillText(req, x+w/2, y+h-20);
    } else {
      ctx.fillStyle = cls.color;
      ctx.font = 'bold 11px monospace';
      ctx.fillText(`[${i+1}] Select`, x+w/2, y+h-20);
    }
  });

  // District info
  ctx.fillStyle = '#64748b';
  ctx.font = '11px monospace';
  ctx.fillText('D1: Training Gallery · D2: Camera Commons · D3: Escape Lines', W/2, H-60);
  ctx.fillStyle = '#94a3b8';
  ctx.fillText('Press 1/2/3 to choose · Start mission 0', W/2, H-40);

  ctx.textAlign = 'left';
}

// ── Mission select (simple) ───────────────────────
function drawMissionSelect(){
  ctx.fillStyle = COLORS.bg;
  ctx.fillRect(0, 0, W, H);

  ctx.textAlign = 'center';
  ctx.fillStyle = '#00e5ff';
  ctx.font = 'bold 20px monospace';
  ctx.fillText('MISSION SELECT', W/2, 50);

  const completed = getCompletedMissions();

  const cols = 10, rows = 3;
  for(let district = 0; district < 3; district++){
    const distNames = ['Training Gallery (D1)','Camera Commons (D2)','Escape Lines (D3)'];
    const distColors = ['#22c55e','#f59e0b','#ef4444'];
    ctx.fillStyle = distColors[district];
    ctx.font = 'bold 12px monospace';
    ctx.fillText(distNames[district], W/2, 80 + district * 160);

    for(let m = 0; m < 10; m++){
      const mId = district * 10 + m;
      const mx = W/2 - 460 + m * 96, my = 95 + district * 160;
      const ww = 80, hh = 100;
      const done = completed.includes(mId);
      const locked = mId > 0 && !completed.includes(mId - 1) && !completed.includes(mId);

      ctx.fillStyle = done ? 'rgba(34,197,94,0.15)' : locked ? 'rgba(20,20,30,0.5)' : 'rgba(15,20,35,0.8)';
      ctx.strokeStyle = done ? '#22c55e50' : locked ? '#333' : '#333';
      ctx.lineWidth = 1;
      roundRect(ctx, mx, my, ww, hh, 8); ctx.fill(); ctx.stroke();

      ctx.fillStyle = locked ? '#444' : done ? '#22c55e' : '#94a3b8';
      ctx.font = 'bold 14px monospace';
      ctx.fillText(String(mId), mx+ww/2, my+24);

      ctx.fillStyle = locked ? '#333' : '#64748b';
      ctx.font = '8px monospace';
      const mName = MISSIONS[mId].name;
      const shortName = mName.length > 10 ? mName.slice(0,10)+'…' : mName;
      ctx.fillText(shortName, mx+ww/2, my+40);

      if(done){
        ctx.fillStyle = '#22c55e';
        ctx.font = '10px monospace';
        ctx.fillText('✓', mx+ww/2, my+58);
      } else if(!locked){
        ctx.fillStyle = '#64748b';
        ctx.font = '9px monospace';
        ctx.fillText('[press]', mx+ww/2, my+58);
      }
    }
  }

  ctx.fillStyle = '#64748b';
  ctx.font = '11px monospace';
  ctx.fillText('Press 0–9 to select mission (D1), A=D2, B=D3 · Esc = class select', W/2, H-20);
  ctx.textAlign = 'left';
}

