// ── Question templates ───────────────────────────
// T1: Percents (basic)
// T2: Percents (multi-step)
// T3: Fractions (add/subtract)
// T4: Fractions (multiply/divide)
// T5: Geometry (angles)
// T6: Fractions of quantities
// T7: Rates
// T8: Ratios / proportions
// T9: Integers
// T10: Decimals / rounding
// T11: Mixed fractions + geometry
// T12: Algebra (one/two step)

function makeT1(seed){
  const pairs=[
    {p:25,n:80,a:'20'},{p:50,n:60,a:'30'},{p:10,n:90,a:'9'},
    {p:75,n:40,a:'30'},{p:20,n:150,a:'30'},{p:30,n:70,a:'21'},
    {p:40,n:50,a:'20'},{p:15,n:80,a:'12'},{p:60,n:30,a:'18'},
    {p:5,n:200,a:'10'}
  ];
  const q=pairs[seed%pairs.length];
  // FIX T1-2 (2026-04-09): hint2 no longer shows the computed multiplication.
  // It names the operation and the decimal form only, stopping before the answer.
  return {
    template:'T1',
    text:`${q.p}% of ${q.n} = ?`,
    answer:q.a,
    hint1:'Convert percent to decimal',
    hint2:`Multiply ${q.n} by ${q.p/100}`
  };
}
// NARRATIVE WRAPPER UPDATE 2026-04-09: makeT2 now wraps each equation in a
// terse Echo Heist scenario.  All generator invariants from the 2026-04-09
// procedural rewrite are preserved exactly:
//   • Fully deterministic (no Math.random()) — same seed → same question
//   • a ∈ {2,3,4,5,6}, x ∈ {3..12}, b ∈ {2..15}
//   • Form A (ax+b=c): c always positive integer
//   • Form B (ax−b=c): safety clamp keeps c ≥ 2
//   • hint2 = question-prompt only, names the division step, never reveals x
//
// Wrapper selection:
//   wIdx = Math.floor(seed / 2) % 5
//   Adjacent seeds (0/1, 2/3, 4/5, …) share a scenario but flip A↔B,
//   so consecutive missions always present a fresh context.
//
// Template slots:  {a} = coefficient,  {b} = constant,  {c} = RHS,
//                  {unit} = countable real-world noun (integer-friendly).
//
// Form A wrappers — ax + b = c, question "How many {unit}?"
//   The coefficient {a} is the "per-unit rate", {b} is a fixed addend,
//   {c} is the known total.
//
// Form B wrappers — ax − b = c, question "How many {unit}?"
//   The coefficient {a} is the "per-unit rate", {b} is subtracted (lost/
//   diverted/drained), {c} is the net result.
//
// Scenario index → theme:
//   0  Hacker billing      (credits per file / heat per scan)
//   1  Electrical grid     (volts per relay / MB per node)
//   2  Courier logistics   (kg per floor / metres per dash)
//   3  Timing & cycles     (seconds per loop / tumblers per layer)
//   4  Agent tokens        (tokens per terminal / pings per pass)
function makeT2(seed){
  const AVALS = [2, 3, 4, 5, 6];
  const a = AVALS[seed % 5];
  const x = 3 + (Math.floor(seed / 5) % 10);        // 3..12
  let   b = 2 + (Math.floor(seed / 50) % 14);        // 2..15
  const formA = (seed % 2 === 0);
  const wIdx  = Math.floor(seed / 2) % 5;            // 0..4 — scenario selector

  // ── Form A scenario wrappers (ax + b = c) ─────────────────────────────
  // fn(a, b, c) → { setup, question }
  const wA = [
    // 0: Hacker billing
    (a,b,c) => ({
      setup:    `The hacker charges ${a} credits per encrypted file plus a ${b}-credit access fee. Total invoice: ${c} credits.`,
      question: `How many files were decrypted?`
    }),
    // 1: Electrical grid
    (a,b,c) => ({
      setup:    `Each relay draws ${a} volts plus ${b} V standby. The panel reads ${c} V total.`,
      question: `How many relays are active?`
    }),
    // 2: Courier logistics
    (a,b,c) => ({
      setup:    `The courier carries ${a} kg of gear per floor plus a ${b}-kg base kit. Total load: ${c} kg.`,
      question: `How many floors were covered?`
    }),
    // 3: Timing & cycles
    (a,b,c) => ({
      setup:    `Each camera loop runs ${a} seconds plus ${b} s boot-up. Full runtime recorded: ${c} s.`,
      question: `How many loops completed?`
    }),
    // 4: Agent tokens
    (a,b,c) => ({
      setup:    `An agent earns ${a} tokens per cracked terminal plus a ${b}-token sign-on bonus. Balance: ${c} tokens.`,
      question: `How many terminals were cracked?`
    })
  ];

  // ── Form B scenario wrappers (ax − b = c) ─────────────────────────────
  const wB = [
    // 0: Heat signature
    (a,b,c) => ({
      setup:    `Each scan emits ${a} heat units; ${b} are cooled by the vent system. Net heat reading: ${c}.`,
      question: `How many scans were run?`
    }),
    // 1: Data throughput
    (a,b,c) => ({
      setup:    `Each node carries ${a} MB, but ${b} MB are lost to interference. Net data received: ${c} MB.`,
      question: `How many nodes are in the chain?`
    }),
    // 2: Runner distance
    (a,b,c) => ({
      setup:    `The runner covers ${a} metres per dash but backtracks ${b} m each time. Net distance: ${c} m.`,
      question: `How many dashes were made?`
    }),
    // 3: Vault lock
    (a,b,c) => ({
      setup:    `Each vault layer has ${a} tumblers; ${b} were already picked. Remaining: ${c} tumblers.`,
      question: `How many layers does the vault have?`
    }),
    // 4: Drone signal
    (a,b,c) => ({
      setup:    `The drone sends ${a} pings per pass; ${b} are jammed. Pings received: ${c}.`,
      question: `How many passes did the drone make?`
    })
  ];

  let c, text, hint1, hint2;

  if (formA) {
    // ax + b = c  →  x = (c − b) / a
    c = a * x + b;                                   // always integer, always > 0
    const { setup, question } = wA[wIdx](a, b, c);
    text  = `${setup}  ${question}`;
    hint1 = `Subtract ${b} from both sides, then divide both sides by ${a}`;
    hint2 = `What is ${c - b} divided by ${a}?`;
  } else {
    // ax − b = c  →  x = (c + b) / a
    // Safety clamp: ensure c ≥ 2 (b ≤ a*x − 2)
    if (b >= a * x) { b = a * x - 2; }
    c = a * x - b;                                   // ≥ 2 by clamp above
    const { setup, question } = wB[wIdx](a, b, c);
    text  = `${setup}  ${question}`;
    hint1 = `Add ${b} to both sides, then divide both sides by ${a}`;
    hint2 = `What is ${c + b} divided by ${a}?`;
  }

  return { template: 'T2', text, answer: '' + x, hint1, hint2 };
}
function makeT3(seed){
