// ── Level layouts ────────────────────────────────
// Each level is a 24×16 grid of tile IDs (W=960/40=24, H=640/40=16)
// Cameras: [{col, row, angle, sweep}]
// Guards: [{col, row, patrolPath:[{dx,dy},...]}]
// Doors: [{col, row}] (DOOR_LOCKED tiles that need a terminal)
// Terminals: [{col, row, doorId}]  (links terminal to a door index)
// Loot: {col, row}
// Exit: {col, row}

function makeLevelGrid(cfg){
  // cfg: {walls:[[c,r],...], carpet:[[c,r],...], metal:[[c,r],...], vent:[[c,r],...]}
  const grid = [];
  for(let r=0;r<16;r++){
    grid.push([]);
    for(let c=0;c<24;c++){
      // Border walls
      if(r===0||r===15||c===0||c===23) grid[r].push(T.WALL);
      else grid[r].push(T.FLOOR);
    }
  }
  (cfg.walls||[]).forEach(([c,r])=>{ if(r>0&&r<15&&c>0&&c<23) grid[r][c]=T.WALL; });
  (cfg.carpet||[]).forEach(([c,r])=>{ grid[r][c]=T.CARPET; });
  (cfg.metal||[]).forEach(([c,r])=>{ grid[r][c]=T.METAL; });
  (cfg.vent||[]).forEach(([c,r])=>{ grid[r][c]=T.VENT; });
  return grid;
}

// Base level template builder
function buildLevel(missionId){
  const seed = missionId;
  const district = getDistrict(missionId);

  // Deterministic layout based on mission seed
  const col = c => c;
  const row = r => r;

  // Shared room skeleton — 3 rooms separated by walls with passages
  const walls = [];
  // Central vertical divider with gap
  for(let r=2;r<14;r++){
    if(r!==7&&r!==8) walls.push([12,r]);
  }
  // Horizontal divider in right half with gap
  for(let c=13;c<23;c++){
    if(c!==17&&c!==18) walls.push([c,8]);
  }

  const grid = makeLevelGrid({
    walls,
    carpet:[[1,1],[2,1],[3,1],[4,1],[1,2],[2,2],[1,3]],
    metal:[[20,1],[21,1],[22,1],[20,2],[21,2],[20,3]],
    vent:[[1,14],[22,14]]
  });

  // Place special tiles
  const spawnC = 2, spawnR = 13;
  grid[spawnR][spawnC] = T.SPAWN;

  const lootC = 14 + (seed%4), lootR = 2 + (seed%3);
  grid[lootR][lootC] = T.LOOT;

  const exitC = 21, exitR = 1;
  grid[exitR][exitC] = T.EXIT;

  // Terminal + locked door
  const termC = 6 + (seed%4), termR = 4;
  grid[termR][termC] = T.TERMINAL;

  const doorC = 12, doorR = 5 + (seed%3);
  grid[doorR][doorC] = T.DOOR_LOCKED;

  // Camera placement (as metadata, not tile)
  const cameras = [];
  cameras.push({col:18,row:1,angle:270,sweep:80});
  if(district>0) cameras.push({col:3,row:10,angle:90,sweep:60});
  if(district>1) cameras.push({col:20,row:10,angle:180,sweep:100});

  // Guards — patrol defined as absolute tile waypoints [{col,row},...]
  const guards = [];
  const speed = 0.8 + district * 0.3;
  guards.push({
    col:15, row:6,
    angle:0, speed,
    waypoints:[{col:15,row:6},{col:18,row:6},{col:18,row:9},{col:15,row:9}],
    waypointIdx:0
  });
  if(district>0){
    guards.push({
      col:5, row:5,
      angle:180, speed:speed*0.9,
      waypoints:[{col:5,row:5},{col:5,row:10},{col:9,row:10},{col:9,row:5}],
      waypointIdx:0
    });
  }
  if(district>1){
    guards.push({
      col:20, row:12,
      angle:90, speed:speed*1.1,
      waypoints:[{col:20,row:12},{col:14,row:12},{col:14,row:9},{col:20,row:9}],
      waypointIdx:0
    });
  }

  return {
    grid,
    spawn:{col:spawnC,row:spawnR},
    loot:{col:lootC,row:lootR},
    exit:{col:exitC,row:exitR},
    terminal:{col:termC,row:termR,doorIndex:0},
    doors:[{col:doorC,row:doorR,open:false}],
    cameras,
    guards
  };
}

