// ── App state ────────────────────────────────────
// 'class_select' | 'mission_select' | 'playing' | 'end'
let appState = 'class_select';
let selectedClass = 'hacker';
let currentMission = 0;

// ── localStorage helpers ──────────────────────────
const LS_KEY = 'echo_heist_save';

function loadSave(){
  try {
    const raw = localStorage.getItem(LS_KEY);
    return raw ? JSON.parse(raw) : { completed: [], scores: {}, totalMissions: 0 };
  } catch(e){
    return { completed: [], scores: {}, totalMissions: 0 };
  }
}

function saveMissionResult(missionId, score, passed){
  const save = loadSave();
  if(passed && !save.completed.includes(missionId)){
    save.completed.push(missionId);
  }
  save.scores[missionId] = Math.max(save.scores[missionId] || 0, score);
  save.totalMissions = (save.totalMissions || 0) + 1;
  localStorage.setItem(LS_KEY, JSON.stringify(save));
}

function getCompletedMissions(){
  return loadSave().completed;
}

function getTotalMissions(){
  return loadSave().totalMissions || 0;
}

function isClassUnlocked(cls){
  const total = getTotalMissions();
  if(cls === 'hacker') return true;
  if(cls === 'ghost')  return total >= 5;
  if(cls === 'runner') return total >= 10;
  return false;
}

// ── Daily mission seed ────────────────────────────
function getDailyMissionId(){
  const now = new Date();
  const dayKey = now.getFullYear() * 1000 + now.getMonth() * 32 + now.getDate();
  return ((dayKey * 2654435761) >>> 0) % MISSIONS.length;
}

// ── State: class select ───────────────────────────
let classSelectFrame = null;

function enterClassSelect(){
  appState = 'class_select';
  stopGameLoop();

  function classSelectLoop(){
    drawClassSelectMenu();
    classSelectFrame = requestAnimationFrame(classSelectLoop);
  }
  if(classSelectFrame) cancelAnimationFrame(classSelectFrame);
  classSelectFrame = requestAnimationFrame(classSelectLoop);
}

function exitClassSelect(){
  if(classSelectFrame){ cancelAnimationFrame(classSelectFrame); classSelectFrame = null; }
}

// ── State: mission select ─────────────────────────
let missionSelectFrame = null;

function enterMissionSelect(){
  appState = 'mission_select';
  stopGameLoop();

  function missionSelectLoop(){
    drawMissionSelect();
    missionSelectFrame = requestAnimationFrame(missionSelectLoop);
  }
  if(missionSelectFrame) cancelAnimationFrame(missionSelectFrame);
  missionSelectFrame = requestAnimationFrame(missionSelectLoop);
}

function exitMissionSelect(){
  if(missionSelectFrame){ cancelAnimationFrame(missionSelectFrame); missionSelectFrame = null; }
}

// ── State: playing ────────────────────────────────
function startMission(missionId){
  exitClassSelect();
  exitMissionSelect();
  appState = 'playing';
  currentMission = missionId;
  window.currentMission = missionId;

  // Reset G global from engine
  initGameState(missionId);
  // G is now window.G — update class fields
  window.G.selectedClass = selectedClass;
  window.G.cls = CLASSES[selectedClass];
  window.G.speed = CLASSES[selectedClass].moveSpeed;

  // Mission end callback
  window.onMissionEnd = function(passed){
    saveMissionResult(missionId, window.G.score, passed);
  };

  startGameLoop();
}

// ── State: end / navigation ───────────────────────
function handleEndKeys(e){
  if(appState !== 'playing') return;
  if(!G.caught && !G.missionComplete) return;

  if(e.code === 'KeyR'){
    // Retry
    document.removeEventListener('keydown', handleMathKey);
    startMission(currentMission);
  } else if(e.code === 'KeyN'){
    // Next mission
    document.removeEventListener('keydown', handleMathKey);
    const next = Math.min(currentMission + 1, MISSIONS.length - 1);
    startMission(next);
  } else if(e.code === 'Escape'){
    // Back to mission select
    stopGameLoop();
    document.removeEventListener('keydown', handleMathKey);
    enterMissionSelect();
  }
}

// ── Global key router ─────────────────────────────
document.addEventListener('keydown', function(e){
  if(appState === 'class_select'){
    if(e.code === 'Digit1'){ selectedClass='hacker'; exitClassSelect(); enterMissionSelect(); }
    else if(e.code === 'Digit2' && isClassUnlocked('ghost')){ selectedClass='ghost'; exitClassSelect(); enterMissionSelect(); }
    else if(e.code === 'Digit3' && isClassUnlocked('runner')){ selectedClass='runner'; exitClassSelect(); enterMissionSelect(); }
    else if(e.code === 'Enter'){ exitClassSelect(); enterMissionSelect(); }

  } else if(appState === 'mission_select'){
    // Digits 0-9 → D1 missions 0-9
    const digitMap = {'Digit0':0,'Digit1':1,'Digit2':2,'Digit3':3,'Digit4':4,'Digit5':5,'Digit6':6,'Digit7':7,'Digit8':8,'Digit9':9};
    if(digitMap[e.code] !== undefined){
      exitMissionSelect(); startMission(digitMap[e.code]); return;
    }
    if(e.code === 'KeyA'){ exitMissionSelect(); startMission(10); return; }
    if(e.code === 'KeyB'){ exitMissionSelect(); startMission(20); return; }
    if(e.code === 'KeyD'){ exitMissionSelect(); startMission(getDailyMissionId()); return; }
    if(e.code === 'Escape'){ exitMissionSelect(); enterClassSelect(); }

  } else if(appState === 'playing'){
    // Route to math popup handler first (it checks G.popupOpen internally)
    handleMathKey(e);
    // Then end-screen navigation
    handleEndKeys(e);
  }
});

