// ── Answer normaliser (PATCH -07: float-safe) ────
function normaliseAnswer(raw){
  const s = String(raw).trim().toLowerCase().replace(/\s/g,'');

  // Percent: "25%" → "25" or "4.5%" → "4.5"
  if(s.endsWith('%')) return String(roundTo(parseFloat(s),4));

  // Fraction: "3/4" → already comparable
  if(s.includes('/')){
    const parts = s.split('/');
    if(parts.length === 2){
      const n = parseFloat(parts[0]), d = parseFloat(parts[1]);
      if(!isNaN(n) && !isNaN(d) && d !== 0) return String(roundTo(n/d,4));
    }
    return s;
  }

  // Plain number
  const n = parseFloat(s);
  if(!isNaN(n)) return String(roundTo(n,4));

  return s;
}

function checkAnswer(userInput, correctAnswer){
  const u = normaliseAnswer(userInput);
  const c = normaliseAnswer(correctAnswer);
  if(u === c) return true;
  // Also compare as fractions against decimal equivalents
  const un = parseFloat(u), cn = parseFloat(c);
  if(!isNaN(un) && !isNaN(cn)) return Math.abs(un - cn) < 0.001;
  return false;
}

