// ── Open math popup ───────────────────────────────
// PATCH -08: terminal intro overlay on first open
// PATCH -08b: guard note appended live
// PATCH -08c: format reminder badges on repeat popups
function openMathPopup(mode, questionData){
  if(G.popupOpen) return;
  cachePopupElements();

  G.popupOpen = true;
  G.popupMode = mode;
  G.currentQ = questionData;
  G.hintCount = 0;

  // Clear state
  popupEl.className = '';
  popupEl.style.display = 'block';
  feedbackEl.textContent = '';
  feedbackEl.className = 'feedback';
  hintAreaEl.textContent = '';
  inputEl.value = '';

  // Mode-specific styling
  switch(mode){
    case 'vault':   popupEl.classList.add('vault-mode');   break;
    case 'escape':  popupEl.classList.add('escape-mode');  break;
    case 'ability': popupEl.classList.add('ability-mode');
      popupEl.style.setProperty('--cls-color', CLASSES[G.selectedClass].color); break;
    default:        break;
  }

  // Title
  const titles = {
    terminal: '⬛ Security Terminal',
    vault:    '🔐 Vault Lock',
    escape:   '🚨 Escape Gate',
    ability:  `⚡ ${G.cls.abilityName}`
  };
  titleEl.textContent = titles[mode] || 'Terminal';

  // Prompt text (replace \n with line breaks)
  promptEl.innerHTML = questionData.text.replace(/\n/g,'<br>');

  // PATCH -08: Terminal intro on first popup ever
  if(!G.terminalIntroShown && mode === 'terminal'){
    // Show intro — don't let player type until they press Enter to dismiss
    introEl.style.display = 'block';
    formatReminderEl.style.display = 'none';
    inputEl.disabled = true;
  } else {
    introEl.style.display = 'none';
    // PATCH -08c: format reminder badges on every popup after the first
    if(G.formatReminderShown){
      formatReminderEl.style.display = 'flex';
    } else {
      formatReminderEl.style.display = 'none';
    }
    inputEl.disabled = false;
    setTimeout(()=>inputEl.focus(), 50);
  }

  // Vault progress dots
  if(mode === 'vault'){
    vaultProgressEl.style.display = 'flex';
    vaultProgressEl.innerHTML = '';
    for(let i = 0; i < G.vaultQs.length; i++){
      const dot = document.createElement('div');
      dot.className = 'vault-step' + (i < G.vaultStep ? ' done' : i === G.vaultStep ? ' active' : '');
      vaultProgressEl.appendChild(dot);
    }
  } else {
    vaultProgressEl.style.display = 'none';
  }

  // PATCH -08b: guard note
  updateGuardNote();
}

// PATCH -08b: live guard note update
function updateGuardNote(){
  if(!guardNoteEl) return;
  if(G.focusMode){
    guardNoteEl.textContent = ' ⏸ Focus: guards at 25% speed';
    guardNoteEl.style.color = '#a855f7';
  } else {
    guardNoteEl.textContent = ' ⚠ Guards still moving!';
    guardNoteEl.style.color = '#f59e0b';
  }
}

// ── Close popup ───────────────────────────────────
function closePopup(){
  cachePopupElements();
  if(popupEl) popupEl.style.display = 'none';
  G.popupOpen = false;
  G.popupMode = null;
  G.currentQ = null;
  if(inputEl){
    inputEl.disabled = false;
    inputEl.value = '';
  }
}

// ── Hint system ───────────────────────────────────
function showHint(){
  if(!G.popupOpen || !G.currentQ || G.popupMode === 'vault') return;
  const dc = getDConfig(G.missionId);

  // Mastery discount
  const tpl = G.currentQ.template || 'T1';
  const masteryCt = G.mastery[tpl] || 0;
  const discount = masteryCt >= 3 ? 0.75 : 1.0;
  const cost = Math.round(dc.hintCost * discount);

  if(G.hintCount === 0){
    hintAreaEl.textContent = `💡 (−${cost} score pts) ${G.currentQ.hint1 || 'Look at the structure of the problem.'}`;
    G.score = Math.max(0, G.score - cost);
    G.hintCount = 1;
    G.hintsUsed++;
  } else if(G.hintCount === 1){
    hintAreaEl.textContent = `💡💡 (−${cost} score pts) ${G.currentQ.hint2 || 'Work step by step.'}`;
    G.score = Math.max(0, G.score - cost);
    G.hintCount = 2;
    G.hintsUsed++;
  } else {
    hintAreaEl.textContent = '✓ Max hints reached for this question.';
  }
}

function autoHintIfNeeded(){
  // PATCH -08: after 2 wrong answers, auto-hint fires
  if(G.mathAttempts >= 2 && G.hintCount === 0 && G.currentQ){
    hintAreaEl.textContent = `🤖 Auto-hint: ${G.currentQ.hint1 || 'Reconsider your approach.'}`;
  }
}

// ── Scaffold panel ────────────────────────────────
function getScaffoldContent(template){
  const scaffolds = {
    T1: '📊 Percent → Decimal\n% ÷ 100 = decimal\npart = whole × decimal',
    T2: '📈 Percent Change\nIncrease: original × (1 + %/100)\nDecrease: original × (1 − %/100)',
    T3: '➕ Fraction Addition\na/b + c/d = (ad+bc)/bd\nSimplify the result!',
    T4: '✖ Fraction Multiply\na/b × c/d = ac/bd\nDivide: flip and multiply',
    T5: '📐 Angles\nSupplementary: 180° total\nComplementary: 90° total\nTriangle: 180° total',
    T6: '🍕 Fraction of Quantity\nResult = Quantity × Numerator ÷ Denominator',
    T7: '🚗 Rate Formula\nd = r × t\nr = d ÷ t\nt = d ÷ r',
    T8: '⚖ Ratios\nPart = (ratio part / total parts) × whole\nProportion: a/b = c/d → ad = bc',
    T9: '🔢 Integers\n+ × + = +\n− × − = +\n+ × − = −\nSubtracting negative = adding',
    T10:'🔟 Decimals\nAlign decimal points to add/subtract\nCount places to place decimal after multiply',
    T11:'📐 Geometry\nRectangle: A = l×w, P = 2(l+w)\nCircle: C = 2πr, A = πr²\nTriangle: A = ½bh',
    T12:'🔣 Algebra\nDo same operation to both sides\nIsolate the variable step by step'
  };
  return scaffolds[template] || 'Use the structure of the problem to guide your approach.';
}

// ── Terminal hack ─────────────────────────────────
function startTerminalHack(col, row){
  if(G.questionIndex >= G.questionQueue.length){
    // Refill queue
    G.questionQueue = G.mission.questions.map(q => makeQuestion(q.template, q.seed + 100));
    G.questionIndex = 0;
  }
  const q = G.questionQueue[G.questionIndex++];

  // Disable nearest camera after terminal solved
  G._pendingCameraDisable = true;

  openMathPopup('terminal', q);
}

// ── Vault sequence ────────────────────────────────
function startVault(){
  if(G.vaultActive || G.lootCollected) return;
  G.vaultActive = true;
  G.vaultStep = 0;
  G.vaultTimer = 0;
  G.level.grid[G.level.loot.row][G.level.loot.col] = T.FLOOR;
  openMathPopup('vault', G.vaultQs[0]);
}

function advanceVault(){
  G.vaultStep++;
  if(G.vaultStep >= G.vaultQs.length){
    // Vault complete
    G.lootCollected = true;
    G.vaultActive = false;
    G.escapeTimer = 0;
    G.score += 500;
    closePopup();
  } else {
    openMathPopup('vault', G.vaultQs[G.vaultStep]);
  }
}

// ── Escape gate ───────────────────────────────────
function triggerEscapeGate(){
  if(!G.lootCollected || G.popupOpen) return;
  const escQ = makeQuestion('T12', G.missionId * 7 + 99);
  openMathPopup('escape', escQ);
}

// ── Handle math key press ─────────────────────────
function handleMathKey(e){
  if(!G.popupOpen) return;

  // Terminal intro: Enter dismisses intro first
  if(introEl && introEl.style.display !== 'none'){
    if(e.code === 'Enter'){
      introEl.style.display = 'none';
      G.terminalIntroShown = true;
      G.formatReminderShown = true;
      localStorage.setItem('eh_intro_shown','1');
      formatReminderEl.style.display = 'flex';
      inputEl.disabled = false;
      inputEl.focus();
    }
    return;
  }

  // PATCH -08c: Tab toggles focus mode and updates guard note
  if(e.code === 'Tab'){
    e.preventDefault();
    G.focusMode = !G.focusMode;
    updateGuardNote();
    return;
  }

  if(e.code === 'KeyH'){
    showHint();
    return;
  }

  if(e.code === 'KeyF'){
    G.scaffoldOpen = !G.scaffoldOpen;
    return;
  }

  // Esc = skip (PATCH -08: +20 heat, not just close)
  if(e.code === 'Escape'){
    if(G.popupMode === 'vault') return; // cannot abandon vault
    G.heat = Math.min(100, G.heat + 20);
    feedbackEl.textContent = '⚡ Node skipped → +20 Heat';
    feedbackEl.className = 'feedback fb-wrong';
    setTimeout(()=> closePopup(), 800);
    return;
  }

  if(e.code === 'Enter'){
    e.preventDefault();
    const userAnswer = inputEl.value;
    if(!userAnswer.trim()) return;

    const correct = checkAnswer(userAnswer, G.currentQ.answer);
    G.mathAttempts++;

    if(correct){
      // PATCH -08: show correct answer + heat delta in feedback
      feedbackEl.textContent = `✓ Correct! (+${scoreForCorrect()} pts)`;
      feedbackEl.className = 'feedback fb-correct';
      G.mathCorrect++;
      G.score += scoreForCorrect();

      // Mastery tracking
      const tpl = G.currentQ.template || 'T1';
      G.mastery[tpl] = (G.mastery[tpl] || 0) + 1;

      handleCorrectAnswer();
    } else {
      // PATCH -08: reveal correct answer + heat cost
      const heatDelta = G.popupMode === 'vault' ? 8 : 5;
      G.heat = Math.min(100, G.heat + heatDelta * getDConfig(G.missionId).heatGainMult);
      feedbackEl.textContent = `✗ Incorrect — answer: ${G.currentQ.answer} · Heat +${Math.round(heatDelta * getDConfig().heatGainMult)}`;
      feedbackEl.className = 'feedback fb-wrong';

      // Reset mastery on wrong answer
      const tpl = G.currentQ.template || 'T1';
      G.mastery[tpl] = 0;

      autoHintIfNeeded();
      inputEl.value = '';
      if(G.heat >= 100) triggerCaught();
    }
  }
}

function scoreForCorrect(){
  const base = G.popupMode === 'vault' ? 150 : G.popupMode === 'escape' ? 200 : 100;
  // Hacker overclock bonus
  if(G.abilityActive && G.selectedClass === 'hacker') return Math.round(base * 1.3);
  return base;
}

function handleCorrectAnswer(){
  const mode = G.popupMode;

  if(mode === 'terminal'){
    // Disable nearest camera
    if(G._pendingCameraDisable){
      const nearest = nearestCamera();
      if(nearest){ nearest.disabled = true; nearest.disabledTimer = 30; }
      G._pendingCameraDisable = false;
    }
    setTimeout(()=> closePopup(), 600);
  } else if(mode === 'vault'){
    setTimeout(()=> advanceVault(), 600);
  } else if(mode === 'escape'){
    setTimeout(()=>{
      closePopup();
      triggerMissionComplete();
    }, 600);
  } else if(mode === 'ability'){
    applyAbilityEffect();
    setTimeout(()=> closePopup(), 600);
  }
}

function nearestCamera(){
  let best = null, bestD = Infinity;
  for(const cam of G.cameras){
    const d = Math.hypot(G.px - cam.x, G.py - cam.y);
    if(d < bestD){ bestD = d; best = cam; }
  }
  return best;
}

function applyAbilityEffect(){
  const cls = G.selectedClass;
  G.abilityCooldown = G.cls.abilityCooldown;
  G.abilityActive = true;

  if(cls === 'hacker'){
    G.abilityTimeLeft = 30;
  } else if(cls === 'ghost'){
    G.noise = Math.max(0, G.noise - 50);
    G.abilityTimeLeft = 1; // ghost effect is instant noise reduction
  } else if(cls === 'runner'){
    G.speed = G.cls.moveSpeed * 2;
    G.abilityTimeLeft = 3;
  }
}

// ── Scaffold draw (on canvas, called from ui.js) ─
function drawScaffold(ctx){
  if(!G.scaffoldOpen || !G.currentQ) return;
  const tpl = (G.currentQ && G.currentQ.template) || 'T1';
  const content = getScaffoldContent(tpl);
  const lines = content.split('\n');
  const pw = 220, ph = 20 + lines.length * 18 + 16;
  const sx = 20, sy = (H - ph) / 2;

  ctx.fillStyle = 'rgba(10,15,30,0.92)';
  ctx.strokeStyle = '#a855f7';
  ctx.lineWidth = 1.5;
  roundRect(ctx, sx, sy, pw, ph, 10);
  ctx.fill(); ctx.stroke();

  ctx.fillStyle = '#a855f7';
  ctx.font = 'bold 10px monospace';
  ctx.fillText('📐 SCAFFOLD', sx+12, sy+16);

  ctx.font = '11px monospace';
  ctx.fillStyle = '#94a3b8';
  lines.forEach((ln, i)=>{
    ctx.fillText(ln, sx+12, sy+32 + i*18);
  });
}

function roundRect(ctx,x,y,w,h,r){
  ctx.beginPath();
  ctx.moveTo(x+r,y);
  ctx.lineTo(x+w-r,y); ctx.arcTo(x+w,y,x+w,y+r,r);
  ctx.lineTo(x+w,y+h-r); ctx.arcTo(x+w,y+h,x+w-r,y+h,r);
  ctx.lineTo(x+r,y+h); ctx.arcTo(x,y+h,x,y+h-r,r);
  ctx.lineTo(x,y+r); ctx.arcTo(x,y,x+r,y,r);
  ctx.closePath();
}

