// ═══════════════════════════════════════════════
//  ECHO HEIST — engine.js
//  Game loop, physics, guard AI, camera sweep,
//  echo ghost, gadget, noise & heat system
// ═══════════════════════════════════════════════

const TILE = 40;
const W = 960, H = 640;
const PI2 = Math.PI * 2;
const DEG = Math.PI / 180;

// FIX -04-07 #1: precise rounding — eliminates float drift
function roundTo(val, decimals){
  return Number(Math.round(+(val+'e'+decimals))+'e-'+decimals);
}

// ── Game state object ────────────────────────────
// All modules access game state via window.G.
// initGameState() replaces the object and re-exports it.
if(!window.G) window.G = {};

function initGameState(missionId){
  const mission = MISSIONS[missionId];
  const cls = CLASSES[G.selectedClass || 'hacker'];
  const level = buildLevel(missionId);
  const dc = DISTRICT_CONFIG[getDistrict(missionId)];

  // Build question queue from mission definition
  const qShuffle = [...mission.questions].map(q => makeQuestion(q.template, q.seed));
  const vaultQs = mission.vault.map(q => makeQuestion(q.template, q.seed));

  G = {
    // Identity
    missionId,
    mission,
    selectedClass: G.selectedClass || 'hacker',
    cls,
    level,
    dc,

    // Player
    px: (level.spawn.col + 0.5) * TILE,
    py: (level.spawn.row + 0.5) * TILE,
    pAngle: 0,
    crouching: false,
    speed: cls.moveSpeed,
    noise: 0,
    heat: 0,
    score: 0,

    // Mission state
    lootCollected: false,
    escaped: false,
    caught: false,
    missionFailed: false,
    missionComplete: false,

    // Timers (seconds)
    missionTimer: 0,
    missionTimeLimit: 180 + (2 - getDistrict(missionId)) * 30,
    escapeTimer: 0,
    escapeTimeLimit: dc.escapeTime,
    vaultTimer: 0,
    vaultTimeLimit: 90,

    // Math state
    popupOpen: false,
    popupMode: null, // 'terminal'|'vault'|'escape'|'ability'
    currentQ: null,
    vaultStep: 0,
    vaultQs,
    vaultActive: false,
    mathAttempts: 0,
    mathCorrect: 0,
    hintsUsed: 0,
    hintCount: 0, // per-question hints used
    terminalIntroShown: localStorage.getItem('eh_intro_shown') === '1',
    formatReminderShown: false,
    questionQueue: qShuffle,
    questionIndex: 0,

    // Class ability
    abilityCooldown: 0,
    abilityActive: false,
    abilityTimeLeft: 0,
    abilityPromptIdx: Math.floor(Math.random() * cls.abilityPrompts.length),

    // Template mastery (per-session)
    mastery: {}, // templateId -> consecutive correct count

    // Guards (live state)
    guards: level.guards.map(g => ({
      ...g,
      x: (g.col + 0.5) * TILE,
      y: (g.row + 0.5) * TILE,
      state: 'patrol',
      alertTimer: 0,
      lastSeenX: null,
      lastSeenY: null,
      coneAngle: g.angle * DEG,
      coneSweep: 70 * DEG,
      coneRange: 120 + getDistrict(missionId) * 30,
      speed: g.speed * dc.guardSpeedMult,
      waypointIdx: g.waypointIdx || 0,
      waypoints: g.waypoints || [{col:g.col,row:g.row}],
    })),

    // Cameras (live state)
    cameras: level.cameras.map(cam => ({
      ...cam,
      x: (cam.col + 0.5) * TILE,
      y: (cam.row + 0.5) * TILE,
      currentAngle: cam.angle * DEG,
      sweepDir: 1,
      disabled: false,
      disabledTimer: 0,
    })),

    // Doors
    doors: level.doors.map(d => ({...d})),

    // Echo ghost
    echoRecording: false,
    echoPath: [],
    echoGhosts: [],
    echoCharges: 2,

    // Gadget
    gadgetPlaced: false,
    gadget: null,

    // Focus mode
    focusMode: false,

    // Scaffold panel
    scaffoldOpen: false,

    // Noise maker trigger
    noiseMakerActive: false,
    noiseMakerPos: null,
    noiseMakerTimer: 0,

    // Visual flash
    screenFlash: 0,
    vaultFlashing: false,

    // Mute
    muted: false,

    // Input keys
    keys: {},
  };

  // Vault flash: track last vault timer
  G._lastVaultTimer = 0;

  // Re-export to window so all other modules see the new state object
  window.G = G;
}

// ── Collision helpers ────────────────────────────
function tileAt(col, row){
  const grid = G.level.grid;
  if(row < 0 || row >= 16 || col < 0 || col >= 24) return T.WALL;
  return grid[row][col];
}

function isSolid(tile){
  return tile === T.WALL || tile === T.DOOR_LOCKED;
}

function canMoveTo(x, y){
  const margin = 12;
  const checks = [
    [x - margin, y - margin],
    [x + margin, y - margin],
    [x - margin, y + margin],
    [x + margin, y + margin],
  ];
  for(const [cx, cy] of checks){
    const col = Math.floor(cx / TILE);
    const row = Math.floor(cy / TILE);
    if(isSolid(tileAt(col, row))) return false;
  }
  return true;
}

function playerTile(){
  return { col: Math.floor(G.px / TILE), row: Math.floor(G.py / TILE) };
}

// ── Line of sight ────────────────────────────────
function hasLineOfSight(x1, y1, x2, y2){
  const steps = 30;
  for(let i = 1; i <= steps; i++){
    const t = i / steps;
    const cx = x1 + (x2 - x1) * t;
    const cy = y1 + (y2 - y1) * t;
    const col = Math.floor(cx / TILE);
    const row = Math.floor(cy / TILE);
    const tile = tileAt(col, row);
    if(tile === T.WALL || tile === T.DOOR_LOCKED) return false;
  }
  return true;
}

// ── Update player ────────────────────────────────
function updatePlayer(dt){
  if(G.popupOpen || G.caught || G.missionComplete) return;

  const { keys, crouching } = G;
  let dx = 0, dy = 0;

  if(keys['KeyW'] || keys['ArrowUp'])    dy -= 1;
  if(keys['KeyS'] || keys['ArrowDown'])  dy += 1;
  if(keys['KeyA'] || keys['ArrowLeft'])  dx -= 1;
  if(keys['KeyD'] || keys['ArrowRight']) dx += 1;

  G.crouching = keys['ShiftLeft'] || keys['ShiftRight'];

  if(dx !== 0 || dy !== 0){
    const spd = G.speed * (G.crouching ? 0.5 : 1.0) * (G.abilityActive ? 2 : 1) * TILE;
    const len = Math.hypot(dx, dy);
    const ndx = (dx / len) * spd * dt;
    const ndy = (dy / len) * spd * dt;

    if(canMoveTo(G.px + ndx, G.py)) G.px += ndx;
    if(canMoveTo(G.px, G.py + ndy)) G.py += ndy;

    G.pAngle = Math.atan2(dy, dx);

    // Noise from movement
    const pt = playerTile();
    const tileNoise = NOISE_MAP[tileAt(pt.col, pt.row)] || 3;
    const noiseMult = G.crouching ? 0.3 : G.cls.noiseMultiplier;
    const abilityNoiseMult = G.abilityActive ? 0 : 1; // Runner burst = silent
    G.noise = Math.min(100, G.noise + tileNoise * noiseMult * abilityNoiseMult * dt * 8);

    // Echo recording
    if(G.echoRecording){
      G.echoPath.push({x: G.px, y: G.py, t: performance.now()});
      if(G.echoPath.length > 600) G.echoPath.shift(); // ~10s at 60fps
    }
  } else {
    // Noise decay when still
    G.noise = Math.max(0, G.noise - dt * 15);
  }
}

// ── Update guards ────────────────────────────────
function updateGuards(dt){
  if(G.caught || G.missionComplete) return;

  const speedMult = (G.focusMode && G.popupOpen) ? 0.25 : 1.0;

  for(const guard of G.guards){
    const gx = guard.x, gy = guard.y;
    const pdx = G.px - gx, pdy = G.py - gy;
    const dist = Math.hypot(pdx, pdy);

    // Check noiseMaker distraction
    if(G.noiseMakerActive && G.noiseMakerPos){
      const ndx = G.noiseMakerPos.x - gx;
      const ndy = G.noiseMakerPos.y - gy;
      const nd = Math.hypot(ndx, ndy);
      if(nd < 200 && guard.state !== 'chase'){
        guard.state = 'alert';
        guard.lastSeenX = G.noiseMakerPos.x;
        guard.lastSeenY = G.noiseMakerPos.y;
        guard.alertTimer = 3;
      }
    }

    // Vision check
    const angleToPlayer = Math.atan2(pdy, pdx);
    const angleDiff = Math.abs(normalizeAngle(angleToPlayer - guard.coneAngle));
    const inCone = dist < guard.coneRange && angleDiff < guard.coneSweep / 2;
    const canSee = inCone && hasLineOfSight(gx, gy, G.px, G.py);
    const playerVisible = canSee && !G.caught;

    if(playerVisible){
      guard.lastSeenX = G.px;
      guard.lastSeenY = G.py;
      if(dist < 60){
        guard.state = 'chase';
      } else {
        guard.state = guard.state === 'chase' ? 'chase' : 'alert';
        guard.alertTimer = 4;
      }
    }

    // State machine
    switch(guard.state){
      case 'patrol':
        updateGuardPatrol(guard, dt * speedMult);
        break;
      case 'alert':
        guard.alertTimer -= dt;
        moveGuardToward(guard, guard.lastSeenX, guard.lastSeenY, guard.speed * speedMult * dt);
        if(guard.alertTimer <= 0) guard.state = 'patrol';
        break;
      case 'chase':
        if(playerVisible){
          moveGuardToward(guard, G.px, G.py, guard.speed * 1.5 * speedMult * dt);
        } else {
          guard.alertTimer -= dt;
          if(guard.alertTimer <= 0) guard.state = 'patrol';
        }
        break;
    }

    // Caught check
    if(Math.hypot(G.px - guard.x, G.py - guard.y) < 20 && guard.state === 'chase'){
      triggerCaught();
    }

    // Rotate cone toward movement direction
    const movDx = guard.x - gx, movDy = guard.y - gy;
    if(Math.abs(movDx) + Math.abs(movDy) > 0.1){
      guard.coneAngle = Math.atan2(movDy, movDx);
    }

    // Heat from camera cones handled below
    // Heat from guard sight
    if(canSee){
      G.heat = Math.min(100, G.heat + G.dc.heatGainMult * 30 * dt);
      if(G.heat >= 100) triggerCaught();
    }
  }
}

function updateGuardPatrol(guard, dt){
  const wps = guard.waypoints;
  if(!wps || wps.length === 0) return;
  const wp = wps[guard.waypointIdx % wps.length];
  const tx = (wp.col + 0.5) * TILE;
  const ty = (wp.row + 0.5) * TILE;
  moveGuardToward(guard, tx, ty, guard.speed * dt * TILE);
  if(Math.hypot(tx - guard.x, ty - guard.y) < 6){
    guard.waypointIdx = (guard.waypointIdx + 1) % wps.length;
  }
}

function moveGuardToward(guard, tx, ty, spd){
  const dx = tx - guard.x, dy = ty - guard.y;
  const d = Math.hypot(dx, dy);
  if(d < 2) return;
  const nx = guard.x + (dx/d)*spd;
  const ny = guard.y + (dy/d)*spd;
  if(canMoveTo(nx, ny)){
    guard.x = nx; guard.y = ny;
  } else if(canMoveTo(nx, guard.y)){
    guard.x = nx;
  } else if(canMoveTo(guard.x, ny)){
    guard.y = ny;
  }
}

function normalizeAngle(a){
  while(a > Math.PI) a -= PI2;
  while(a < -Math.PI) a += PI2;
  return a;
}

// ── Update cameras ────────────────────────────────
function updateCameras(dt){
  if(G.caught || G.missionComplete) return;
  const speedMult = (G.focusMode && G.popupOpen) ? 0.25 : 1.0;

  for(const cam of G.cameras){
    if(cam.disabled){
      cam.disabledTimer -= dt;
      if(cam.disabledTimer <= 0) cam.disabled = false;
      continue;
    }

    // Sweep
    const halfSweep = cam.sweep * DEG / 2;
    cam.currentAngle += cam.sweepDir * 0.6 * DEG * speedMult;
    if(Math.abs(cam.currentAngle - cam.angle * DEG) > halfSweep) cam.sweepDir *= -1;

    // Player in cone?
    const dx = G.px - cam.x, dy = G.py - cam.y;
    const dist = Math.hypot(dx, dy);
    const angleTo = Math.atan2(dy, dx);
    const diff = Math.abs(normalizeAngle(angleTo - cam.currentAngle));
    if(dist < 180 && diff < halfSweep && hasLineOfSight(cam.x, cam.y, G.px, G.py)){
      cam._seesPlayer = true;
      G.heat = Math.min(100, G.heat + G.dc.heatGainMult * 20 * dt);
      if(G.heat >= 100) triggerCaught();
    } else {
      cam._seesPlayer = false;
    }
  }
  // Decay heat once if no camera/guard sees player (guard sight adds heat inline)
  const anyCamSees = G.cameras.some(c => c._seesPlayer);
  if(!anyCamSees) G.heat = Math.max(0, G.heat - 3 * dt);
}

// ── Gadget / noise maker ──────────────────────────
function updateGadget(dt){
  if(!G.gadget) return;
  G.gadget.timer -= dt;
  if(G.gadget.phase === 'delay' && G.gadget.timer <= 0){
    G.gadget.phase = 'active';
    G.gadget.timer = 4;
    G.noiseMakerActive = true;
    G.noiseMakerPos = {x: G.gadget.x, y: G.gadget.y};
  }
  if(G.gadget.phase === 'active' && G.gadget.timer <= 0){
    G.gadget = null;
    G.noiseMakerActive = false;
    G.noiseMakerPos = null;
  }
}

function placeGadget(){
  if(G.gadgetPlaced || G.popupOpen) return;
  G.gadgetPlaced = true;
  G.gadget = { x: G.px, y: G.py, phase: 'delay', timer: 2 };
}

// ── Echo ghost ────────────────────────────────────
function startEchoRecord(){
  if(G.echoCharges <= 0 || G.popupOpen) return;
  G.echoRecording = !G.echoRecording;
  if(G.echoRecording){
    G.echoPath = [];
  } else {
    if(G.echoPath.length > 5){
      G.echoCharges--;
      G.echoGhosts.push({ path: [...G.echoPath], idx: 0, x: G.echoPath[0].x, y: G.echoPath[0].y, done: false });
    }
    G.echoPath = [];
  }
}

function updateEchoGhosts(dt){
  for(const ghost of G.echoGhosts){
    if(ghost.done) continue;
    ghost.idx += dt * 60;
    const i = Math.min(Math.floor(ghost.idx), ghost.path.length - 1);
    ghost.x = ghost.path[i].x;
    ghost.y = ghost.path[i].y;
    if(Math.floor(ghost.idx) >= ghost.path.length - 1) ghost.done = true;

    // Guards react to ghost
    for(const guard of G.guards){
      if(guard.state === 'chase') continue;
      const dx = ghost.x - guard.x, dy = ghost.y - guard.y;
      if(Math.hypot(dx, dy) < 150 && guard.state !== 'chase'){
        guard.state = 'alert';
        guard.lastSeenX = ghost.x;
        guard.lastSeenY = ghost.y;
        guard.alertTimer = 3;
      }
    }
  }
  G.echoGhosts = G.echoGhosts.filter(g => !g.done);
}

// ── Ability ───────────────────────────────────────
function updateAbility(dt){
  if(G.abilityCooldown > 0) G.abilityCooldown -= dt;
  if(G.abilityActive){
    G.abilityTimeLeft -= dt;
    if(G.abilityTimeLeft <= 0){
      G.abilityActive = false;
      if(G.selectedClass === 'runner') G.speed = G.cls.moveSpeed; // reset burst speed
    }
  }
}

function activateAbility(){
  if(G.abilityCooldown > 0 || G.abilityActive || G.popupOpen) return;
  // Open ability math popup
  const promptData = G.cls.abilityPrompts[G.abilityPromptIdx % G.cls.abilityPrompts.length];
  G.abilityPromptIdx++;
  openMathPopup('ability', promptData);
}

// ── Interaction (E key) ───────────────────────────
function tryInteract(){
  if(G.popupOpen || G.caught) return;
  const {col, row} = playerTile();

  // Check adjacent tiles for terminal
  const neighbors = [[col,row],[col-1,row],[col+1,row],[col,row-1],[col,row+1]];
  for(const [c,r] of neighbors){
    const tile = tileAt(c, r);
    if(tile === T.TERMINAL){
      // Are we close enough?
      const tx = (c + 0.5)*TILE, ty = (r + 0.5)*TILE;
      if(Math.hypot(G.px - tx, G.py - ty) < TILE * 1.5){
        startTerminalHack(c, r);
        return;
      }
    }
  }

  // Loot pickup handled in updateLoot
}

// ── Loot / vault / escape ─────────────────────────
function updateLoot(){
  if(G.lootCollected || G.vaultActive || G.popupOpen) return;
  const loot = G.level.loot;
  const lx = (loot.col + 0.5)*TILE, ly = (loot.row + 0.5)*TILE;
  if(Math.hypot(G.px - lx, G.py - ly) < TILE * 0.8){
    startVault();
  }
}

function updateEscape(){
  if(!G.lootCollected || G.escaped || G.caught || G.popupOpen) return;
  const exit = G.level.exit;
  const ex = (exit.col + 0.5)*TILE, ey = (exit.row + 0.5)*TILE;
  if(Math.hypot(G.px - ex, G.py - ey) < TILE * 0.8){
    triggerEscapeGate();
  }
}

function updateEscapeTimer(dt){
  if(!G.lootCollected || G.escaped || G.caught || G.missionComplete || G.popupOpen) return;
  G.escapeTimer += dt;
  if(G.escapeTimer >= G.escapeTimeLimit) triggerCaught();

  // Vault timer
  if(G.vaultActive){
    G.vaultTimer += dt;
    // Flash at ≤15s remaining
    const remaining = G.vaultTimeLimit - G.vaultTimer;
    if(remaining <= 15 && remaining > 0) G.vaultFlashing = true;
    else G.vaultFlashing = false;
    if(G.vaultTimer >= G.vaultTimeLimit) triggerCaught();
  }
}

function updateMissionTimer(dt){
  if(G.caught || G.missionComplete) return;
  G.missionTimer += dt;
  if(G.missionTimer >= G.missionTimeLimit) triggerCaught();
}

// ── Caught / complete ─────────────────────────────
function triggerCaught(){
  if(G.caught || G.missionComplete) return;
  G.caught = true;
  G.screenFlash = 0.8;
  closePopup();
  if(window.onMissionEnd) window.onMissionEnd(false);
}

function triggerMissionComplete(){
  if(G.caught || G.missionComplete) return;
  G.missionComplete = true;
  G.escaped = true;
  if(window.onMissionEnd) window.onMissionEnd(true);
}

// ── Main game loop ────────────────────────────────
let lastTime = 0;
let animFrame = null;

function gameLoop(ts){
  const dt = Math.min((ts - lastTime) / 1000, 0.05);
  lastTime = ts;

  if(!G.caught && !G.missionComplete){
    updatePlayer(dt);
    updateGuards(dt);
    updateCameras(dt);
    updateGadget(dt);
    updateEchoGhosts(dt);
    updateAbility(dt);
    updateLoot();
    updateEscape();
    updateEscapeTimer(dt);
    updateMissionTimer(dt);

    // Screen flash decay
    if(G.screenFlash > 0) G.screenFlash = Math.max(0, G.screenFlash - dt * 2);

    // Noise decay when no noise maker active
    if(!G.noiseMakerActive) G.noise = Math.max(0, G.noise - dt * 5);

    // Score: time bonus
    if(!G.popupOpen) G.score = Math.max(0, G.score + (G.caught ? 0 : 0));

    // Focus mode score drain
    if(G.focusMode && G.popupOpen) G.score = Math.max(0, G.score - dt * 2);
  }

  drawFrame();
  animFrame = requestAnimationFrame(gameLoop);
}

function startGameLoop(){
  lastTime = performance.now();
  if(animFrame) cancelAnimationFrame(animFrame);
  animFrame = requestAnimationFrame(gameLoop);
}

function stopGameLoop(){
  if(animFrame) cancelAnimationFrame(animFrame);
  animFrame = null;
}

// ── Keyboard ──────────────────────────────────────
function setupInput(){
  document.addEventListener('keydown', e => {
    if(!window.G || !window.G.keys) return;
    if(G.caught || G.missionComplete) return;
    G.keys[e.code] = true;

    // Math popup input handled in main.js global router → handleMathKey
    if(G.popupOpen) return;

    switch(e.code){
      case 'KeyE': tryInteract(); break;
      case 'Space': e.preventDefault(); activateAbility(); break;
      case 'KeyR': startEchoRecord(); break;
      case 'KeyQ': placeGadget(); break;
      case 'KeyM': G.muted = !G.muted; break;
      case 'Tab': e.preventDefault(); G.focusMode = !G.focusMode; break;
      case 'KeyF': G.scaffoldOpen = !G.scaffoldOpen; break;
    }
  });

  document.addEventListener('keyup', e => {
    if(window.G && window.G.keys) G.keys[e.code] = false;
  });
}

